INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('ed9bf3b9-7306-587f-b615-6a98b0f855a5', 'math', 'الأعداد الحقيقية', 'مجموعات الأعداد، الترتيب، المجالات، القيمة المطلقة والعمليات في ℝ', '# ⚔️ الأعداد الحقيقية — ساحة المعركة الأولى

> 💡 «قبل أن تخوض أيّ معركة حسابية، عليك أن تعرف عالم الأعداد الذي تقاتل فيه.»

## 🏰 مجموعات الأعداد

نرتّب عوالم الأعداد من الأصغر إلى الأكبر، كلّ عالم يحتوي ما قبله:

- **ℕ** الأعداد الطبيعية: 0، 1، 2، 3، …
- **ℤ** الأعداد الصحيحة النسبية: …، −2، −1، 0، 1، 2، …
- **𝔻** الأعداد العشرية: لها كتابة عشرية **متناهية** (مثل 3,25).
- **ℚ** الأعداد الكسرية (الناطقة): تُكتب على شكل كسر a/b حيث b ≠ 0.
- **ℝ** الأعداد الحقيقية: كلّ الأعداد التي تمثّل فاصلة نقطة على المستقيم العددي.

نكتب سلسلة الاحتواء:

$$ ℕ ⊂ ℤ ⊂ 𝔻 ⊂ ℚ ⊂ ℝ $$

> 🗡️ كلّ عدد طبيعي هو عدد صحيح، وكلّ عدد صحيح هو كسري… لكن العكس غير صحيح!

## ⚡ الأعداد الصمّاء (غير الناطقة)

العدد **الناطق** كتابته العشرية **متناهية** (مثل 1/2 = 0,5) أو **دوريّة** (مثل 1/3 = 0,333…).
أمّا العدد **الأصمّ** فلا يمكن كتابته على شكل كسر؛ كتابته العشرية **غير متناهية وغير دوريّة**.
أشهر الأمثلة:

- العدد √2 ≈ 1,414213…
- العدد π ≈ 3,14159…

مجموعة الأعداد الحقيقية ℝ هي اتّحاد الأعداد الناطقة (ℚ) والأعداد الصمّاء.

## 🛡️ ترتيب الأعداد الحقيقية

لكلّ عددين حقيقيّين a وb، تتحقّق **حالة واحدة فقط**: إمّا a < b، أو a = b، أو a > b.

قواعد الترتيب التي ستستعملها كثيرًا:

- إذا كان a < b فإنّ a + c < b + c (الجمع لا يغيّر الترتيب). _مثال_: من 2 < 5، إضافة 3 تعطي 5 < 8.
- إذا كان a < b و c > 0 فإنّ a × c < b × c (الضرب في عدد موجب يحفظ الترتيب). _مثال_: من 2 < 5، الضرب في 3 يعطي 6 < 15.
- إذا كان a < b و c < 0 فإنّ a × c > b × c (**الضرب في عدد سالب يقلب الترتيب**). _مثال_: من 2 < 5، الضرب في −3 يعطي −6 > −15.

> ⚠️ الفخّ الأكثر شيوعًا: نسيان قلب الإشارة عند الضرب أو القسمة على عدد سالب.

## 📐 المجالات

المجال هو مجموعة من الأعداد الحقيقية محصورة بين حدّين:

| المجال   | الكتابة بعدم المساواة | الحدود               |
| -------- | --------------------- | -------------------- |
| [a ; b]  | a ≤ x ≤ b             | مغلق (يشمل a وb)     |
| ]a ; b[  | a < x < b             | مفتوح (لا يشمل a وb) |
| [a ; +∞[ | x ≥ a                 | نصف مستقيم           |
| ]−∞ ; b] | x ≤ b                 | نصف مستقيم           |

القوس المتّجه نحو الحدّ يعني أنّ الحدّ **غير مشمول**؛ والقوس المربّع يعني أنّه **مشمول**.

_مثال محسوب_: المجال ]2 ; 5] يعني 2 < x ≤ 5، فالعدد 5 **ينتمي** إليه (لأنّ 5 ≤ 5 صحيحة)
والعدد 2 **لا ينتمي** إليه (لأنّ 2 < 2 خاطئة)، بينما 3 و4 ينتميان إليه.

## 🔮 القيمة المطلقة

القيمة المطلقة للعدد x هي **بعده عن الصفر** على المستقيم العددي، ونرمز لها بـ |x|:

| الحالة | القيمة المطلقة |
| ------ | -------------- |
| x ≥ 0  | \|x\| = x      |
| x < 0  | \|x\| = −x     |

أمثلة: |5| = 5، و |−7| = 7، و |0| = 0. القيمة المطلقة **لا تكون أبدًا سالبة**.

**معادلة بقيمة مطلقة**: إذا كان k > 0 فإنّ |X| = k ⟺ X = k أو X = −k.
_مثال_: |2x − 3| = 5 تعني 2x − 3 = 5 أو 2x − 3 = −5، أي 2x = 8 أو 2x = −2، ومنه x = 4 أو x = −1.

**حصر بقيمة مطلقة**: |x| ≤ k ⟺ −k ≤ x ≤ k.
_مثال_: |x| ≤ 3 تعني −3 ≤ x ≤ 3، أي x ∈ [−3 ; 3].

**معادلة من الشكل x² = a**: إذا كان a > 0 فللمعادلة x² = a **حلّان** هما √a و −√a.
_مثال_: المعادلة x² = 16 حلّاها 4 و −4 (لأنّ 4² = 16 و (−4)² = 16)، فمجموعة الحلول هي {−4 ; 4}.

## 🧮 العمليّات الأربع في ℝ

سلاح الجمع وسلاح الضرب لهما خصائص قويّة:

- **التبديل**: a + b = b + a و a × b = b × a
- **التجميع**: (a + b) + c = a + (b + c)
- **العنصر المحايد**: a + 0 = a و a × 1 = a
- **التوزيع**: a × (b + c) = a × b + a × c

> 🗡️ **عدّة سريعة** — تذكير من السنوات السابقة:
> **قواعد الإشارات**: سالب × سالب = موجب. _مثال_: (−3) × (−4) + (−2) = 12 − 2 = 10.
> **قوى الأعداد السالبة**: الأسّ الفردي يُبقي الإشارة سالبة. _مثال_: (−2)³ = −8.
> **جذر مربّع كامل**: √9 = 3 و √16 = 4.
> **المتطابقات الشهيرة**: (a ± b)² = a² ± 2ab + b² و a² − b² = (a − b)(a + b) — ستتعمّق فيها في فصل الحساب الحرفي.

## 🧪 الكتابة العلمية

**الكتابة العلمية** لعدد هي كتابته على الشكل a × 10ⁿ حيث a ∈ [1 ; 10[ (أي 1 ≤ a < 10) و n عدد صحيح نسبي.

_مثال محسوب_: 2500 = 2,5 × 1000 = 2,5 × 10³.

> ⚠️ يجب أن يكون 1 ≤ a < 10: الكتابة 25 × 10² تساوي 2500 لكنّها **ليست** كتابة علمية لأنّ 25 ≥ 10.

> 🏆 أتقنت البوّابة الأولى! الأعداد الحقيقية هي أرضيّة كلّ ما سيأتي: الجذور، الحساب الحرفي، والمعادلات.', '# 📜 ملخّص: الأعداد الحقيقية

- **سلسلة الاحتواء**: ℕ ⊂ ℤ ⊂ 𝔻 ⊂ ℚ ⊂ ℝ، وكلّ مجموعة تحتوي ما قبلها.
- **الناطقة والصمّاء**: العدد الناطق (ℚ) كسرٌ a/b وكتابته العشرية متناهية أو دوريّة؛ الأصمّ غير متناهٍ وغير دوريّ (مثل √2 و π). و ℝ = الناطقة ∪ الصمّاء.
- **الترتيب**: الجمع والضرب في موجب يحفظان الترتيب؛ الضرب أو القسمة على عدد **سالب يقلب** إشارة عدم المساواة (من 2 < 5: ×(−3) يعطي −6 > −15).
- **المجالات**: قوس مربّع [ ] ⇒ الحدّ مشمول؛ قوس متّجه ] [ ⇒ غير مشمول. مثال: ]2 ; 5] يعني 2 < x ≤ 5 (العدد 5 ينتمي و2 لا ينتمي).
- **القيمة المطلقة**: |x| هي البعد عن الصفر، دائمًا ≥ 0؛ |X| = k ⟺ X = k أو X = −k (مثل |2x − 3| = 5 ⇒ x = 4 أو x = −1)؛ |x| ≤ k ⟺ −k ≤ x ≤ k؛ والمعادلة x² = a (حيث a > 0) حلّاها √a و −√a.
- **خصائص العمليّات**: التبديل، التجميع، العنصر المحايد (0 للجمع، 1 للضرب)، والتوزيع؛ وتذكّر: سالب × سالب = موجب، و(−2)³ = −8.
- **الكتابة العلمية**: a × 10ⁿ حيث 1 ≤ a < 10 و n صحيح نسبي، مثل 2500 = 2,5 × 10³.', 1, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('65871a90-e921-55ff-b1fe-5483ab510aad', 'math', 'الجذور التربيعية', 'تعريف الجذر التربيعي وخصائصه، تبسيط الجذور وإنطاق المقام', '# 🗡️ الجذور التربيعية — سلاح الأعداد الصمّاء

> 💡 «الجذر التربيعي هو المفتاح الذي يفتح أبواب الأعداد الصمّاء ونظرية فيثاغورس.»

## 🏰 تعريف الجذر التربيعي

الجذر التربيعي لعدد **موجب** a — أي a ≥ 0، والصفر مشمول — هو العدد الموجب الذي مربّعه يساوي a، ونرمز له بـ √a.
بالنسبة لكلّ عدد a ≥ 0:

$$ (√a)² = a $$

> ⚠️ لا يوجد جذر تربيعي لعدد **سالب** في مجموعة الأعداد الحقيقية: √(−4) غير معرّف في ℝ.

أمثلة: √0 = 0، √1 = 1، √9 = 3، √16 = 4.

## ⚡ علاقة أساسية: √(a²) = |a|

مربّع العدد ثمّ جذره يعيدنا إلى **القيمة المطلقة**:

$$ √(a²) = |a| $$

مثال: √((−5)²) = √25 = 5 = |−5|. هذا الفخّ يظهر كثيرًا في الامتحانات!

## 🛡️ خصائص الجذور (الضرب والقسمة)

بالنسبة لعددين موجبين a وb:

- **جذر الجداء**: √(a × b) = √a × √b
- **جذر القسمة**: √(a/b) = √a / √b (حيث b > 0)

_مثال محسوب على القسمة_: √54 / √6 = √(54/6) = √9 = 3.

> ⚠️ انتبه: **لا توجد** خاصيّة مماثلة للجمع! √(a + b) ≠ √a + √b.
> مثال مضادّ: √(9 + 16) = √25 = 5، بينما √9 + √16 = 3 + 4 = 7.

## 🔮 تبسيط الجذور

نُخرج من تحت الجذر كلّ عامل مربّع كامل:

$$ √50 = √(25 × 2) = √25 × √2 = 5√2 $$

الطريقة: نحلّل العدد إلى جداء يحتوي أكبر مربّع كامل ممكن، ثمّ نُخرج جذره.

- √8 = √(4 × 2) = 2√2
- √75 = √(25 × 3) = 5√3

> 🗡️ ابحث دائمًا عن **أكبر** مربّع كامل يقسم العدد: 4، 9، 16، 25، 36، 49، 64… فهذا يبسّط الجذر في خطوة واحدة.

## 🧪 إنطاق المقام

حين يظهر جذر في المقام، نضرب البسط والمقام في الجذر نفسه لجعل المقام عددًا ناطقًا:

$$ 1/√2 = (1 × √2)/(√2 × √2) = √2/2 $$

لأنّ √2 × √2 = 2. هكذا اختفى الجذر من المقام.

### مرافق المقام

إذا كان المقام على الشكل √a + b، نضرب البسط والمقام في **مرافقه** √a − b،
مستعملين المتطابقة (a − b)(a + b) = a² − b² (ستتعمّق فيها في فصل الحساب الحرفي):

$$ 1/(√5 + 2) = (√5 − 2)/((√5 + 2)(√5 − 2)) = (√5 − 2)/(5 − 4) = √5 − 2 $$

لأنّ (√5 + 2)(√5 − 2) = (√5)² − 2² = 5 − 4 = 1.

## 🧮 الجمع والطرح بين الجذور

نجمع أو نطرح الجذور **المتشابهة** فقط (التي تحت جذرها العدد نفسه):

$$ 3√2 + 5√2 = 8√2 $$

أمّا √2 + √3 فلا يمكن جمعهما لأنّهما غير متشابهين.

**تذكير من الهندسة (فيثاغورس)**: في مثلّث قائم: الوتر² = ضلع² + ضلع².
_مثال_: المثلّث الذي ضلعاه القائمان 6 و8 وتره 10، لأنّ 6² + 8² = 36 + 64 = 100 = 10²، ومنه الوتر = √100 = 10.

> 🏆 الآن صار سلاح الجذور بين يديك: ستستعمله في الحساب الحرفي، والمعادلات، وخاصّة في الهندسة مع فيثاغورس.', '# 📜 ملخّص: الجذور التربيعية

- **التعريف**: √a (لـ a ≥ 0، والصفر مشمول) هو العدد الموجب الذي مربّعه a، و (√a)² = a. لا جذر لعدد سالب في ℝ.
- **علاقة جوهرية**: √(a²) = |a| (وليس a فقط).
- **الضرب والقسمة**: √(a×b) = √a × √b، و √(a/b) = √a/√b (مثل √54/√6 = √9 = 3). تحذير: √(a+b) ≠ √a + √b.
- **التبسيط**: نُخرج أكبر مربّع كامل، مثل √50 = 5√2 و √8 = 2√2.
- **إنطاق المقام**: نضرب في الجذر (1/√2 = √2/2)؛ وإذا كان المقام √a + b نضرب في **المرافق** √a − b، مثل 1/(√5 + 2) = √5 − 2.
- **الجمع/الطرح**: ممكن فقط بين الجذور المتشابهة: 3√2 + 5√2 = 8√2.
- **تذكير فيثاغورس**: في مثلّث قائم: الوتر² = ضلع² + ضلع²، مثل المثلّث 6 و8 و10 (لأنّ 36 + 64 = 100).', 2, NULL)
