INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', 'الأشعّة والانسحاب', 'تعريف الشعاع وخصائصه، الانسحاب وصورة نقطة، جمع الأشعّة وعلاقة شال، تطبيقات متوازي الأضلاع', '# ⚔️ الأشعّة والانسحاب — سلاح الاتجاه والقوّة

> 💡 «الشعاع هو سلاحك في المستوي: له نقطة انطلاق، واتجاه، ومنحى، وطول. أتقنه تفتح أبواب الهندسة التحليلية.»

## 🏰 تعريف الشعاع

الشعاع هو **قطعة مستقيمة مزوّدة باتجاه ومنحى**. نرمز للشعاع الذي منشأه A وطرفه B بـ AB.

للشعاع AB أربع خصائص:

- **المنشأ**: النقطة A، وهي نقطة الانطلاق.
- **الاتجاه**: المستقيم الحامل للشعاع (أي المستقيم AB).
- **المنحى**: من A نحو B (وهو عكس منحى BA).
- **الطول**: هو طول القطعة [AB]، ويُكتب ‖AB‖.

> 🗡️ لا تخلط بين الشعاع AB والشعاع BA: لهما نفس الاتجاه والطول، لكنّهما متعاكسا المنحى!

## ⚡ تساوي شعاعين

شعاعان **متساويان** إذا تشاركا نفس الاتجاه ونفس المنحى ونفس الطول (المنشأ قد يختلف).

$$ AB = CD ⟺ نفس الاتجاه + نفس المنحى + نفس الطول $$

**نتيجة هندسية**: AB = CD إذا وفقط إذا كان ABDC متوازي أضلاع (أي إذا كان للقطعتَين [AD] و[BC] المنتصف نفسه).

مثال: إذا كان ABCD متوازي أضلاع فإنّ AB = DC و AD = BC.

> ⚠️ الفخّ: AB = DC وليس CD! في متوازي الأضلاع الضلعان المتوازيان متساويان في المنحى أيضًا.

## 🛡️ الانسحاب الذي شعاعه معطى

**الانسحاب ذو الشعاع u** هو تحويل هندسي ينقل كلّ نقطة M إلى نقطة M'' بحيث:

$$ MM'' = u $$

نقول إنّ M'' هي **صورة** النقطة M بالانسحاب ذي الشعاع u. وعكسيًّا، نقول إنّ M هي **سابقة** النقطة M'' بهذا الانسحاب: للعودة من الصورة إلى السابقة ننسحب بالشعاع المعاكس −u.

**مثال محلول:** لتكن A وB نقطتين بحيث AB = 3 cm. صورة النقطة M بالانسحاب ذي الشعاع AB هي النقطة M'' التي تحقّق MM'' = AB: نرسم انطلاقًا من M، موازيًا لـ (AB) وفي منحى B، القطعة [MM''] بطول 3 cm — فيكون الرباعي ABM''M متوازي أضلاع.

**خصائص الانسحاب:**

- يحفظ الأطوال: MM'' = AB (إذا كان الشعاع AB = u).
- يحفظ الزوايا والأشكال (يحفظ الشكل مع تغيير الموضع فقط).
- صورة مستقيم هي مستقيم **موازٍ** له.
- صورة قطعة هي قطعة مساوية لها في الطول.

| الصورة بالانسحاب u = AB | الشكل الأصلي                | ملاحظة                 |
| ----------------------------------------------------------- | --------------------------- | ---------------------- |
| نقطة M'' بحيث MM'' = u    | نقطة M                      | MM'' = AB               |
| مستقيم موازٍ للمستقيم (d)                                   | مستقيم (d)                  | تحفّظ الموازاة         |
| مثلّث مساوٍ في الشكل والحجم                                 | مثلّث                       | تحفّظ الأطوال والزوايا |
| دائرة مركزها I'' (صورة I) وبنفس نصف القطر r                  | دائرة مركزها I ونصف قطرها r | تحفّظ نصف القطر        |

## 🔮 جمع الأشعّة وعلاقة شال (Chasles)

**قاعدة شال (Chasles):**

$$ **AB + BC = AC** $$

هذه العلاقة تقول: للانتقال من A إلى C، يمكنني المرور بأيّ نقطة وسطى B.

**تعميم:** لأيّ نقطة وسطى O:

$$ AB = AO + OB $$

**نتيجة مهمّة — الشعاع المعاكس:**

$$ AB + BA = AA = 0 $$

إذن BA = −AB (الشعاع المعاكس يُعكس المنحى فقط).

**طرح شعاعين:** طرحُ شعاعٍ هو جمعُ معاكسِه:

$$ u − v = u + (−v) $$

**مثال محلول:** AC − AB = AC + BA = BA + AC = BC بعلاقة شال.

> 🏆 حيلة البطل: عندما تجد مجموعًا من الأشعّة، اربط طرف الشعاع الأوّل بمنشأ الشعاع الثاني — وإذا تطابقا تطبق شال مباشرة!

## 🧮 تبسيط مجموع أشعّة باستخدام شال

لحساب AC + CA: نلاحظ أنّ CA = −AC، إذن الناتج هو الشعاع الصفري.

لحساب AB + BC + CD: نطبّق شال تدريجيًا:

$$ AB + BC = AC ⟹ AC + CD = AD $$

**مبدأ المسار المغلق:** مجموع أشعّة مسار يعود إلى نقطة انطلاقه هو الشعاع الصفري:

$$ AB + BC + CA = AC + CA = 0 $$

وفي الأشكال المركّبة (كالسداسي المنتظم)، عوّض كلّ شعاع بشعاع يساويه قبل التجميع، حتى تتسلسل الحروف ويُغلق المسار.

**مثال محلول:** إذا كان ABCD متوازي أضلاع ومركزه O، احسب OA + OC.

بما أنّ O منتصف [AC]، فإنّ OA = −OC، إذن OA + OC = الشعاع الصفري.

## 🏅 متوازي الأضلاع وتساوي الأشعّة

**الخاصيّة الأساسية:**

ABCD متوازي أضلاع ⟺ AB = DC

معنى ذلك أنّ الضلعَين [AB] و[DC] متوازيان ومتساويان في الطول وبالمنحى نفسه.

**النتائج:**

- AB = DC و AD = BC
- مركز متوازي الأضلاع O هو منتصف كلّ من [AC] و [BD]
- OA + OB + OC + OD = الشعاع الصفري إذا كان O المركز

**قاعدة متوازي الأضلاع للجمع:** مجموع شعاعين لهما **نفس المنشأ** هو شعاع قطر متوازي الأضلاع المبنيّ عليهما. في متوازي الأضلاع ABCD:

$$ BA + BC = BD $$

**مثال:** بما أنّ BC = AD، فإنّ BA + BC = BA + AD = BD بعلاقة شال.

> 🗡️ ملخّص القتال: علاقة شال = سلاحك الأوّل؛ الشعاع المعاكس = درعك؛ متوازي الأضلاع = ميدانك.

> 🏆 اجتزت بوّابة الأشعّة: شال، المعاكس، الطرح، وقاعدة متوازي الأضلاع كلّها في جعبتك. في الفصل القادم يدخل الشعاع المعلّمَ — وتتحوّل الهندسة كلّها إلى حساب!', '# 📜 ملخّص: الأشعّة والانسحاب

- **الشعاع AB**: له منشأ (A)، اتجاه، منحى (من A نحو B)، وطول ‖AB‖.
- **تساوي شعاعين**: AB = CD إذا تشاركا الاتجاه والمنحى والطول (ABDC متوازي أضلاع).
- **الانسحاب ذو الشعاع u**: ينقل M إلى M'' بحيث MM'' = u. يحفظ الأطوال والزوايا والتوازي، وصورة الدائرة دائرة بنفس نصف القطر.
- **سابقة النقطة بالانسحاب**: M سابقة M''؛ للعودة من الصورة إلى السابقة ننسحب بالشعاع المعاكس −u.
- **علاقة شال**: AB + BC = AC — سلاح التبسيط الأوّل.
- **الشعاع المعاكس والطرح**: BA = −AB و AB + BA = الشعاع الصفري؛ والطرح: u − v = u + (−v).
- **المسار المغلق**: مجموع أشعّة مسار يعود إلى نقطة انطلاقه = الشعاع الصفري (AB + BC + CA = 0).
- **متوازي الأضلاع**: ABCD متوازي أضلاع ⟺ AB = DC. مركزه O: OA + OC = 0 و OB + OD = 0.
- **قاعدة متوازي الأضلاع للجمع**: شعاعان من نفس المنشأ يُجمعان على قطر المتوازي: BA + BC = BD.', 11, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('67e1970d-7e67-5193-acd3-1729b90b0cb2', 'math', 'المعلّم في المستوي', 'المعلّم المتعامد والمتجانس، إحداثيّات نقطة وشعاع، منتصف قطعة، والمسافة بين نقطتين', '# 🗺️ المعلّم في المستوي — خريطة الهندسة التحليلية

> 💡 «المعلّم هو نظام الإحداثيّات الذي يحوّل الهندسة إلى حساب — كلّ نقطة في المستوي لها عنوانها الخاصّ!»

## 🏰 المعلّم المتعامد والمتجانس

**المعلّم المتعامد والمتجانس** (يُرمز له بـ (O ; i ; j)) يتكوّن من:

- **النقطة الأصل O**: نقطة تقاطع المحورين.
- **المحور الأوّل (محور الفاصلات)**: المستقيم الأفقي، اتّجاهه الشعاع i.
- **المحور الثاني (محور الترتيبات)**: المستقيم العمودي، اتّجاهه الشعاع j.
- **المتجانس**: كلّ وحدة على المحورين لها نفس الطول (المقياس موحَّد).

الخاصيّتان الجوهريّتان:

- المحوران عموديّان: زاوية 90° بين محور الفاصلات ومحور الترتيبات.
- الوحدة متساوية على كلا المحورين.

> 🗡️ «متعامد» = المحوران عموديّان؛ «متجانس» = نفس المقياس على المحورين. الفرق مهمّ لرسم الأشكال بدقّة.

## ⚡ إحداثيّات نقطة

كلّ نقطة M في المستوي تُعرَّف بزوج ترتيبي **(x ; y)**:

- **الفاصلة**: x = الإسقاط الأفقي على محور الفاصلات.
- **الترتيبة**: y = الإسقاط العمودي على محور الترتيبات.

نكتب: M(xM ; yM).

| النقطة | الفاصلة | الترتيبة | الموضع             |
| ------ | ------- | -------- | ------------------ |
| O      | 0       | 0        | الأصل              |
| A      | 3       | 2        | الربع الأوّل (+,+) |
| B      | −4      | 1        | الربع الثاني (−,+) |
| C      | −2      | −3       | الربع الثالث (−,−) |
| D      | 5       | −1       | الربع الرابع (+,−) |
| E      | 0       | 4        | على محور الترتيبات |
| F      | −3      | 0        | على محور الفاصلات  |

إذا كانت الفاصلة = 0 أو الترتيبة = 0، فالنقطة تقع **على أحد المحورين** ولا تنتمي إلى أيّ ربع.

> ⚠️ الترتيب مهمّ: الفاصلة أوّلًا ثمّ الترتيبة. A(3 ; 2) ≠ A(2 ; 3).

## 🛡️ إحداثيّات شعاع من نقطتين

إذا كانت A(xA ; yA) و B(xB ; yB)، فإنّ إحداثيّات الشعاع AB هي:

$$ **AB = (xB − xA ; yB − yA)** $$

- المركّبة الأولى: xB − xA (فاصلة الطرف − فاصلة المنشأ).
- المركّبة الثانية: yB − yA (ترتيبة الطرف − ترتيبة المنشأ).

**مثال محلول:** A(1 ; 3) و B(5 ; −1):

$$ AB = (5 − 1 ; −1 − 3) = (4 ; −4) $$

> 🗡️ حيلة: الشعاع يشير دائمًا من المنشأ (الحرف الأوّل) نحو الطرف (الحرف الثاني). «طرف ناقص منشأ».

## 🧭 تساوي شعاعين بالمركّبات — إيجاد الرأس الرابع

شعاعان متساويان إذا وفقط إذا كانت لهما **نفس المركّبتين**:

$$ AB = DC ⟺ xB − xA = xC − xD و yB − yA = yC − yD $$

**طريقة الرأس الرابع:** ABCD متوازي أضلاع ⟺ AB = DC — وهذا يكفي لإيجاد رأس مجهول.

**مثال محلول:** A(1 ; 2)، B(4 ; 3)، C(6 ; 7). أوجد D حتى يكون ABCD متوازي أضلاع.

- AB = (4 − 1 ; 3 − 2) = (3 ; 1) و DC = (6 − xD ; 7 − yD).
- من 6 − xD = 3 نجد xD = 3، ومن 7 − yD = 1 نجد yD = 6. إذن D(3 ; 6).

> 🗡️ يكافئ ذلك الصيغة المباشرة: xD = xA + xC − xB و yD = yA + yC − yB (هنا: 1 + 6 − 4 = 3 و 2 + 7 − 3 = 6).

## 🌀 الانسحاب في المعلّم

إذا كانت للشعاع u المركّبتان (a ; b)، فإنّ صورة النقطة M(x ; y) بالانسحاب ذي الشعاع u هي:

$$ M''(x + a ; y + b) $$

**مثال محلول:** الشعاع u = (3 ; −2) و M(1 ; 4): الصورة هي M''(1 + 3 ; 4 − 2) = M''(4 ; 2).

**السابقة:** سابقة النقطة M'' هي النقطة M التي صورتها M''؛ نعود بالشعاع المعاكس: M(x'' − a ; y'' − b).

**مثال:** سابقة N''(5 ; 0) بالانسحاب نفسه هي N(5 − 3 ; 0 + 2) = N(2 ; 2).

## 🔮 إحداثيّات منتصف قطعة

إذا كانت A(xA ; yA) و B(xB ; yB)، فإنّ المنتصف I للقطعة [AB] له إحداثيّات:

$$ **I = ((xA + xB)/2 ; (yA + yB)/2)** $$

الفاصلة والترتيبة هما **المعدّل الحسابي** لفاصلتَي A وB وترتيبتَيهما.

**مثال محلول:** A(2 ; 6) و B(8 ; 2):

$$ I = ((2 + 8)/2 ; (6 + 2)/2) = (5 ; 4) $$

**التحقّق:** AI = (5 − 2 ; 4 − 6) = (3 ; −2) و IB = (8 − 5 ; 2 − 4) = (3 ; −2). متساويان، إذن I منتصف [AB]. ✓

**الطريقة العكسية — إيجاد طرف من المنتصف:** إذا عُرف المنتصف I وأحد الطرفين A، نعزل الطرف الآخر:

$$ (xA + xC)/2 = xI ⟺ xC = 2xI − xA $$

(والترتيبة بنفس الطريقة: yC = 2yI − yA.)

**مثال محلول:** I(4 ; 1) منتصف [AC] حيث A(2 ; 5): xC = 2 × 4 − 2 = 6 و yC = 2 × 1 − 5 = −3، إذن C(6 ; −3).

> 🗡️ **مماثل نقطة بالنسبة إلى نقطة**: مماثل A بالنسبة إلى B هو النقطة M حيث B منتصف [AM]، أي xM = 2xB − xA و yM = 2yB − yA.

## 🧪 المسافة بين نقطتين

إذا كانت A(xA ; yA) و B(xB ; yB)، فإنّ المسافة AB هي:

$$ **AB = √((xB − xA)² + (yB − yA)²)** $$

هذه الصيغة مستنبَطة من **نظرية فيثاغورس** المطبَّقة على المثلّث القائم الذي ساقاه (xB − xA) و (yB − yA).

**مثال محلول:** A(1 ; 2) و B(5 ; 5):

$$ (xB − xA) = 5 − 1 = 4 $$
$$ (yB − yA) = 5 − 2 = 3 $$
$$ AB = √(4² + 3²) = √(16 + 9) = √25 = 5 $$

> 🏆 المثلّث ذو الأبعاد 3-4-5 كلاسيكي في الامتحانات! احفظه: 3² + 4² = 9 + 16 = 25 = 5².

## 🧮 تطبيقات مجتمعة — الشعاع والمسافة والمنتصف

**تطبيق:** المثلّث ABC بـ A(0 ; 0)، B(6 ; 0)، C(3 ; 4). أثبت أنّه متساوي الساقين.

- AB = √((6 − 0)² + (0 − 0)²) = √36 = 6
- AC = √((3 − 0)² + (4 − 0)²) = √(9 + 16) = √25 = 5
- BC = √((3 − 6)² + (4 − 0)²) = √(9 + 16) = √25 = 5

بما أنّ AC = BC = 5، فالمثلّث ABC متساوي الساقين **رأسه C** (الضلعان المتساويان يلتقيان في C). ✓

**منتصف [AB]**: I = ((0 + 6)/2 ; (0 + 0)/2) = (3 ; 0).

CI = √((3 − 3)² + (0 − 4)²) = √(0 + 16) = 4.

**تطبيق — التحقّق من زاوية قائمة (عكس فيثاغورس):** A(1 ; 1)، B(4 ; 1)، D(1 ; 5). هل الزاوية BAD قائمة؟

- AB = √((4 − 1)² + (1 − 1)²) = √9 = 3
- AD = √((1 − 1)² + (5 − 1)²) = √16 = 4
- BD = √((4 − 1)² + (1 − 5)²) = √(9 + 16) = √25 = 5

بما أنّ AB² + AD² = 9 + 16 = 25 = BD²، فبموجب **عكس نظرية فيثاغورس** المثلّث ABD قائم في A، أي الزاوية BAD قائمة. ✓

> 🗡️ عند حلّ مسائل المعلّم: الخطوة الأولى دائمًا — احسب إحداثيّات الأشعّة والمسافات بالصيغ، ثمّ استنتج الخاصيّات الهندسية.

## 🏅 خلاصة الصيغ — بطاقة البطل

| المطلوب                         | الصيغة                                                                             |
| ------------------------------- | ---------------------------------------------------------------------------------- |
| إحداثيّات الشعاع AB | (xB − xA ; yB − yA)                             |
| منتصف [AB]                      | ((xA + xB)/2 ; (yA + yB)/2)                               |
| المسافة AB                      | √((xB − xA)² + (yB − yA)²)                                                   |
| شعاعان متساويان                 | AB = CD ⟺ xB − xA = xD − xC و yB − yA = yD − yC |

> 🏆 اكتملت خريطة المستوي: رأس رابع، انسحاب، منتصف ومسافة — كلّها صارت حسابًا بين يديك. استعدّ للفصل القادم: الهندسة تغادر الورقة نحو **الفضاء**!', '# 📜 ملخّص: المعلّم في المستوي

- **المعلّم (O ; i ; j)**: محوران عموديّان بنفس المقياس. الأصل O عند (0 ; 0).
- **إحداثيّات نقطة**: M(x ; y) — الفاصلة أوّلًا ثمّ الترتيبة؛ وإذا كان x = 0 أو y = 0 فالنقطة على أحد المحورين لا في ربع.
- **إحداثيّات شعاع**: الشعاع AB له مركّبتان (xB − xA ; yB − yA) — «طرف ناقص منشأ».
- **تساوي شعاعين والرأس الرابع**: AB = DC إذا وفقط إذا تساوت المركّبتان؛ في متوازي الأضلاع ABCD: xD = xA + xC − xB و yD = yA + yC − yB.
- **الانسحاب في المعلّم**: صورة M(x ; y) بانسحاب شعاعه (a ; b) هي M''(x + a ; y + b)؛ والسابقة: M(x'' − a ; y'' − b).
- **منتصف قطعة**: I = ((xA + xB)/2 ; (yA + yB)/2)؛ عكسيًّا: xC = 2xI − xA، ومماثل A بالنسبة إلى B: xM = 2xB − xA و yM = 2yB − yA.
- **المسافة**: AB = √((xB − xA)² + (yB − yA)²) — مستنبَطة من فيثاغورس؛ احفظ المثلّث الكلاسيكي 3-4-5: 3² + 4² = 5².
- **منهجية البرهان**: مثلّث متساوي الساقين = احسب المسافات الثلاث وقارنها؛ زاوية قائمة = قارن AB² + AD² مع BD² (عكس فيثاغورس).', 12, NULL)
