INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99b8dbc4-3cb1-59b8-b170-3223474f24bd', 'c97bbd8a-3e61-5712-8ef0-a7a7ce925786', 'أيّ من التعريفات الآتية يصف القيمة المطلقة |x| بشكل صحيح؟', '[{"id":"a","text":"|x| هي ضعف العدد x مهما كانت إشارته"},{"id":"b","text":"|x| هي بُعد العدد x عن الصفر على المستقيم العددي"},{"id":"c","text":"|x| تكون سالبة إذا كان العدد x سالبًا"},{"id":"d","text":"|x| هي مقابل العدد x (أي −x) في كلّ الحالات"}]'::jsonb, 'b', 'القيمة المطلقة |x| هي بُعد العدد x عن الصفر: تساوي x إذا كان x ≥ 0، وتساوي −x إذا كان x < 0. وهي دائمًا موجبة أو معدومة، لا تكون أبدًا سالبة.', 2)
