INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('51711489-dc10-504b-8879-ec06ab733e04', 'c97bbd8a-3e61-5712-8ef0-a7a7ce925786', 'ما الأثر على إشارة عدم المساواة عند ضرب طرفَيها في عدد سالب؟', '[{"id":"a","text":"تبقى الإشارة كما هي دون تغيير"},{"id":"b","text":"تنقلب الإشارة فقط عند الضرب في العدد −1 بالذات"},{"id":"c","text":"تنقلب الإشارة فقط إذا كان طرفا عدم المساواة موجبَين"},{"id":"d","text":"تنقلب إشارة عدم المساواة إلى العكس"}]'::jsonb, 'd', 'عند الضرب في عدد سالب تنقلب إشارة عدم المساواة؛ فمثلًا إذا كان a < b وضربنا في c < 0 نحصل على a × c > b × c. هذا الفخّ الأشهر في باب الأعداد الحقيقية.', 4)
