INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('013fee50-06fc-50c2-b122-8b3c405c5207', '81ff9da1-548c-50cf-9f91-8ef7d971cab6', 'أيّ من الأعداد التالية عددٌ أصمّ (غير ناطق)؟', '[{"id":"a","text":"−5"},{"id":"b","text":"0,25"},{"id":"c","text":"2/3"},{"id":"d","text":"√2"}]'::jsonb, 'd', '√2 كتابته العشرية غير متناهية وغير دوريّة، فلا يمكن كتابته على شكل كسر، إذن هو عدد أصمّ. أمّا −5 فعدد صحيح، و0,25 = 1/4 و2/3 عددان ناطقان.', 2)
