INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80ed71ca-cc0f-5995-9f36-1fe1985c5718', 'ec9248c4-9408-548f-aee3-046aa660c54d', 'ما ناتج العملية: (−3) × (−4) + (−2) ؟', '[{"id":"a","text":"−14"},{"id":"b","text":"−10"},{"id":"c","text":"10"},{"id":"d","text":"14"}]'::jsonb, 'c', '(−3) × (−4) = 12 (سالب × سالب = موجب)، ثمّ 12 + (−2) = 10.', 3)
