INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d973b1a3-d43a-5ec5-82a7-962400b33d6e', 'ec9248c4-9408-548f-aee3-046aa660c54d', 'أيّ الأعداد التالية هو الأكبر؟', '[{"id":"a","text":"1,4"},{"id":"b","text":"1,41"},{"id":"c","text":"1,5"},{"id":"d","text":"√2"}]'::jsonb, 'c', '√2 ≈ 1,4142، وبالتالي 1,5 هو الأكبر من بين هذه الأعداد.', 5)
