INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c30e96b9-1170-508b-a5fe-aad6aa0cc992', 'ec9248c4-9408-548f-aee3-046aa660c54d', 'إذا كان a < b، فأيّ عبارة صحيحة دائمًا؟', '[{"id":"a","text":"a × 0 < b × 0"},{"id":"b","text":"a + 3 < b + 3"},{"id":"c","text":"−a < −b"},{"id":"d","text":"2a > 2b"}]'::jsonb, 'b', 'إضافة العدد نفسه إلى الطرفين تحفظ الترتيب: من a < b نستنتج a + 3 < b + 3 دائمًا. الخطأ الشائع: الضرب في عدد سالب يقلب الترتيب، فمن a < b ينتج −a > −b (لا أصغر)، بينما الضرب في 2 الموجب يحفظه (2a < 2b لا العكس)، و a × 0 = b × 0 = 0 فلا متباينة قاطعة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

