INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44cffaaf-830a-5ca5-81de-17bd3737cbf6', '172edea9-3107-5d1a-a5b3-b8d55d3b96db', 'أيّ مجال يكافئ عدم المساواة −1 ≤ x < 4 ؟', '[{"id":"a","text":"]−1 ; 4["},{"id":"b","text":"[−1 ; 4["},{"id":"c","text":"]−1 ; 4]"},{"id":"d","text":"[−1 ; 4]"}]'::jsonb, 'b', 'الرمز ≤ عند −1 يعني أنّ −1 مشمول فنكتب قوسًا مربّعًا [−1، والرمز < عند 4 يعني أنّ 4 غير مشمول فنكتب قوسًا متّجهًا 4[. إذن −1 ≤ x < 4 يكافئ المجال [−1 ; 4[. الخطأ الشائع: عكس اتّجاه القوسين أو شمول الطرفين معًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9845284-c085-5b00-9764-2c8eb3d446f2', '172edea9-3107-5d1a-a5b3-b8d55d3b96db', 'كانت درجة الحرارة عند الفجر −3°C، ثمّ ارتفعت بمقدار 8 درجات. ما درجة الحرارة الجديدة؟', '[{"id":"a","text":"11°C"},{"id":"b","text":"−11°C"},{"id":"c","text":"5°C"},{"id":"d","text":"−5°C"}]'::jsonb, 'c', 'درجة الحرارة الجديدة = −3 + 8 = 5°C. الارتفاع بمقدار 8 يعني إضافة 8 إلى القيمة السالبة: −3 + 8 = 5.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7425c2e9-e237-5e54-9bd0-e80dbaf0b8c5', '172edea9-3107-5d1a-a5b3-b8d55d3b96db', 'ما الكتابة العلمية الصحيحة للعدد 2500؟', '[{"id":"a","text":"25 × 10²"},{"id":"b","text":"0,25 × 10⁴"},{"id":"c","text":"2,5 × 10³"},{"id":"d","text":"2,5 × 10⁻³"}]'::jsonb, 'c', 'الكتابة العلمية تشترط أن يكون المعامل بين 1 و10 (غير مشمول). 2500 = 2,5 × 1000 = 2,5 × 10³. الخيار (a) معامله 25 ≥ 10 فلا يُقبل، والخيار (b) معامله أقلّ من 1، والخيار (d) يعطي عددًا أقلّ من 1.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e836ab7e-a4ce-5624-886a-ec90a31280ef', '172edea9-3107-5d1a-a5b3-b8d55d3b96db', 'إذا كان x ∈ ℝ وكان x² = 16، فما مجموعة الحلول؟', '[{"id":"a","text":"{4}"},{"id":"b","text":"{−4 ; 4}"},{"id":"c","text":"{−16 ; 16}"},{"id":"d","text":"{8 ; −8}"}]'::jsonb, 'b', 'x² = 16 يعني x = 4 أو x = −4، لأنّ (4)² = 16 و(−4)² = 16. لا تنسَ الحلّ السالب! مجموعة الحلول هي {−4 ; 4}.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('909783ed-8c93-5595-b2c0-bc221c6af843', '172edea9-3107-5d1a-a5b3-b8d55d3b96db', 'ما قيم x الحقيقية التي تحقّق |2x − 3| = 5؟', '[{"id":"a","text":"x = 4 فقط"},{"id":"b","text":"x = 4 أو x = −1"},{"id":"c","text":"x = 1 أو x = −4"},{"id":"d","text":"لا يوجد حلّ"}]'::jsonb, 'b', '|2x − 3| = 5 يعني: إمّا 2x − 3 = 5 فنجد 2x = 8 أي x = 4، وإمّا 2x − 3 = −5 فنجد 2x = −2 أي x = −1. التحقّق: |2(4)−3| = |5| = 5 ✓ و |2(−1)−3| = |−5| = 5 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1c95a370-18dc-5351-bcfc-33836e75b1df', '172edea9-3107-5d1a-a5b3-b8d55d3b96db', 'حدّد الأكبر من بين الأعداد التالية: 2,2 ، √5 ، 9/4 ، 2,3', '[{"id":"a","text":"2,3"},{"id":"b","text":"√5"},{"id":"c","text":"9/4"},{"id":"d","text":"2,2"}]'::jsonb, 'a', 'نُقارن القيم: 2,2 = 2,2 ، √5 ≈ 2,236 ، 9/4 = 2,25 ، 2,3 = 2,3. الترتيب التصاعدي: 2,2 < √5 < 9/4 < 2,3. إذن الأكبر هو 2,3.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f8e067f0-3d38-576e-b604-ea6dd05a0548', 'ed9bf3b9-7306-587f-b615-6a98b0f855a5', 'math', '👑 تحدّي النخبة ⭐⭐⭐⭐: الأعداد الحقيقية والقيمة المطلقة', 4, 300, 60, 'challenge', 'admin', 4)
