INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c50940e7-1467-5f35-aee9-46c83e572d0e', 'f8e067f0-3d38-576e-b604-ea6dd05a0548', 'العدد x يحقّق |x| = √5 و x < 0. ما طبيعة العدد x وإلى أيّ مجموعة يُصنَّف؟', '[{"id":"a","text":"عدد ناطق ينتمي إلى ℚ"},{"id":"b","text":"عدد أصمّ ينتمي إلى ℝ \\ ℚ"},{"id":"c","text":"عدد صحيح ينتمي إلى ℤ"},{"id":"d","text":"عدد عشري ينتمي إلى 𝔻"}]'::jsonb, 'b', 'من |x| = √5 مع الشرط x < 0 نستنتج x = −√5 (الحلّ الموجب √5 مرفوض لأنّ x سالب). بما أنّ 5 ليس مربّعًا كاملًا فإنّ √5 عدد أصمّ: كتابته العشرية غير متناهية وغير دوريّة (√5 ≈ 2,2360679…)، ومقابل العدد الأصمّ أصمّ أيضًا. إذن x ينتمي إلى ℝ \ ℚ. الخطأ الشائع: الاكتفاء بالحلّ x = √5 ونسيان أنّ الشرط x < 0 يفرض الحلّ السالب، أو الظنّ أنّ كلّ عدد مكتوب بجذر هو عدد ناطق.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('027e7e1a-a8ce-50f6-879f-9ac2821ea75b', 'f8e067f0-3d38-576e-b604-ea6dd05a0548', 'رتّب الأعداد التالية تصاعديًّا (من الأصغر إلى الأكبر): −√7 ، −2 ، √3 − 2 ، 0', '[{"id":"a","text":"−2 < −√7 < 0 < √3 − 2"},{"id":"b","text":"−√7 < −2 < 0 < √3 − 2"},{"id":"c","text":"−√7 < −2 < √3 − 2 < 0"},{"id":"d","text":"−2 < −√7 < √3 − 2 < 0"}]'::jsonb, 'c', 'نحسب قيمًا تقريبية: √7 ≈ 2,646 وإذن −√7 ≈ −2,646؛ أمّا √3 ≈ 1,732 فـ√3 − 2 ≈ −0,268. نقارن الأربعة: −2,646 < −2 < −0,268 < 0، أي −√7 < −2 < √3 − 2 < 0. الفخّ الشائع هو ظنّ أنّ −√7 > −2 لأنّ √7 > 2، مع نسيان أنّ الضرب في −1 يقلب الترتيب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4ee7b042-288e-572a-ae92-d57cac7a3d5d', 'f8e067f0-3d38-576e-b604-ea6dd05a0548', 'كم عددًا صحيحًا ينتمي إلى مجموعة حلول عدم المساواة |2x − 1| ≤ 5؟', '[{"id":"a","text":"5"},{"id":"b","text":"6"},{"id":"c","text":"7"},{"id":"d","text":"4"}]'::jsonb, 'b', 'نحلّ |2x − 1| ≤ 5 بتطبيق تعريف القيمة المطلقة: −5 ≤ 2x − 1 ≤ 5. نُضيف 1 للطرفين: −4 ≤ 2x ≤ 6. نقسم على 2 (عدد موجب، الترتيب يبقى): −2 ≤ x ≤ 3. المجال هو [−2 , 3]. الأعداد الصحيحة في هذا المجال هي: −2 ، −1 ، 0 ، 1 ، 2 ، 3 — أي 6 أعداد صحيحة. الأخطاء الشائعة: نسيان الطرفين −2 و3 اللذين يُشملان لأنّ المجال مغلق.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d9a21b0-15c5-5d61-be5d-7d3928a7e2de', 'f8e067f0-3d38-576e-b604-ea6dd05a0548', 'إذا كان −3 < x < 1، فأيّ مجال يحتوي دائمًا العبارة 2 − 3x؟', '[{"id":"a","text":"]−3 , 9["},{"id":"b","text":"]−7 , 5["},{"id":"c","text":"[ −1 , 11 ]"},{"id":"d","text":"]−1 , 11["}]'::jsonb, 'd', 'نبدأ من −3 < x < 1. نضرب في −3 (سالب ← نقلب الترتيب): −3×1 < −3x < −3×(−3)، أي −3 < −3x < 9. ثمّ نُضيف 2 للطرفين (لا يُغيّر الترتيب): 2+(−3) < 2−3x < 2+9، أي −1 < 2−3x < 11. إذن 2−3x ∈ ]−1 , 11[. الطرفان −1 و11 غير مشمولين لأنّ المجال الأصلي مفتوح. الخطأ الشائع هو نسيان قلب إشارة عدم المساواة عند الضرب في −3.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e5e52db1-ec86-5665-b108-17cdfd47e229', 'f8e067f0-3d38-576e-b604-ea6dd05a0548', 'ليكن a = |√2 − 1,5| وb = |√2 − 1,4| وc = |1,5 − 1,4|. أيّ الترتيبات التالية صحيح؟', '[{"id":"a","text":"b < a < c"},{"id":"b","text":"a < b < c"},{"id":"c","text":"b < c < a"},{"id":"d","text":"c < a < b"}]'::jsonb, 'a', 'نعلم أنّ √2 ≈ 1,41421. نحسب: a = |1,41421 − 1,5| = |−0,08579| = 0,08579؛ b = |1,41421 − 1,4| = |0,01421| = 0,01421؛ c = |1,5 − 1,4| = 0,1. مقارنة: 0,01421 < 0,08579 < 0,1، أي b < a < c. تفسير هندسي: b هو المسافة بين √2 و1,4 (قريبة جدًّا منه)، وa هو البعد بين √2 و1,5، وc هو المسافة الثابتة بين 1,4 و1,5.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b071def-b469-5de4-9c31-0cfef93124c9', 'f8e067f0-3d38-576e-b604-ea6dd05a0548', 'ما قيمة العبارة (√3 + 1)² − (√3 − 1)²؟', '[{"id":"a","text":"4"},{"id":"b","text":"2√3"},{"id":"c","text":"4√3"},{"id":"d","text":"6"}]'::jsonb, 'c', 'نستخدم قاعدة a² − b² = (a+b)(a−b) مع a = √3+1 وb = √3−1: (a+b) = (√3+1)+(√3−1) = 2√3؛ (a−b) = (√3+1)−(√3−1) = 2. إذن (√3+1)² − (√3−1)² = 2√3 × 2 = 4√3. تحقّق مباشر: (√3+1)² = 3+2√3+1 = 4+2√3؛ (√3−1)² = 3−2√3+1 = 4−2√3؛ الفرق = (4+2√3)−(4−2√3) = 4√3. النتيجة عدد أصمّ ≈ 6,928. الخطأ الشائع هو حساب 3+1=4 أو 3−1=2 دون تطبيق قاعدة التربيع الصحيحة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'ed9bf3b9-7306-587f-b615-6a98b0f855a5', 'math', '📝 تدريب ⭐⭐⭐: الأعداد الحقيقية (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f463adf-346b-56d6-9071-457cd9bd6c0a', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'ما أصغر مجموعة عدديّة ينتمي إليها العدد √16 ؟', '[{"id":"a","text":"ℕ"},{"id":"b","text":"ℤ"},{"id":"c","text":"ℚ"},{"id":"d","text":"ℝ \\ ℚ"}]'::jsonb, 'a', '√16 = 4 بالضبط لأنّ 4² = 16، والعدد 4 عدد طبيعي. إذن أصغر مجموعة تحتويه هي ℕ (وهو ينتمي أيضًا إلى ℤ وℚ وℝ بالاحتواء). الخطأ الشائع: الظنّ أنّ وجود رمز الجذر يجعل العدد أصمّ — هذا صحيح فقط إذا لم يكن ما تحت الجذر مربّعًا كاملًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6fbcfc1b-1b2d-58d7-b16b-bdf0c6069898', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'ما ناتج العملية: (−2)³ + (−5) × (−3) ؟', '[{"id":"a","text":"−23"},{"id":"b","text":"1"},{"id":"c","text":"7"},{"id":"d","text":"23"}]'::jsonb, 'c', 'نحسب القوّة أوّلًا: (−2)³ = −8، ثمّ الضرب: (−5) × (−3) = 15. أخيرًا الجمع: −8 + 15 = 7. التحقّق: −8 + 15 = 7 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('35e76788-e657-5be4-b93d-43064799b43d', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'ما قيمة |2 − 9| + |−3| ؟', '[{"id":"a","text":"−10"},{"id":"b","text":"−4"},{"id":"c","text":"4"},{"id":"d","text":"10"}]'::jsonb, 'd', '2 − 9 = −7 إذن |2 − 9| = 7، و|−3| = 3. المجموع = 7 + 3 = 10. القيمة المطلقة دائمًا موجبة أو معدومة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d51ef99d-e6b4-5655-b4fc-8c69e0cd2e97', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'أيّ مجال يمثّل مجموعة الأعداد الحقيقية x التي تحقّق |x| ≤ 3 ؟', '[{"id":"a","text":"[0 ; 3]"},{"id":"b","text":"]−3 ; 3["},{"id":"c","text":"[−3 ; 3]"},{"id":"d","text":"]−∞ ; 3]"}]'::jsonb, 'c', '|x| ≤ 3 يعني أنّ بُعد x عن الصفر لا يتجاوز 3، أي −3 ≤ x ≤ 3، وهو المجال المغلق [−3 ; 3]. الخيار (a) يهمل الأعداد السالبة، و(b) يستثني الطرفين رغم أنّ الرمز ≤ يشملهما، و(d) ينسى الشرط x ≥ −3.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0b9aed72-616e-58c5-abc9-9a362e2cff71', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'رتّب الأعداد التالية تصاعديًّا: √2 ، 1 ، 1,5 ، √3 . ما الترتيب الصحيح؟', '[{"id":"a","text":"1 < √3 < √2 < 1,5"},{"id":"b","text":"1 < √2 < 1,5 < √3"},{"id":"c","text":"1 < 1,5 < √2 < √3"},{"id":"d","text":"√2 < 1 < √3 < 1,5"}]'::jsonb, 'b', '√2 ≈ 1,414 و√3 ≈ 1,732. إذن الترتيب التصاعدي: 1 < 1,414 < 1,5 < 1,732، أي 1 < √2 < 1,5 < √3. الخطأ الشائع: الظنّ أنّ √2 > 1,5 — قارن المربّعين: (1,5)² = 2,25 > 2، إذن 1,5 > √2.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a930d86d-1fb6-548b-a1ad-81bbae7bb2b8', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'إذا كان 0 < a < b، فأيّ عبارة صحيحة دائمًا؟', '[{"id":"a","text":"a² < b²"},{"id":"b","text":"a² > b²"},{"id":"c","text":"−a < −b"},{"id":"d","text":"a − b > 0"}]'::jsonb, 'a', 'بما أنّ a وb موجبان، فالضرب في عدد موجب يحفظ الترتيب: نضرب a < b في a فنجد a² < ab، ونضربها في b فنجد ab < b²، إذن a² < b². مثال: 2 < 3 يعطي 4 < 9 ✓. الخطأ الشائع: اختيار −a < −b، والصحيح أنّ الضرب في −1 يقلب الترتيب فـ −a > −b؛ كما أنّ a − b سالب لأنّ a < b.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

