  ('a59fdfa4-f8c5-5e02-ade5-d6bf905d445e', '65871a90-e921-55ff-b1fe-5483ab510aad', 'math', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
