  ('5680c5e9-d223-542e-9db3-4c3e770da622', '65871a90-e921-55ff-b1fe-5483ab510aad', 'math', '⭐ تمرين: حساب وتبسيط الجذور', 1, 50, 10, 'practice', 'admin', 1)
