  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d73efe27-cd2b-5ade-b536-f505689746d4', '5680c5e9-d223-542e-9db3-4c3e770da622', 'ما هو الشكل المبسّط للعدد √50 ؟', '[{"id":"a","text":"5√2"},{"id":"b","text":"2√5"},{"id":"c","text":"25√2"},{"id":"d","text":"10√5"}]'::jsonb, 'a', 'لتبسيط الجذر نُخرج أكبر مربّع كامل عاملًا للعدد: 50 = 25 × 2 حيث 25 مربّع كامل. نطبّق خاصيّة جذر الجداء √(a×b) = √a × √b: √50 = √(25 × 2) = √25 × √2 = 5√2. الخيار (b) حلّل 50 خطأً، و(c) لم يُخرج الجذر من 25.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0e1a8e5a-8a8b-5f8d-abb9-846f550be28f', '5680c5e9-d223-542e-9db3-4c3e770da622', 'ما ناتج √3 × √12 ؟', '[{"id":"a","text":"6"},{"id":"b","text":"√15"},{"id":"c","text":"36"},{"id":"d","text":"6√3"}]'::jsonb, 'a', 'نطبّق خاصيّة جذر الجداء √a × √b = √(a×b): √3 × √12 = √(3 × 12) = √36. وبما أنّ 6² = 36 فإنّ √36 = 6. الخطأ الشائع: تبسيط √12 = 2√3 ثمّ الاكتفاء بضرب 3 × 2 مع إبقاء √3، فيُحصل خطأً على 6√3.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6a118a4-cd9d-5c70-895e-0cff5a81a44c', '5680c5e9-d223-542e-9db3-4c3e770da622', 'أيّ من العبارات التالية صحيحة؟', '[{"id":"a","text":"√(36 + 64) = 6 + 8"},{"id":"b","text":"√(36 × 64) = 6 × 8"},{"id":"c","text":"√(−4) = 2"},{"id":"d","text":"√(a²) = a دائمًا"}]'::jsonb, 'b', 'خاصيّة جذر الجداء: √(36 × 64) = √36 × √64 = 6 × 8 = 48 ✓. أمّا الجمع فلا خاصيّة له (√(36 + 64) = √100 = 10 بينما 6 + 8 = 14)، ولا وجود لجذر عدد سالب في ℝ، و√(a²) = |a| وليس a دائمًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

