INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d0d46468-66ac-57b8-87c8-6c3ccdd6f77c', '2d3109e8-a00c-5619-8905-d768c68c00b9', 'ما ناتج 3√2 + 5√2 ؟', '[{"id":"a","text":"8√4"},{"id":"b","text":"15√2"},{"id":"c","text":"8"},{"id":"d","text":"8√2"}]'::jsonb, 'd', 'الجذران متشابهان (√2)، فنجمع المعاملين: 3 + 5 = 8، أي 8√2.', 1)
ON CONFLICT (id) DO UPDATE SET
