INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d4fcdcbc-54d2-512f-a801-a980e162361a', '2d3109e8-a00c-5619-8905-d768c68c00b9', 'بعد إنطاق المقام، يصبح الكسر 1/√2 مساويًا لـ:', '[{"id":"a","text":"√2/2"},{"id":"b","text":"2/√2"},{"id":"c","text":"√2"},{"id":"d","text":"1/2"}]'::jsonb, 'a', 'لإنطاق المقام نتخلّص من الجذر بضرب البسط والمقام في الجذر نفسه √2: (1×√2)/(√2×√2) = √2/(√2)² = √2/2، لأنّ (√2)² = 2. النتيجة 1/√2 = √2/2 وقيمتها لم تتغيّر (نفس العدد ≈ 0,707).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('761705b3-5632-50c3-8e89-1fcbb1a293ee', '2d3109e8-a00c-5619-8905-d768c68c00b9', 'ما هو الشكل المبسّط للعدد √75 ؟', '[{"id":"a","text":"3√5"},{"id":"b","text":"5√3"},{"id":"c","text":"15"},{"id":"d","text":"25√3"}]'::jsonb, 'b', 'نُخرج أكبر مربّع كامل عاملًا للعدد 75: 75 = 25 × 3 حيث 25 مربّع كامل. إذن √75 = √(25 × 3) = √25 × √3 = 5√3. أمّا 3√5 فناتج عن تحليل خاطئ للعدد 75، و25√3 نسي أنّ √25 = 5 (لا 25).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47c48b5a-49d9-5a04-b022-4ec57adf2a3b', '2d3109e8-a00c-5619-8905-d768c68c00b9', 'ما قيمة (2√3)² ؟', '[{"id":"a","text":"2√3"},{"id":"b","text":"6"},{"id":"c","text":"12"},{"id":"d","text":"36"}]'::jsonb, 'c', '(2√3)² = 2² × (√3)² = 4 × 3 = 12.', 4)
ON CONFLICT (id) DO UPDATE SET
