INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a7b4344-7720-59ed-8bc9-4d67d9ad42c9', '2d3109e8-a00c-5619-8905-d768c68c00b9', 'هل يمكن جمع √2 + √3 في عدد واحد على شكل k√n ؟', '[{"id":"a","text":"لا، لأنّ الجذرين غير متشابهين"},{"id":"b","text":"نعم، يساوي √5 لأنّ 2 + 3 = 5"},{"id":"c","text":"نعم، يساوي √6 لأنّ 2 × 3 = 6"},{"id":"d","text":"لا، لأنّ الجذور لا تُجمع مطلقًا ولو كانت متشابهة"}]'::jsonb, 'a', 'لا يمكن الدمج لأنّ الجذرين غير متشابهين، و√(a + b) ≠ √a + √b: فمثلًا √2 + √3 ≈ 3,15 بينما √5 ≈ 2,24. لكنّ الجذور المتشابهة تُجمع فعلًا بجمع معاملاتها (مثل 2√3 + 5√3 = 7√3)، لذلك الخيار (d) خاطئ أيضًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

