INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f7d366dd-abc3-5d2a-98ea-4f5fa30c73c5', 'c8957fdb-6fc2-5637-aef7-b904288394bb', 'أبسّط √45 :', '[{"id":"a","text":"9√5"},{"id":"b","text":"3√15"},{"id":"c","text":"5√3"},{"id":"d","text":"3√5"}]'::jsonb, 'd', 'نحلّل 45 إلى جداء يحتوي مربّعًا كاملًا: 45 = 9 × 5. إذن √45 = √(9 × 5) = √9 × √5 = 3√5. تحقّق: (3√5)² = 9 × 5 = 45 ✓. الخيار (a) نسي أنّ √9 = 3، و(c) بدّل العاملين، و(b) حلّل 45 = 3 × 15 وأخرج 3 رغم أنّه ليس مربّعًا كاملًا.', 1)
ON CONFLICT (id) DO UPDATE SET
