  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd7ca0a1-fb2b-5744-ad6e-36c4ca721219', 'c8957fdb-6fc2-5637-aef7-b904288394bb', 'في مثلّث قائم الزاوية، ضلعاه القائمان يساويان 6 cm و8 cm. ما طول الوتر؟', '[{"id":"a","text":"√14 cm"},{"id":"b","text":"7 cm"},{"id":"c","text":"√48 cm"},{"id":"d","text":"10 cm"}]'::jsonb, 'd', 'بتطبيق نظريّة فيثاغورس: وتر² = 6² + 8² = 36 + 64 = 100، إذن الوتر = √100 = 10 cm. تذكّر المثلث 6-8-10 وهو من مضاعفات المثلث 3-4-5.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

