INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cddb6916-197d-59c6-8b7c-bedbb035f5e8', '3750e3af-89f4-5760-81d8-b809c1daf2a3', 'بسّط التعبير التالي تبسيطًا كاملًا: (√48 − √12) / √3', '[{"id":"a","text":"√3"},{"id":"b","text":"2"},{"id":"c","text":"4"},{"id":"d","text":"6"}]'::jsonb, 'b', 'نبسّط البسط أوّلًا: √48 = √(16×3) = 4√3، و√12 = √(4×3) = 2√3. إذن البسط = 4√3 − 2√3 = 2√3. ثمّ نقسم على √3: (2√3)/√3 = 2 × (√3/√3) = 2 × 1 = 2. الخيار (c) خطأ شائع من نسيان الطرح، و(a) من خطأ في التبسيط، و(d) من عدم الطرح أصلًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1e28e1b4-c77e-57e1-91da-81d6b88264d9', '3750e3af-89f4-5760-81d8-b809c1daf2a3', 'بسّط التعبير التالي (بعد إنطاق المقام إن لزم): (√6 + √2) / √2', '[{"id":"a","text":"√3"},{"id":"b","text":"√2 + 1"},{"id":"c","text":"√3 + 1"},{"id":"d","text":"2√3"}]'::jsonb, 'c', 'نقسم كلّ حدّ على √2 بصورة مستقلّة: (√6)/√2 + (√2)/√2 = √(6/2) + 1 = √3 + 1. الخيار (a) نسي الحدّ الثاني (+1)، و(b) خلط بين √6/√2 و√2/√2، و(d) ضاعف بدلًا من القسمة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('02521333-866d-58a6-9045-0e5d40e1da59', '3750e3af-89f4-5760-81d8-b809c1daf2a3', 'ليكن x = −3. ما قيمة التعبير √(4x² + 24x + 36) ؟', '[{"id":"a","text":"0"},{"id":"b","text":"6"},{"id":"c","text":"12"},{"id":"d","text":"3"}]'::jsonb, 'a', 'نحلّل التعبير داخل الجذر: 4x² + 24x + 36 = (2x)² + 2×(2x)×6 + 6² = (2x + 6)². إذن √(4x² + 24x + 36) = √((2x+6)²) = |2x + 6|. بتعويض x = −3: 2(−3) + 6 = −6 + 6 = 0، فـ |0| = 0. الخيار (b) تعويض مباشر خاطئ، و(c) حساب 4×9=36 ثمّ الجذر دون تحليل، و(d) تجاهل المعامل 4.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f1e1059-ee76-59a8-892e-46896808bfc6', '3750e3af-89f4-5760-81d8-b809c1daf2a3', 'اُنطق مقام الكسر التالي وبسّطه تمامًا (تلميح: استعمل الفرق بين مربّعين): 1 / (√5 + 2)', '[{"id":"a","text":"√5 + 2"},{"id":"b","text":"1 / (√5 − 2)"},{"id":"c","text":"(√5 + 2) / 3"},{"id":"d","text":"√5 − 2"}]'::jsonb, 'd', 'نضرب البسط والمقام في المرافق (√5 − 2): 1 / (√5 + 2) = (√5 − 2) / ((√5 + 2)(√5 − 2)) = (√5 − 2) / ((√5)² − 2²) = (√5 − 2) / (5 − 4) = √5 − 2. الخيار (a) نسي تغيير الإشارة، و(c) حسب المقام 5 − 2 = 3 ناسيًا تربيع العدد 2، و(b) لم يُجرِ أيّ تبسيط.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('197234de-606e-5b9e-9c5e-3a7730a5f789', '3750e3af-89f4-5760-81d8-b809c1daf2a3', 'اُحسب قيمة التعبير A ثمّ عيّن قيمة A² حيث: A = √50 + √8 − √18', '[{"id":"a","text":"A = 3√2 ، A² = 18"},{"id":"b","text":"A = 4√2 ، A² = 32"},{"id":"c","text":"A = 5√2 ، A² = 50"},{"id":"d","text":"A = 7√2 ، A² = 98"}]'::jsonb, 'b', 'نبسّط كلّ جذر: √50 = √(25×2) = 5√2، √8 = √(4×2) = 2√2، √18 = √(9×2) = 3√2. إذن: A = 5√2 + 2√2 − 3√2 = (5+2−3)√2 = 4√2. ثمّ A² = (4√2)² = 16 × 2 = 32. الخيار (d) جمع بدون الطرح، و(c) نسي طرح √18، و(a) أخطأ في تبسيط √50.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('10f12cba-ba86-52cb-a72a-6bfc5520010b', '3750e3af-89f4-5760-81d8-b809c1daf2a3', 'في مثلّث قائم الزاوية، ضلعاه القائمان هما √3 cm و√5 cm. ما طول الوتر بالصورة المبسّطة؟', '[{"id":"a","text":"√2 cm"},{"id":"b","text":"√15 cm"},{"id":"c","text":"2√2 cm"},{"id":"d","text":"4 cm"}]'::jsonb, 'c', 'بتطبيق نظريّة فيثاغورس: وتر² = (√3)² + (√5)² = 3 + 5 = 8. إذن الوتر = √8 = √(4×2) = 2√2 cm. الخيار (a) أخذ جذر الفرق، و(b) طبّق √(a×b) خطأً، و(d) جمع الضلعين عوضًا عن مربّعيهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('35382d30-ed80-5e0e-b5ce-46da877152cf', '65871a90-e921-55ff-b1fe-5483ab510aad', 'math', '📝 تدريب ⭐⭐⭐: الجذور التربيعية (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
