INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4908721-72aa-51ae-8b71-e22a8b633ea4', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'أبسّط √98 :', '[{"id":"a","text":"2√7"},{"id":"b","text":"7√2"},{"id":"c","text":"14√2"},{"id":"d","text":"49√2"}]'::jsonb, 'b', 'نحلّل 98 إلى جداء مربّع كامل: 98 = 49 × 2. إذن √98 = √(49 × 2) = √49 × √2 = 7√2. التحقّق: (7√2)² = 49 × 2 = 98 ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c26c3dc4-2755-56a0-9961-ea04bd7ee7c4', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'ما قيمة √50 − √18 ؟', '[{"id":"a","text":"√32"},{"id":"b","text":"8√2"},{"id":"c","text":"√2"},{"id":"d","text":"2√2"}]'::jsonb, 'd', 'نبسّط: √50 = √(25×2) = 5√2 و√18 = √(9×2) = 3√2. إذن √50 − √18 = 5√2 − 3√2 = 2√2. الخطأ الشائع: تطبيق √a − √b = √(a − b) فيُحصل خطأً على √32.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('32c26bd5-1576-575b-ae80-09b2672b01e1', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'اُنطق مقام الكسر 10/√5 (اكتبه بدون جذر في المقام):', '[{"id":"a","text":"2√5"},{"id":"b","text":"10√5"},{"id":"c","text":"√5"},{"id":"d","text":"√5/2"}]'::jsonb, 'a', 'نضرب البسط والمقام في √5: (10 × √5) / (√5 × √5) = 10√5 / 5 = 2√5. التحقّق: 2√5 = 2√5، ومربّعه (2√5)²=20 و(10/√5)²=100/5=20 ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1549de7d-0f12-56b6-9248-0b5c3af6058d', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'إذا كان x = −4، فما قيمة √(x²) + x ؟', '[{"id":"a","text":"12"},{"id":"b","text":"4"},{"id":"c","text":"0"},{"id":"d","text":"−8"}]'::jsonb, 'c', '√(x²) = |x| وليس x: هنا √((−4)²) = √16 = 4 = |−4|. إذن √(x²) + x = 4 + (−4) = 0 ✓. الخطأ الشائع: كتابة √(x²) = x فيُحصل خطأً على −4 + (−4) = −8؛ و(a) حسب x² = 16 دون أخذ الجذر، و(b) نسي إضافة x.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6a56b2b-f341-5e7c-aab5-a7874fe60fdf', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'ما قيمة (3 + √5)(3 − √5) ؟', '[{"id":"a","text":"4"},{"id":"b","text":"6"},{"id":"c","text":"9 + √5"},{"id":"d","text":"14"}]'::jsonb, 'a', 'هذا فرق مربّعين: (a+b)(a−b) = a² − b² مع a = 3 وb = √5. إذن = 3² − (√5)² = 9 − 5 = 4 ✓. الخطأ الشائع: جمع المربّعين بدل طرحهما (9 + 5 = 14)، أو حساب (√5)² = 25 بدل 5.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9527c06-59ec-5c8d-9092-411f79da8814', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'مربّع مساحته 32 cm². ما طول ضلعه بالصورة المبسّطة؟', '[{"id":"a","text":"2√2 cm"},{"id":"b","text":"4√2 cm"},{"id":"c","text":"8√2 cm"},{"id":"d","text":"16 cm"}]'::jsonb, 'b', 'ضلع المربّع = جذر المساحة = √32. نبسّط: √32 = √(16 × 2) = 4√2 cm. التحقّق: (4√2)² = 16 × 2 = 32 ✓. أمّا 2√2 فمربّعه 8، و8√2 مربّعه 128، و16 ناتج عن قسمة المساحة على 2 وهو خطأ شائع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ed5fbefe-679b-5d0d-8372-262c1abb3f14', '65871a90-e921-55ff-b1fe-5483ab510aad', 'math', '👑 تحدّي المناظرة ⭐⭐⭐⭐: الجذور التربيعية في وضعيات مركّبة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
