  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5577dfd7-17c1-55f7-828a-b024f8b754d3', 'ed5fbefe-679b-5d0d-8372-262c1abb3f14', 'بسّط العبارة: (√7 + √3)² − (√7 − √3)².', '[{"id":"a","text":"0"},{"id":"b","text":"4√21"},{"id":"c","text":"2√21"},{"id":"d","text":"20"}]'::jsonb, 'b', 'نطوّر: (√7 + √3)² = 7 + 2√21 + 3 = 10 + 2√21، و(√7 − √3)² = 10 − 2√21. الفرق: (10 + 2√21) − (10 − 2√21) = 4√21. ✓ (تحقّق بالهويّة: (a+b)² − (a−b)² = 4ab مع a = √7 وb = √3، أي 4√21). الخطأ الشائع: كتابة (√7 ± √3)² = 7 ± 3 بإهمال الحدّ الأوسط 2√21 فيصير الفرق 0؛ أو الاكتفاء بـ 2√21 (نسيان أنّ المعامل 4 لا 2).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('011df078-4373-5f15-8dd1-6ef7094ff20c', 'ed5fbefe-679b-5d0d-8372-262c1abb3f14', 'بسّط تلميذ العبارة √50 − √32 + √18 هكذا: «√50 = 5√2، √32 = 16√2، √18 = 3√2، إذن الناتج = (5 − 16 + 3)√2 = −8√2». ما الخطوة الخاطئة؟', '[{"id":"a","text":"تبسيط √32 (الصواب 4√2)"},{"id":"b","text":"تبسيط √50 (الصواب ليس 5√2)"},{"id":"c","text":"تبسيط √18 (الصواب ليس 3√2)"},{"id":"d","text":"لا خطأ، الناتج صحيح"}]'::jsonb, 'a', '√50 = √(25×2) = 5√2 صحيح، و√18 = √(9×2) = 3√2 صحيح. الخطأ في √32: √32 = √(16×2) = √16 × √2 = 4√2، لا 16√2. الناتج الصحيح: (5 − 4 + 3)√2 = 4√2. (تمرين «صيد الخطأ»: الجواب الصحيح هو الخطوة التي تحوي الغلط.) الخطأ الشائع: إخراج العدد من تحت الجذر دون أخذ جذره (√16 = 4 لا 16).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eac48ff6-f5eb-54c2-b8c1-7888846b45e9', 'ed5fbefe-679b-5d0d-8372-262c1abb3f14', 'احسب القيمة المبسّطة للعبارة: √((√5 − 3)²).', '[{"id":"a","text":"√5 − 3"},{"id":"b","text":"3 + √5"},{"id":"c","text":"3 − √5"},{"id":"d","text":"9 − √5"}]'::jsonb, 'c', 'القاعدة: جذر مربّع عددٍ ما هو قيمته المطلقة |a|، لا a نفسه. وبما أنّ √5 ≈ 2,24 < 3 فإنّ √5 − 3 عدد سالب، ومنه √((√5 − 3)²) = |√5 − 3| = 3 − √5. ✓ الخطأ الشائع: اعتبار جذر المربّع مساويًا للعدد نفسه فيخرج √5 − 3 (عدد سالب مستحيل أن يكون جذرًا تربيعيًّا) — الجذر التربيعي دائمًا موجب أو معدوم، لذا نأخذ القيمة المطلقة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e0ccc36-fe16-5057-9782-f6e42955626b', 'ed5fbefe-679b-5d0d-8372-262c1abb3f14', 'مستطيل بُعداه √27 cm و√48 cm. ما طول قطره بالصورة المبسّطة؟', '[{"id":"a","text":"7√3 cm"},{"id":"b","text":"5√3 cm"},{"id":"c","text":"25√3 cm"},{"id":"d","text":"15 cm"}]'::jsonb, 'b', 'بنظرية بيثاغورس، القطر = √((√27)² + (√48)²) = √(27 + 48) = √75. ونبسّط: √75 = √(25 × 3) = 5√3 cm. ✓ (تحقّق: √27 = 3√3 و√48 = 4√3، وهما ضلعا قائم على شاكلة 3 و4، فالوتر 5√3). الخطأ الشائع: جمع الضلعين مباشرةً √27 + √48 = 3√3 + 4√3 = 7√3 (تطبيق القاعدة الخاطئة «جذر المجموع = مجموع الجذرين» بدل بيثاغورس)؛ أو كتابة √75 = 25√3 بنسيان الجذر على 25.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5aa97901-9a84-5ca8-b0b4-369eb358d049', 'ed5fbefe-679b-5d0d-8372-262c1abb3f14', 'أنطق مقام الكسر وبسّطه تمامًا: 3 / (√7 − 2).', '[{"id":"a","text":"√7 − 2"},{"id":"b","text":"3√7 + 6"},{"id":"c","text":"(3√7 + 6) / 5"},{"id":"d","text":"√7 + 2"}]'::jsonb, 'd', 'نضرب البسط والمقام في المرافق (√7 + 2): 3(√7 + 2) / [(√7 − 2)(√7 + 2)]. المقام فرق مربّعين: (√7)² − 2² = 7 − 4 = 3. إذن العبارة = 3(√7 + 2) / 3 = √7 + 2. ✓ الخطأ الشائع: حساب المقام 7 − 2 = 5 بدل (√7)² − 2² = 3 (فيخرج (3√7 + 6)/5)؛ أو نسيان القسمة على 3 (فيخرج 3√7 + 6)؛ أو الضرب في (√7 − 2) فلا يُنطَق المقام.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd143682-13bf-54d0-a2a6-87e09c0b39a0', 'ed5fbefe-679b-5d0d-8372-262c1abb3f14', 'ليكن x = √3 + 1. احسب قيمة x² − 2x.', '[{"id":"a","text":"2 − 2√3"},{"id":"b","text":"4"},{"id":"c","text":"2"},{"id":"d","text":"2√3"}]'::jsonb, 'c', 'x² = (√3 + 1)² = 3 + 2√3 + 1 = 4 + 2√3، و2x = 2√3 + 2. إذن x² − 2x = (4 + 2√3) − (2√3 + 2) = 2. ✓ (تحقّق بالتعميل: x² − 2x = x(x − 2) = (√3 + 1)(√3 − 1) = 3 − 1 = 2). الخطأ الشائع: كتابة (√3 + 1)² = 3 + 1 = 4 بإهمال 2√3 (فيخرج 2 − 2√3)؛ أو نسيان الحدّ 2×1 في 2x فيبقى جذر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('1d2f2525-db2a-503f-a806-3900b9cbdb66', 'ddbe302b-6317-5fa9-a93d-9eddd64651fe', 'math', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
