INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b21df867-d9c0-598c-9283-8d39d3f729a3', '78d50116-f2e7-55df-8c02-20811ed38ef2', 'ما ناتج نشر العبارة: 3(2x − 5) ؟', '[{"id":"a","text":"6x + 15"},{"id":"b","text":"6x − 15"},{"id":"c","text":"5x − 15"},{"id":"d","text":"6x − 5"}]'::jsonb, 'b', 'نوزّع 3 على كلّ حدّ: 3 × 2x = 6x و 3 × (−5) = −15، إذن الناتج هو 6x − 15.', 1)
