INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9264716-e6ab-5a0b-b8c3-16c2a745b57a', '78d50116-f2e7-55df-8c02-20811ed38ef2', 'ما الصورة المعمَّلة تعميلًا تامًّا للعبارة: 6x² + 9x ؟', '[{"id":"a","text":"3(2x² + 3x)"},{"id":"b","text":"x(6x + 9)"},{"id":"c","text":"9x(x + 1)"},{"id":"d","text":"3x(2x + 3)"}]'::jsonb, 'd', 'القاسم المشترك الأكبر لـ 6x² و 9x هو 3x، إذن 6x² + 9x = 3x(2x + 3). تحقّق: 3x × 2x + 3x × 3 = 6x² + 9x ✓. الخياران (a) و(b) تعميلان جزئيّان فقط لأنّهما لا يُخرجان القاسم المشترك الأكبر 3x.', 4)
ON CONFLICT (id) DO UPDATE SET
