INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d268c130-6caa-58cf-bd28-b1414ea396d1', '78d50116-f2e7-55df-8c02-20811ed38ef2', 'باستخدام المتطابقات الشهيرة، ما قيمة 101 × 99 ؟', '[{"id":"a","text":"9801"},{"id":"b","text":"10001"},{"id":"c","text":"9999"},{"id":"d","text":"10101"}]'::jsonb, 'c', '101 × 99 = (100 + 1)(100 − 1) = 100² − 1² = 10000 − 1 = 9999. هذه هي المتطابقة الثالثة فرق المربّعين!', 6)
