INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7beabd0d-1bda-5e00-b65f-7337a970cc9a', 'ab49794e-9915-51a9-aaa0-c4a4eec3bf53', 'ما الصورة المعمَّلة للعبارة x² − 25 ؟', '[{"id":"a","text":"(x − 5)²"},{"id":"b","text":"(x + 5)(x − 5)"},{"id":"c","text":"x(x − 25)"},{"id":"d","text":"(x + 25)(x − 1)"}]'::jsonb, 'b', 'x² − 25 = x² − 5²، وهذا فرق مربّعين: a² − b² = (a − b)(a + b) حيث a = x و b = 5، إذن النتيجة (x − 5)(x + 5). الخيار (c) يعامل x وكأنّه عامل مشترك، لكنّ نشره يعطي x² − 25x لا x² − 25.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('574d83f6-8a4e-5cbf-af16-601319f31805', 'ab49794e-9915-51a9-aaa0-c4a4eec3bf53', 'ما الصورة المعمَّلة للعبارة x² + 10x + 25 ؟', '[{"id":"a","text":"(x + 5)²"},{"id":"b","text":"(x − 5)²"},{"id":"c","text":"(x + 5)(x − 5)"},{"id":"d","text":"(x + 10)(x + 15)"}]'::jsonb, 'a', 'x² + 10x + 25 = x² + 2(x)(5) + 5²، وهذه مربّع المجموع: (a + b)² حيث a = x و b = 5، إذن (x + 5)².', 3)
ON CONFLICT (id) DO UPDATE SET
