INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e441f276-3a03-5903-b23e-822a4e85f453', 'ab49794e-9915-51a9-aaa0-c4a4eec3bf53', 'ما قيمة (x + 3)² − (x − 3)² ؟', '[{"id":"a","text":"0"},{"id":"b","text":"12x"},{"id":"c","text":"18"},{"id":"d","text":"2x² + 18"}]'::jsonb, 'b', '(x+3)² = x²+6x+9 و (x−3)² = x²−6x+9، إذن الفرق = (x²+6x+9) − (x²−6x+9) = 12x. الخطأ الشائع: الظنّ أنّ الفرق يساوي 0 لأنّ القوسين «متماثلان»، لكنّ الحدّين الأوسطين يتراكمان عند الطرح: 6x − (−6x) = 12x.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5316a068-a6c0-5dff-9898-ad76dbe03c69', 'ab49794e-9915-51a9-aaa0-c4a4eec3bf53', 'ما الصورة المعمَّلة للعبارة 4x² − 12x + 9 ؟', '[{"id":"a","text":"(2x − 3)²"},{"id":"b","text":"(2x + 3)²"},{"id":"c","text":"(4x − 3)(x − 3)"},{"id":"d","text":"(2x − 3)(2x + 3)"}]'::jsonb, 'a', '4x² − 12x + 9 = (2x)² − 2(2x)(3) + 3²، وهذه مربّع الفرق: (a − b)² حيث a = 2x و b = 3، إذن (2x − 3)².', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
