  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('08378dd0-dc44-5d7d-a59d-c53ae8911f5b', 'd48dcd17-c9e6-546d-be8d-42c17dd0fc00', 'بسِّط العبارة التالية: (3x − 2)² − (3x + 2)²', '[{"id":"a","text":"−24"},{"id":"b","text":"18x² + 8"},{"id":"c","text":"−24x"},{"id":"d","text":"24x"}]'::jsonb, 'c', 'نطوّر كلّ حدّ على حدة:
(3x − 2)² = 9x² − 12x + 4
(3x + 2)² = 9x² + 12x + 4
إذن الفرق = (9x² − 12x + 4) − (9x² + 12x + 4)
= 9x² − 12x + 4 − 9x² − 12x − 4
= −24x.
الخيار (d) خطأ في الإشارة، و(b) نتيجة جمع لا طرح، و(a) يهمل المتغيّر x.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('520c4c61-0fd4-5a7d-b509-f03123603330', 'd48dcd17-c9e6-546d-be8d-42c17dd0fc00', 'عمِّل (فلِّل) العبارة التالية تعميلًا تامًّا: 5x³ − 20x', '[{"id":"a","text":"5x(x² − 4)"},{"id":"b","text":"5x(x − 2)(x + 2)"},{"id":"c","text":"(5x − 4)(x + 5)"},{"id":"d","text":"x(5x² − 20)"}]'::jsonb, 'b', 'الخطوة 1 — نُخرج العامل المشترك الأكبر: 5x³ − 20x = 5x(x² − 4).
الخطوة 2 — نلاحظ أنّ x² − 4 = x² − 2² وهو فرق مربّعين، فنعمِّله: x² − 4 = (x − 2)(x + 2).
إذن 5x³ − 20x = 5x(x − 2)(x + 2).
الخيار (a) تعميل جزئي فقط (لم نعمِّل x² − 4)، والخياران (c) و(d) خاطئان.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a1aa5eb-7124-54e0-b2b2-0c342dc15700', 'd48dcd17-c9e6-546d-be8d-42c17dd0fc00', 'احسب بالطريقة الذكيّة باستخدام المتطابقات الشهيرة: 97² + 6 × 97 + 9', '[{"id":"a","text":"10000"},{"id":"b","text":"9418"},{"id":"c","text":"9430"},{"id":"d","text":"9409"}]'::jsonb, 'a', 'نُعيد كتابة العبارة بصورة تكشف المتطابقة:
97² + 6 × 97 + 9 = 97² + 2 × 97 × 3 + 3²
وهذا يطابق الصيغة a² + 2ab + b² = (a + b)² حيث a = 97 و b = 3.
إذن العبارة = (97 + 3)² = 100² = 10000.
الخيار (d) هو 97² = 9409 فقط بدون الحدود الأخرى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a474749e-c80e-5b5c-b15d-73be1fdb25ab', 'd48dcd17-c9e6-546d-be8d-42c17dd0fc00', 'عمِّل تعميلًا تامًّا العبارة: 9x² − 6x + 1 − 4y²', '[{"id":"a","text":"(3x − 2y)² − 1"},{"id":"b","text":"(3x + 2y + 1)(3x − 2y − 1)"},{"id":"c","text":"(3x − 2y − 1)(3x + 2y − 1)"},{"id":"d","text":"(3x − 1)² − 4y²"}]'::jsonb, 'c', 'الخطوة 1 — نجمع الحدود الثلاثة الأولى: 9x² − 6x + 1 = (3x)² − 2(3x)(1) + 1² = (3x − 1)².
الخطوة 2 — تصبح العبارة: (3x − 1)² − (2y)²، وهو فرق مربّعين.
الخطوة 3 — نطبّق a² − b² = (a − b)(a + b) حيث a = 3x − 1 و b = 2y:
(3x − 1 − 2y)(3x − 1 + 2y)
وبإعادة الترتيب: (3x − 2y − 1)(3x + 2y − 1).
الخيار (d) هو الخطوة الوسيطة غير المكتملة، و(b) خطأ في إشارة الحدّ الثابت.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79793830-c330-5da6-8f31-3ad78cb2dec6', 'd48dcd17-c9e6-546d-be8d-42c17dd0fc00', 'إذا كان a + b = 7 و ab = 10، فما قيمة a² + b² ؟', '[{"id":"a","text":"49"},{"id":"b","text":"59"},{"id":"c","text":"29"},{"id":"d","text":"39"}]'::jsonb, 'c', 'نستخدم المتطابقة الشهيرة الأولى:
(a + b)² = a² + 2ab + b²
إذن: a² + b² = (a + b)² − 2ab
= 7² − 2 × 10
= 49 − 20
= 29.
الخيار (a) يهمل طرح 2ab، والخيار (d) يطرح ab بدلًا من 2ab.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a2159ea9-40bd-5b05-9478-e1e7f16fcf0b', 'd48dcd17-c9e6-546d-be8d-42c17dd0fc00', 'بيِّن أنّ العبارة التالية عدد ثابت لا يتعلّق بـ x، ثمّ أوجد قيمته:
A = (2x + 1)² + (2x − 1)² − 2(2x + 1)(2x − 1)', '[{"id":"a","text":"0"},{"id":"b","text":"4"},{"id":"c","text":"8x²"},{"id":"d","text":"2"}]'::jsonb, 'b', 'نلاحظ الشكل: u² + v² − 2uv حيث u = (2x + 1) و v = (2x − 1).
هذا يطابق المتطابقة الثانية: (u − v)² = u² − 2uv + v².
إذن: A = (u − v)² = ((2x + 1) − (2x − 1))²
= (2x + 1 − 2x + 1)²
= (2)² = 4.
بالتحقّق بالنشر المباشر:
(2x+1)² = 4x²+4x+1
(2x−1)² = 4x²−4x+1
2(2x+1)(2x−1) = 2(4x²−1) = 8x²−2
A = (4x²+4x+1) + (4x²−4x+1) − (8x²−2) = 8x²+2−8x²+2 = 4 ✓', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'ddbe302b-6317-5fa9-a93d-9eddd64651fe', 'math', '📝 تدريب ⭐⭐⭐: الحساب الحرفي والمتطابقات (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
