  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('37fc9894-1858-5cf0-b712-b7ad9b3b4aab', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'انشر العبارة: −2(3x − 4) ؟', '[{"id":"a","text":"−6x + 8"},{"id":"b","text":"−6x − 8"},{"id":"c","text":"−6x + 4"},{"id":"d","text":"6x − 8"}]'::jsonb, 'a', 'نوزّع −2 على كلّ حدّ مع مراعاة الإشارات: −2 × 3x = −6x و −2 × (−4) = +8. إذن −2(3x − 4) = −6x + 8. الخطأ الشائع: نسيان أنّ سالبًا في سالب يعطي موجبًا فتُكتب −8، أو نسيان ضرب الحدّ الثاني في 2.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2df687dd-026a-5241-a911-ef698f832390', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'انشر العبارة: (3x + 2)² ؟', '[{"id":"a","text":"9x² + 4"},{"id":"b","text":"9x² + 6x + 4"},{"id":"c","text":"9x² + 12x + 4"},{"id":"d","text":"6x² + 12x + 4"}]'::jsonb, 'c', 'مربّع المجموع: (a + b)² = a² + 2ab + b² مع a = 3x وb = 2. إذن (3x)² + 2(3x)(2) + 2² = 9x² + 12x + 4. الخطأ الشائع: نسيان الحدّ الأوسط 2ab فيُحصل على 9x² + 4، أو نسيان مضاعفته فيُحصل على 6x.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d7817946-d5ac-52f9-bf22-b14019574756', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'عمّل العبارة: 3x² − 12 ؟', '[{"id":"a","text":"3(x² − 12)"},{"id":"b","text":"(3x − 12)(x + 1)"},{"id":"c","text":"3(x − 4)(x + 4)"},{"id":"d","text":"3(x − 2)(x + 2)"}]'::jsonb, 'd', 'نُخرج العامل المشترك 3 أوّلًا: 3x² − 12 = 3(x² − 4). ثمّ x² − 4 = x² − 2² فرق مربّعين = (x − 2)(x + 2). النتيجة: 3(x − 2)(x + 2).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('511c23a6-5988-581b-8e8b-93cd092ff15b', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'احسب 102 × 98 باستخدام المتطابقات الشهيرة:', '[{"id":"a","text":"9992"},{"id":"b","text":"9996"},{"id":"c","text":"9998"},{"id":"d","text":"10004"}]'::jsonb, 'b', '102 × 98 = (100 + 2)(100 − 2) = 100² − 2² = 10000 − 4 = 9996. هذه متطابقة فرق المربّعين. الخطأ الشائع: طرح 2 بدل 2² فيُحصل على 9998، أو جمع 4 بدل طرحها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d4cb0049-893e-5942-a530-94978dcf447e', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'عمّل تعميلًا تامًّا: (x + 1)(x − 3) + (x + 1)(2x + 5) ؟', '[{"id":"a","text":"(x + 1)(3x + 2)"},{"id":"b","text":"(x + 1)²(3x + 2)"},{"id":"c","text":"(x + 1)(3x + 8)"},{"id":"d","text":"(x + 1)(x − 3)(2x + 5)"}]'::jsonb, 'a', 'العامل المشترك هو (x + 1)، نُخرجه: (x + 1)[(x − 3) + (2x + 5)] = (x + 1)(3x + 2)، لأنّ x + 2x = 3x و −3 + 5 = 2. الخطأ الشائع: ضرب القوسين المتبقّيين بدل جمعهما كما في (d)، أو خطأ إشارة عند جمع −3 و+5 فيُحصل على 3x + 8، أو الاحتفاظ بالعامل المشترك مرّتين كما في (b).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b79c3d7d-ad1b-51f3-9991-0921a0bcdb85', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'ما قيمة العبارة 2(a + b)² − 2(a − b)² ؟', '[{"id":"a","text":"4a² + 4b²"},{"id":"b","text":"8ab"},{"id":"c","text":"4ab"},{"id":"d","text":"0"}]'::jsonb, 'b', '(a + b)² = a² + 2ab + b² و(a − b)² = a² − 2ab + b². الفرق (a+b)² − (a−b)² = 4ab. نضرب في 2: 2 × 4ab = 8ab. الخطأ الشائع: نسيان المعامل 2 أمام كلّ مربّع فيُحصل على 4ab، أو الظنّ أنّ الفرق يساوي 0 لأنّ المربّعين «متشابهان».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('02bc559a-4f2e-5245-ac82-0e6e363f3ee4', 'ddbe302b-6317-5fa9-a93d-9eddd64651fe', 'math', '👑 تحدّي المناظرة ⭐⭐⭐⭐: الهويّات والتعميل والمعادلات', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
