  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('74efe5bc-1a55-5936-83ed-e13d44dc6487', '02bc559a-4f2e-5245-ac82-0e6e363f3ee4', 'إذا كان a − b = 5 وab = 3، فما قيمة a² + b²؟', '[{"id":"a","text":"19"},{"id":"b","text":"31"},{"id":"c","text":"25"},{"id":"d","text":"28"}]'::jsonb, 'b', 'ننطلق من الهويّة: (a − b)² = a² − 2ab + b²، ومنه a² + b² = (a − b)² + 2ab. بالتعويض: a² + b² = 5² + 2×3 = 25 + 6 = 31. ✓ الخطأ الشائع: طرح 2ab بدل جمعه (فيخرج 25 − 6 = 19)؛ أو نسيان 2ab كلّيًّا (25)؛ أو جمع ab بدل 2ab (28).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85081486-f2c2-5cf3-91be-04a033933e57', '02bc559a-4f2e-5245-ac82-0e6e363f3ee4', 'عمّل تلميذ العبارة 4x² − 25 فكتب: «4x² − 25 = (2x − 5)²». هل من خطأ، وما الصواب؟', '[{"id":"a","text":"نعم، الصواب (2x − 5)(2x + 5) — فرق مربّعين"},{"id":"b","text":"نعم، الصواب (2x + 5)²"},{"id":"c","text":"نعم، الصواب (4x − 5)(4x + 5)"},{"id":"d","text":"لا خطأ، التعميل صحيح"}]'::jsonb, 'a', '4x² − 25 = (2x)² − 5² وهي فرق مربّعين، تُعمَّل إلى (2x − 5)(2x + 5)، لا (2x − 5)². (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين فرق المربّعين a² − b² = (a−b)(a+b) والمربّع الكامل (a−b)² = a² − 2ab + b²؛ للتحقّق: (2x − 5)² = 4x² − 20x + 25 ≠ 4x² − 25.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72271760-f2f9-5663-939e-ca9d895cd936', '02bc559a-4f2e-5245-ac82-0e6e363f3ee4', 'ليكن E = x² − 9 − (x − 3)(2x + 1). عمِّل E ثمّ احسب قيمته عند x = 5.', '[{"id":"a","text":"6"},{"id":"b","text":"−6"},{"id":"c","text":"16"},{"id":"d","text":"−16"}]'::jsonb, 'b', 'نلاحظ x² − 9 = (x − 3)(x + 3) (فرق مربّعين)، فيصير العامل المشترك (x − 3): E = (x − 3)(x + 3) − (x − 3)(2x + 1) = (x − 3)[(x + 3) − (2x + 1)] = (x − 3)(2 − x). عند x = 5: E = (5 − 3)(2 − 5) = 2 × (−3) = −6. ✓ (تحقّق بالنشر: x² − 9 − (2x² − 5x − 3) = −x² + 5x − 6، وعند x=5: −25 + 25 − 6 = −6). الخطأ الشائع: نسيان تغيير إشارات (2x + 1) عند الطرح، أو الاكتفاء بـ x² − 9 = 16.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('20b427db-a189-5f93-9423-844f5d1415af', '02bc559a-4f2e-5245-ac82-0e6e363f3ee4', 'بيّن أنّ العبارة A = (x + 3)² − (x + 1)(x + 5) لا تتعلّق بـ x، وأوجد قيمتها.', '[{"id":"a","text":"14"},{"id":"b","text":"−4"},{"id":"c","text":"4"},{"id":"d","text":"8"}]'::jsonb, 'c', 'ننشر: (x + 3)² = x² + 6x + 9، و(x + 1)(x + 5) = x² + 6x + 5. إذن A = (x² + 6x + 9) − (x² + 6x + 5) = 4. حدود x² و6x تتلاشى، فالعبارة ثابتة قيمتها 4 مهما كان x. ✓ الخطأ الشائع: كتابة (x + 3)² = x² + 9 بإهمال 6x (فلا تُلغى الحدود ويظنّ الناتج متغيّرًا)؛ أو جمع الثابتين 9 + 5 = 14 بدل طرحهما.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('627d00c7-db9a-564a-9a4f-b4e7b7e544c0', '02bc559a-4f2e-5245-ac82-0e6e363f3ee4', 'ما مجموعة حلول المعادلة x³ = 4x في ℝ؟', '[{"id":"a","text":"{−2 ; 0 ; 2}"},{"id":"b","text":"{−2 ; 2}"},{"id":"c","text":"{0 ; 2}"},{"id":"d","text":"{2}"}]'::jsonb, 'a', 'ننقل كلّ شيء لطرف واحد: x³ − 4x = 0، ثمّ نعمّل: x(x² − 4) = 0، أي x(x − 2)(x + 2) = 0. جداء منعدم ⟺ أحد العوامل منعدم: x = 0 أو x = 2 أو x = −2. إذن S = {−2 ; 0 ; 2}. ✓ الخطأ الشائع: القسمة على x للحصول على x² = 4 ⟹ {−2 ; 2} — القسمة على x تُفقد الحلّ x = 0 لأنّ x قد يكون معدومًا؛ لا نقسم أبدًا على مقدار قد ينعدم، بل نعمّل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79c56d1a-931e-54e7-a476-35eaa87f6c2a', '02bc559a-4f2e-5245-ac82-0e6e363f3ee4', 'إذا كان x + 1/x = 3 (مع x ≠ 0)، فما قيمة x² + 1/x²؟', '[{"id":"a","text":"9"},{"id":"b","text":"11"},{"id":"c","text":"6"},{"id":"d","text":"7"}]'::jsonb, 'd', 'نربّع الطرفين بالهويّة (x + 1/x)² = x² + 2·x·(1/x) + 1/x² = x² + 2 + 1/x². وبما أنّ (x + 1/x)² = 3² = 9، فإنّ x² + 1/x² = 9 − 2 = 7. ✓ الخطأ الشائع: كتابة (x + 1/x)² = x² + 1/x² بإهمال الحدّ الأوسط 2 (فيخرج 9)؛ أو جمع 2 بدل طرحه (11).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

