INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('49205de3-502a-5a5a-a531-46e04f49c300', '3175611f-46ae-53ca-8b70-580d3231f54c', 'ما حلّ المعادلة: 2x + 5 = 13 ؟', '[{"id":"a","text":"x = 3"},{"id":"b","text":"x = 4"},{"id":"c","text":"x = 8"},{"id":"d","text":"x = 9"}]'::jsonb, 'b', '2x + 5 = 13 → 2x = 13 − 5 = 8 → x = 4. تحقّق: 2(4) + 5 = 13 ✓', 1)
