INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab929c9e-dff5-5f71-b345-192a20805337', '3175611f-46ae-53ca-8b70-580d3231f54c', 'ما حلّ المعادلة: 5x − 3 = 3x + 7 ؟', '[{"id":"a","text":"x = 1"},{"id":"b","text":"x = 2"},{"id":"c","text":"x = 5"},{"id":"d","text":"x = 10"}]'::jsonb, 'c', '5x − 3 = 3x + 7 → 5x − 3x = 7 + 3 → 2x = 10 → x = 5. تحقّق: 5(5)−3 = 22 و 3(5)+7 = 22 ✓', 2)
