INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('301a0982-c6e8-59be-ba6d-a0e4b5a327f5', 'd8d89bf8-2b16-583f-85bd-beb3818b9e4d', 'ما مجموعة حلول المعادلة: x(2x − 8) = 0 ؟', '[{"id":"a","text":"{ 0 ; −4 }"},{"id":"b","text":"{ 0 ; 4 }"},{"id":"c","text":"{ 0 ; 8 }"},{"id":"d","text":"{ 4 ; 8 }"}]'::jsonb, 'b', 'x(2x − 8) = 0 → إمّا x = 0 أو 2x − 8 = 0 أي 2x = 8 فـ x = 4. مجموعة الحلول: {0 ; 4}.', 2)
