INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e19be12-fd67-5acc-8f8f-2750647b9e20', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما حلّ المعادلة: 3(x − 2) + 5 = 2x + 4 ؟', '[{"id":"a","text":"x = −5"},{"id":"b","text":"x = 1"},{"id":"c","text":"x = 3"},{"id":"d","text":"x = 5"}]'::jsonb, 'd', 'نوسّع: 3x − 6 + 5 = 2x + 4 → 3x − 1 = 2x + 4 → 3x − 2x = 4 + 1 → x = 5. التحقّق: 3(3) + 5 = 14 و2(5) + 4 = 14 ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aada6349-d934-5bf6-a045-ecf7ed9f2cf2', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما مجموعة حلول المعادلة: (x − 5)(2x + 6) = 0 ؟', '[{"id":"a","text":"{ −5 ; −3 }"},{"id":"b","text":"{ −5 ; 6 }"},{"id":"c","text":"{ 5 ; −3 }"},{"id":"d","text":"{ 5 ; 3 }"}]'::jsonb, 'c', 'جداء معدوم: إمّا x − 5 = 0 فـ x = 5، أو 2x + 6 = 0 أي 2x = −6 فـ x = −3. مجموعة الحلول {5 ; −3}.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aee6b3c0-1493-5bf3-bca1-1abcffee50ba', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما حلّ المتراجحة: 3x − 7 < x + 5 ؟', '[{"id":"a","text":"x < 1"},{"id":"b","text":"x < 6"},{"id":"c","text":"x > −6"},{"id":"d","text":"x > 6"}]'::jsonb, 'b', '3x − 7 < x + 5 → 3x − x < 5 + 7 → 2x < 12 → نقسم على 2 (موجب) → x < 6. لا قلب للإشارة لأنّ المعامل موجب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f101f79-1a67-5b75-8189-bfc10cd9385e', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ضعف عدد مزيدًا بـ 7 يساوي 23. ما هو العدد؟', '[{"id":"a","text":"8"},{"id":"b","text":"15"},{"id":"c","text":"16"},{"id":"d","text":"30"}]'::jsonb, 'a', 'نُسمّي العدد x. المعادلة: 2x + 7 = 23 → 2x = 16 → x = 8. التحقّق: 2(8) + 7 = 23 ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('704d9e48-2a96-5829-9890-9ba9ac687b65', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما حلّ المتراجحة: 4 − 3x ≥ 19 ؟', '[{"id":"a","text":"x ≤ −5"},{"id":"b","text":"x ≥ −5"},{"id":"c","text":"x ≤ 5"},{"id":"d","text":"x ≥ 5"}]'::jsonb, 'a', '4 − 3x ≥ 19 → −3x ≥ 15 → نقسم على −3 مع قلب الإشارة → x ≤ −5. التحقّق بـ x = −5: 4 − 3(−5) = 19 ≥ 19 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0bd527cf-ae89-582d-9e03-767d3ff59e49', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما مجموعة الأعداد الصحيحة x التي تحقّق في آنٍ واحد: x > −2 و2x ≤ 6 ؟', '[{"id":"a","text":"{ −2 ; −1 ; 0 ; 1 ; 2 ; 3 }"},{"id":"b","text":"{ −1 ; 0 ; 1 ; 2 }"},{"id":"c","text":"{ −1 ; 0 ; 1 ; 2 ; 3 }"},{"id":"d","text":"{ 0 ; 1 ; 2 ; 3 }"}]'::jsonb, 'c', 'من x > −2 نأخذ x ابتداءً من −1 (لأنّ −2 غير مشمول). من 2x ≤ 6 نجد x ≤ 3. إذن −1 ≤ x ≤ 3، والأعداد الصحيحة هي {−1 ; 0 ; 1 ; 2 ; 3}.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3b314807-8374-5f48-be8b-5dd4241d706d', 'b9d33015-226b-5d6f-8109-8f164dfe2e07', 'math', '👑 تحدّي المناظرة ⭐⭐⭐⭐: معادلات ومتراجحات متقدّمة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
