INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27a89697-94da-5360-a0f0-885a5fcf28cf', '3b314807-8374-5f48-be8b-5dd4241d706d', 'ما حلّ المعادلة (x − 1)² − (x + 2)(x − 2) = 1؟', '[{"id":"a","text":"x = −2"},{"id":"b","text":"x = 2"},{"id":"c","text":"x = 3"},{"id":"d","text":"لا حلّ لها"}]'::jsonb, 'b', 'ننشر: (x − 1)² = x² − 2x + 1، و(x + 2)(x − 2) = x² − 4 (فرق مربّعين). إذن الطرف الأيسر = (x² − 2x + 1) − (x² − 4) = −2x + 5. المعادلة تصير −2x + 5 = 1، أي −2x = −4، ومنه x = 2. ✓ (تحقّق: (2−1)² − (4)(0) = 1 − 0 = 1). الخطأ الشائع: كتابة (x + 2)(x − 2) = x² + 4 بإشارة خاطئة (فيخرج x = −2)؛ أو (x − 1)² = x² + 1 بإهمال −2x.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f93b534a-5498-5795-95cf-36a16f439633', '3b314807-8374-5f48-be8b-5dd4241d706d', 'حلّ تلميذ المتراجحة −2x > 6 فكتب «x > −3». هل من خطأ، وما الصواب؟', '[{"id":"a","text":"نعم، القسمة على سالب تعكس الاتّجاه، الصواب x < −3"},{"id":"b","text":"نعم، الصواب x > 3"},{"id":"c","text":"نعم، الصواب x < 3"},{"id":"d","text":"لا خطأ، الحلّ صحيح"}]'::jsonb, 'a', 'من −2x > 6 نقسم الطرفين على −2، وبما أنّه عدد سالب يُعكَس اتّجاه المتراجحة: x < −3. (تمرين «صيد الخطأ».) التلميذ نسي عكس الاتّجاه. تحقّق بـ x = −4: −2(−4) = 8 > 6 صحيح، بينما x = 0 يعطي 0 > 6 خطأ، فالحلول فعلًا x < −3.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4304ff0e-ad1c-5226-8e5f-711c5452c7d7', '3b314807-8374-5f48-be8b-5dd4241d706d', 'ما مجموعة حلول المعادلة (x − 4)² = 9؟', '[{"id":"a","text":"{7}"},{"id":"b","text":"{13}"},{"id":"c","text":"{1 ; 7}"},{"id":"d","text":"{−1 ; 7}"}]'::jsonb, 'c', '(x − 4)² = 9 ⟺ x − 4 = 3 أو x − 4 = −3 (لأنّ المربّع يساوي 9 لعددين متقابلين ±3). إذن x = 7 أو x = 1، وS = {1 ; 7}. ✓ (تحقّق: (7−4)² = 9 و(1−4)² = (−3)² = 9). الخطأ الشائع: أخذ الجذر الموجب فقط x − 4 = 3 فيضيع الحلّ x = 1 (يُنسى الحلّ السالب)؛ أو كتابة x − 4 = 9 بنسيان الجذر التربيعي (فيخرج 13).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bfc86574-185f-583d-95ef-dd224ccf6ecc', '3b314807-8374-5f48-be8b-5dd4241d706d', 'ما مجموعة حلول المتراجحة −3(x − 1) > 2x + 8؟', '[{"id":"a","text":"x > −1"},{"id":"b","text":"x < −1"},{"id":"c","text":"x < 1"},{"id":"d","text":"x > 1"}]'::jsonb, 'b', 'ننشر: −3x + 3 > 2x + 8. ننقل: −3x − 2x > 8 − 3، أي −5x > 5. نقسم على −5، ومع القسمة على عدد سالب يُعكَس اتّجاه المتراجحة: x < −1. ✓ (تحقّق بـ x = −2: −3(−3) = 9 > 2(−2)+8 = 4 صحيح). الخطأ الشائع: عدم عكس الاتّجاه عند القسمة على (−5) فيخرج x > −1 — وهي أشهر أخطاء المتراجحات.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d412f28-d55b-5bd3-a92e-dbb56f6a2714', '3b314807-8374-5f48-be8b-5dd4241d706d', 'عددان مجموعهما 25، وضِعْف الأوّل يفوق الثاني بـ 8. ما العدد الأوّل؟', '[{"id":"a","text":"14"},{"id":"b","text":"17"},{"id":"c","text":"11"},{"id":"d","text":"9"}]'::jsonb, 'c', 'نضع x الأوّل وy الثاني: x + y = 25 و2x − y = 8. بجمع المعادلتين (يُحذف y): 3x = 33، ومنه x = 11 (ثمّ y = 14). ✓ (تحقّق: 11 + 14 = 25 و2×11 − 14 = 22 − 14 = 8). الخطأ الشائع: إعطاء قيمة الثاني 14 بدل الأوّل؛ أو خطأ إشارة عند الجمع فيخرج 17.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f6ba326f-a03a-586c-98c2-8cde3c7c5294', '3b314807-8374-5f48-be8b-5dd4241d706d', 'ثلث عدد مزيدًا بـ 4 يساوي نصف العدد منقوصًا منه 1. ما هذا العدد؟', '[{"id":"a","text":"5"},{"id":"b","text":"30"},{"id":"c","text":"18"},{"id":"d","text":"−30"}]'::jsonb, 'b', 'نترجم: x/3 + 4 = x/2 − 1. نضرب كلّ الحدود في 6 (المضاعف المشترك): 2x + 24 = 3x − 6. ننقل: 24 + 6 = 3x − 2x، ومنه x = 30. ✓ (تحقّق: 30/3 + 4 = 14 و30/2 − 1 = 14). الخطأ الشائع: ضرب طرفي الكسور في 6 دون ضرب الثابتين 4 و1 (فيخرج 2x + 4 = 3x − 1 ثمّ x = 5).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

