INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2c4b874-30e8-504c-ac5e-843895e584d4', 'a99f6dd2-77a2-59b7-acff-a2e35119d643', 'ما تعريف جملة معادلتَين من الدرجة الأولى بمجهولَين؟', '[{"id":"a","text":"معادلة واحدة من الدرجة الثانية بمجهول واحد تُحلّ بمبدأ الجداء المعدوم"},{"id":"b","text":"معادلتان من الدرجة الأولى بالمجهولَين x وy تُحقَّقان معًا في آنٍ واحد"},{"id":"c","text":"معادلتان من الدرجة الأولى تُحلّ كلّ واحدة منهما بشكل مستقلّ عن الأخرى"},{"id":"d","text":"معادلة واحدة من الدرجة الأولى بمجهولَين تُحلّ بطريقة التعويض فقط"}]'::jsonb, 'b', 'الجملة هي مجموعة معادلتَين من الدرجة الأولى بالمجهولَين x وy؛ الحلّ هو الثنائية (x ; y) التي تُحقّق كلتا المعادلتَين في الآن ذاته، ليس إحداهما فقط.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('29f3c9da-e906-57a9-8c94-7b9a691d2ecf', 'a99f6dd2-77a2-59b7-acff-a2e35119d643', 'في طريقة التعويض، ما الخطوة الأولى؟', '[{"id":"a","text":"نضرب المعادلتَين في عددَين مناسبَين"},{"id":"b","text":"نجمع المعادلتَين طرفًا بطرف مباشرةً"},{"id":"c","text":"نعزل أحد المجهولَين من إحدى المعادلتَين ثمّ نعوّضه في الأخرى"},{"id":"d","text":"نطرح المعادلتَين إحداهما من الأخرى"}]'::jsonb, 'c', 'في طريقة التعويض: نعزل مجهولًا (مثلًا x) من إحدى المعادلتَين، ثمّ نعوّض التعبير المحصَّل في المعادلة الأخرى للحصول على معادلة بمجهول واحد.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('444b9dcc-d7b0-5fec-988b-6b6f2cfa6350', 'a99f6dd2-77a2-59b7-acff-a2e35119d643', 'كيف نتحقّق من صحّة الثنائية الحلّ (x₀ ; y₀) لجملة معادلتَين؟', '[{"id":"a","text":"نعوّض في المعادلة الأولى فقط، فإن تحقّقت كان الحلّ صحيحًا"},{"id":"b","text":"نعوّض في المعادلة الأسهل حسابًا فقط ونكتفي بنتيجتها"},{"id":"c","text":"نقارن قيمتَي x₀ وy₀ ونتأكّد أنّ الأعداد تبدو معقولة الحجم"},{"id":"d","text":"نعوّض في كلتا المعادلتَين ونتحقّق أنّ الطرفَين يتساويان في كلّ منهما"}]'::jsonb, 'd', 'التحقّق الصحيح يستلزم تعويض (x₀ ; y₀) في كلتا المعادلتَين: يجب أن تتحقّق كلتاهما معًا. التحقّق في معادلة واحدة فقط غير كافٍ لأنّ الثنائية قد تُحقّق إحداهما دون الأخرى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db14f278-3179-5deb-b3a0-e4ed3eec76fd', 'a99f6dd2-77a2-59b7-acff-a2e35119d643', 'في طريقة التأليف (الجمع)، ما الهدف من ضرب المعادلتَين في أعداد مناسبة؟', '[{"id":"a","text":"جعل المعادلتَين متماثلتَين تمامًا"},{"id":"b","text":"جعل معامل أحد المجهولَين متعاكسًا في المعادلتَين حتى يختفي بالجمع"},{"id":"c","text":"التخلّص من الأعداد الكسرية في المعادلتَين"},{"id":"d","text":"تحويل المعادلتَين إلى معادلة واحدة من الدرجة الثانية"}]'::jsonb, 'b', 'في طريقة التأليف نضرب المعادلتَين في أعداد مناسبة لجعل معامل أحد المجهولَين متعاكسًا (+k و−k)، فعند جمع المعادلتَين يختفي ذلك المجهول وتبقى معادلة بمجهول واحد.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48276cca-618c-59e5-9b6e-82b8dff833eb', 'a99f6dd2-77a2-59b7-acff-a2e35119d643', 'متى تُفضَّل طريقة التعويض على طريقة التأليف؟', '[{"id":"a","text":"عندما تكون المعاملات أعدادًا كبيرة جدًّا"},{"id":"b","text":"عندما يكون معامل أحد المجهولَين 1 أو −1 في إحدى المعادلتَين"},{"id":"c","text":"عندما تكون المعادلتان متماثلتَين"},{"id":"d","text":"التأليف يُفضَّل دائمًا ولا يُلجأ إلى التعويض أبدًا"}]'::jsonb, 'b', 'التعويض مُفضَّل عندما يمكن عزل مجهول بسهولة، أي حين يكون معامله 1 أو −1 في إحدى المعادلتَين. كلتا الطريقتَين تُعطيان نفس الحلّ دائمًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

