INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('86310bba-8d13-59fb-b8d6-4cd4a80b4bd1', 'b3698968-9bdd-5a04-87a8-d5f872fa3268', 'احلل بطريقة التعويض الجملة المكوّنة من المعادلتَين: x = 3 و 2x + y = 8. ما قيمة y ؟', '[{"id":"a","text":"5"},{"id":"b","text":"2"},{"id":"c","text":"14"},{"id":"d","text":"1"}]'::jsonb, 'b', 'المعادلة الأولى تُعطينا مباشرةً x = 3. نعوّض في الثانية: 2(3) + y = 8، إذن 6 + y = 8، y = 2. الحلّ هو (3 ; 2).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91c39910-2b8b-5da9-b47c-4163d1cc84f6', 'b3698968-9bdd-5a04-87a8-d5f872fa3268', 'الثنائية (3 ; 1) هي حلّ الجملة المكوّنة من المعادلتَين: 2x + y = 7 و x − y = 2. هل هذا صحيح؟', '[{"id":"a","text":"لا، لأنّ المعادلة الأولى فقط محقَّقة"},{"id":"b","text":"لا، لأنّ المعادلة الثانية فقط محقَّقة"},{"id":"c","text":"لا، لأنّ الثنائية الصحيحة هي (4 ; −1)"},{"id":"d","text":"نعم، لأنّ كلتا المعادلتَين محقَّقتان"}]'::jsonb, 'd', 'نتحقّق: المعادلة الأولى: 2(3) + 1 = 6 + 1 = 7 ✓. المعادلة الثانية: 3 − 1 = 2 ✓. إذن (3 ; 1) هو الحلّ الصحيح للجملة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4b38cf9-26ed-5b98-8b28-4def152bce4a', 'b3698968-9bdd-5a04-87a8-d5f872fa3268', 'احلل بطريقة التأليف الجملة المكوّنة من المعادلتَين: x + y = 10 و x − y = 4. ما هو الحلّ؟', '[{"id":"a","text":"(7 ; 3)"},{"id":"b","text":"(6 ; 4)"},{"id":"c","text":"(8 ; 2)"},{"id":"d","text":"(5 ; 5)"}]'::jsonb, 'a', 'بجمع المعادلتَين: (x+y) + (x−y) = 10+4، إذن 2x = 14، x = 7. نعوّض: 7 + y = 10، y = 3. الحلّ هو (7 ; 3). التحقّق: 7+3=10 ✓، 7−3=4 ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d62ca7c-3ebd-5751-adcc-1afa88307b2f', 'b3698968-9bdd-5a04-87a8-d5f872fa3268', 'احلل الجملة المكوّنة من المعادلتَين: x + 3y = 9 و 2x + 3y = 12. ما هو الحلّ؟', '[{"id":"a","text":"(6 ; 1)"},{"id":"b","text":"(0 ; 3)"},{"id":"c","text":"(3 ; 2)"},{"id":"d","text":"(4 ; 2)"}]'::jsonb, 'c', 'نطرح المعادلة الأولى من الثانية: (2x+3y) − (x+3y) = 12−9، إذن x = 3. نعوّض: 3 + 3y = 9، 3y = 6، y = 2. الحلّ (3 ; 2). التحقّق: 3+6=9 ✓، 6+6=12 ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('413fd85d-1622-563e-bba9-e69551afcd63', 'b3698968-9bdd-5a04-87a8-d5f872fa3268', 'احلل الجملة المكوّنة من المعادلتَين: 2x + 3y = 12 و 2x − y = 4. ما هو الحلّ؟', '[{"id":"a","text":"(2 ; 3)"},{"id":"b","text":"(4 ; 0)"},{"id":"c","text":"(1 ; 4)"},{"id":"d","text":"(3 ; 2)"}]'::jsonb, 'd', 'نطرح المعادلة الثانية من الأولى: (2x+3y) − (2x−y) = 12−4، إذن 4y = 8، y = 2. نعوّض في الثانية: 2x − 2 = 4، 2x = 6، x = 3. الحلّ (3 ; 2). التحقّق: 6+6=12 ✓، 6−2=4 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bb25f0a5-ff1b-5bcd-b0ac-5c61293424cf', 'b3698968-9bdd-5a04-87a8-d5f872fa3268', 'مجموع عددَين يساوي 20، والعدد الأوّل يزيد عن الثاني بـ 6. ما هذان العددان؟', '[{"id":"a","text":"14 و 6"},{"id":"b","text":"12 و 8"},{"id":"c","text":"13 و 7"},{"id":"d","text":"15 و 5"}]'::jsonb, 'c', 'نُسمّي العددَين x وy. الشرطان: x + y = 20 و x = y + 6. بالتعويض: (y+6) + y = 20، إذن 2y = 14، y = 7، x = 13. التحقّق: 13+7=20 ✓، 13−7=6 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('93b0884f-f1fa-5677-ba0c-45682a394f86', 'e9b1fb37-38ae-5b12-a38b-c6f536ff90a7', 'math', '⚔️ زعيم الفصل ⭐⭐⭐: جُمل المعادلتَين — التحدّي الأكبر', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
