  ('19994972-418b-5eeb-90e0-8db612ea6855', 'a1dc4ef0-cc8f-54bd-a3f4-9d4f4e1dc851', 'math', '⭐ تمرين: الدوال الخطية والتآلفية — الصور والسوابق والتمثيل', 1, 50, 10, 'practice', 'admin', 1)
