INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f830ff4c-84fe-5bc7-aa13-3c7505a5978b', '19994972-418b-5eeb-90e0-8db612ea6855', 'الدالة التآلفية f تُعرَّف بـ f(x) = −2x + 5. ما قيمة x حين f(x) = 0 (أي سابقة الصفر) ؟', '[{"id":"a","text":"5"},{"id":"b","text":"−5"},{"id":"c","text":"2,5"},{"id":"d","text":"10"}]'::jsonb, 'c', 'نحلّ −2x + 5 = 0، إذن −2x = −5، x = 5/2 = 2,5. هذه هي سابقة الصفر، أي نقطة تقاطع المستقيم مع محور الفواصل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d1f9b78-da86-566d-9b23-ea9bd72d2d40', '19994972-418b-5eeb-90e0-8db612ea6855', 'الدالة التآلفية f تُعرَّف بـ f(x) = 3x + 2. ما قيمة x إذا كانت f(x) = 14 ؟', '[{"id":"a","text":"5"},{"id":"b","text":"6"},{"id":"c","text":"4"},{"id":"d","text":"3"}]'::jsonb, 'c', 'نحلّ 3x + 2 = 14، إذن 3x = 12، x = 4. التحقّق: f(4) = 3(4) + 2 = 14 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
