INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('78519b47-13d4-53ba-bd75-2d99d988b1c6', '6344760c-5d13-5ace-be92-9275a52c654a', 'الدالة التآلفية f تُعرَّف بـ f(x) = −x + 4. ما قيمة f(2) ؟', '[{"id":"a","text":"6"},{"id":"b","text":"2"},{"id":"c","text":"−2"},{"id":"d","text":"4"}]'::jsonb, 'b', 'f(2) = −1 × 2 + 4 = −2 + 4 = 2. معامل التوجيه سالب (a = −1)، إذن المستقيم نازل.', 1)
ON CONFLICT (id) DO UPDATE SET
