  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bbfa171e-f4a6-5a57-944d-e09c2712a7cb', '6344760c-5d13-5ace-be92-9275a52c654a', 'الدالة الخطية f تُعرَّف بـ f(x) = ax وتحقّق f(6) = 18. ما قيمة f(10) ؟', '[{"id":"a","text":"20"},{"id":"b","text":"28"},{"id":"c","text":"180"},{"id":"d","text":"30"}]'::jsonb, 'd', 'من f(6) = 18 نستنتج a = 18 ÷ 6 = 3. إذن f(x) = 3x. f(10) = 3 × 10 = 30.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c2beedac-d602-58bc-a393-3fc7d75c20ee', '6344760c-5d13-5ace-be92-9275a52c654a', 'مستقيمان: f(x) = 4x − 5 و g(x) = −x + 10. ما إحداثيّا نقطة تقاطعهما؟', '[{"id":"a","text":"(3 ; 7)"},{"id":"b","text":"(3 ; 17)"},{"id":"c","text":"(5 ; 15)"},{"id":"d","text":"(7 ; 3)"}]'::jsonb, 'a', 'نحلّ 4x − 5 = −x + 10، إذن 4x + x = 10 + 5، 5x = 15، x = 3. الصورة: f(3) = 4(3) − 5 = 7. نقطة التقاطع هي (3 ; 7). التحقّق: g(3) = −3 + 10 = 7 ✓. الخطأ الشائع: نقل −x دون قلب إشارته فيُحسب 4x − x = 15 ونحصل خطأً على x = 5.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f8536003-53a7-52de-bb8c-0affc30f3c66', '6344760c-5d13-5ace-be92-9275a52c654a', 'الدالة f خطية وتحقّق f(2) = 10؛ الدالة g تآلفية وتحقّق g(0) = 4 و g(2) = 8. أيّ الدالتَين تعطي القيمة الأكبر عند x = 3 ؟', '[{"id":"a","text":"f، لأنّ f(3) = 15 و g(3) = 10"},{"id":"b","text":"g، لأنّ g(3) = 15 و f(3) = 10"},{"id":"c","text":"كلتاهما تعطيان نفس القيمة"},{"id":"d","text":"f، لأنّ f(3) = 12 و g(3) = 10"}]'::jsonb, 'a', 'الدالة f: f(x) = ax، من f(2) = 10 نجد a = 5، إذن f(3) = 15. الدالة g: g(x) = bx + c، من g(0) = 4 نجد c = 4؛ من g(2) = 8 نجد 2b + 4 = 8، b = 2. إذن g(3) = 2(3) + 4 = 10. f(3) = 15 > g(3) = 10، فـ f تعطي القيمة الأكبر. الخطأ الشائع: حساب f(3) بإضافة 2 إلى f(2) فنحصل على 12؛ الصحيح استعمال التناسب لأنّ f خطية: f(3) = 5 × 3 = 15.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

