  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f89cf4ff-ebab-5eb3-84e3-8350eb35163e', 'e50af184-82cf-5fed-a75c-5fe103b19bd8', 'الدالة الخطية f تحقّق f(5) = 15. ما هو معامل التناسب a ؟', '[{"id":"a","text":"a = 5"},{"id":"b","text":"a = 2"},{"id":"c","text":"a = 10"},{"id":"d","text":"a = 3"}]'::jsonb, 'd', 'الدالة الخطية هي f(x) = a·x. إذن f(5) = 5a = 15، فنقسم الطرفَين على 5: a = 3. نتحقّق: f(5) = 3 × 5 = 15 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fefd1013-760f-55a5-8301-3bfdf0fc0411', 'e50af184-82cf-5fed-a75c-5fe103b19bd8', 'لتكن f(x) = 3x − 1. ما هي سابقة العدد 8 بالدالة f ؟', '[{"id":"a","text":"x = 3"},{"id":"b","text":"x = 9"},{"id":"c","text":"x = 4"},{"id":"d","text":"x = 2"}]'::jsonb, 'a', 'السابقة هي قيمة x التي تُعطي f(x) = 8. نحلّ: 3x − 1 = 8، إذن 3x = 9، x = 3. التحقّق: f(3) = 3(3) − 1 = 9 − 1 = 8 ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eb98e9dd-57f4-58f4-a0d3-8a77f5224c3d', 'e50af184-82cf-5fed-a75c-5fe103b19bd8', 'الدالة الخطية g تُمثَّل بيانيًّا بمستقيم يمرّ بنقطة الأصل و بالنقطة (2 ; −6). ما هي قيمة معامل التناسب a ؟', '[{"id":"a","text":"a = −3"},{"id":"b","text":"a = −2"},{"id":"c","text":"a = 2"},{"id":"d","text":"a = 3"}]'::jsonb, 'a', 'الدالة الخطية هي g(x) = a·x. المستقيم يمرّ بـ (2 ; −6)، إذن g(2) = 2a = −6، فنحصل على a = −3. التحقّق: g(2) = −3 × 2 = −6 ✓. المستقيم نازل لأنّ a < 0.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2aa385d0-e81e-5531-a04b-fd0aefb421b6', 'e50af184-82cf-5fed-a75c-5fe103b19bd8', 'مستقيم يمرّ بالنقطتَين A(0 ; 2) و B(3 ; 8). ما هي الدالة التآلفية f التي يمثّلها؟', '[{"id":"a","text":"f(x) = 3x + 2"},{"id":"b","text":"f(x) = 2x + 2"},{"id":"c","text":"f(x) = 2x + 3"},{"id":"d","text":"f(x) = x + 2"}]'::jsonb, 'b', 'معامل التوجيه: a = (8 − 2) / (3 − 0) = 6 / 3 = 2. القطع مع محور التراتيب: b = f(0) = 2. إذن f(x) = 2x + 2. التحقّق: f(0) = 2 ✓، f(3) = 6 + 2 = 8 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f729bcb-ccf8-5167-a100-d128aef14565', 'e50af184-82cf-5fed-a75c-5fe103b19bd8', 'تحسب أجرة سيارة أجرة (تاكسي) وفق الصيغة f(x) = ax + b، حيث x هو عدد الكيلومترات. لرحلة 5 كم تكون الأجرة 9 دنانير، ولرحلة 10 كم تكون 14 دينارًا. ما تكلفة رحلة 20 كم؟', '[{"id":"a","text":"20 دينارًا"},{"id":"b","text":"22 دينارًا"},{"id":"c","text":"24 دينارًا"},{"id":"d","text":"28 دينارًا"}]'::jsonb, 'c', 'من المعطيَين: 5a + b = 9 و 10a + b = 14. نطرح المعادلة الأولى من الثانية: 5a = 5، إذن a = 1. نعوّض في الأولى: 5 + b = 9، b = 4. إذن f(x) = x + 4. تكلفة 20 كم: f(20) = 20 + 4 = 24 دينارًا. التحقّق: f(5) = 9 ✓، f(10) = 14 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('c01e7975-4f52-581d-b788-909e2ff408af', 'a1dc4ef0-cc8f-54bd-a3f4-9d4f4e1dc851', 'math', '👑 تحدّي النخبة ⭐⭐⭐⭐: الدوال الخطية والتآلفية — مستوى المتفوّقين', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db756051-7f6a-5d31-8a2c-d03263ed33c7', 'c01e7975-4f52-581d-b788-909e2ff408af', 'الدالة التآلفية f تُحقّق f(3) = 7 و f(−1) = −5. ما قيمة سابقة العدد 19 بالنسبة لـ f ؟', '[{"id":"a","text":"5"},{"id":"b","text":"7"},{"id":"c","text":"6"},{"id":"d","text":"9"}]'::jsonb, 'b', 'نُحدِّد a و b: a = (7 − (−5)) ÷ (3 − (−1)) = 12 ÷ 4 = 3. ثمّ b = 7 − 3 × 3 = 7 − 9 = −2. إذن f(x) = 3x − 2. لإيجاد سابقة 19 نحلّ: 3x − 2 = 19 ← 3x = 21 ← x = 7. التحقّق: f(7) = 3(7) − 2 = 21 − 2 = 19 ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('771cfc12-c9a0-500c-9fc3-a1059b26adae', 'c01e7975-4f52-581d-b788-909e2ff408af', 'الدالة f خطية وتُحقّق f(3) = −12. الدالة g تآلفية وبيانها يمرّ بالنقطتَين (0 ; 4) و (2 ; −2). ما إحداثيّ x لنقطة تقاطع بياني f و g ؟', '[{"id":"a","text":"4"},{"id":"b","text":"−2"},{"id":"c","text":"−4"},{"id":"d","text":"2"}]'::jsonb, 'c', 'الدالة f خطية: f(x) = ax. من f(3) = −12 نجد a = −12 ÷ 3 = −4، إذن f(x) = −4x. الدالة g تآلفية: a_g = (−2 − 4) ÷ (2 − 0) = −6 ÷ 2 = −3؛ وبما أنّ g(0) = 4 فـ b = 4، إذن g(x) = −3x + 4. نجد تقاطعهما بحلّ: −4x = −3x + 4 ← −4x + 3x = 4 ← −x = 4 ← x = −4. التحقّق: f(−4) = 16 و g(−4) = 12 + 4 = 16 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('763e98b1-0ea4-5f81-b1ca-202bc6ca5ec0', 'c01e7975-4f52-581d-b788-909e2ff408af', 'الدالة f تآلفية بالشكل f(x) = 2x + b وتُحقّق f(−2) = 0. الدالة g تآلفية بالشكل g(x) = ax − 3 وبيانها يمرّ بنقطة التقاطع P مع بيان f عند x = 1. ما قيمة a + b ؟', '[{"id":"a","text":"13"},{"id":"b","text":"7"},{"id":"c","text":"11"},{"id":"d","text":"15"}]'::jsonb, 'a', 'من f(−2) = 0: 2(−2) + b = 0 ← −4 + b = 0 ← b = 4. إذن f(x) = 2x + 4. عند x = 1: f(1) = 2 + 4 = 6، فالنقطة P هي (1 ; 6). بما أنّ P تنتمي إلى بيان g: g(1) = a − 3 = 6 ← a = 9. الناتج: a + b = 9 + 4 = 13.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fc771671-66d7-5d88-aadf-fadca839b190', 'c01e7975-4f52-581d-b788-909e2ff408af', 'بيان الدالة التآلفية f موازٍ لبيان g(x) = 3x − 5، ويمرّ بالنقطة A(2 ; 7). ما قيمة f(−1) ؟', '[{"id":"a","text":"−4"},{"id":"b","text":"2"},{"id":"c","text":"−2"},{"id":"d","text":"4"}]'::jsonb, 'c', 'مستقيمان متوازيان لهما نفس معامل التوجيه، إذن a = 3. نجد b من A(2 ; 7): 3(2) + b = 7 ← 6 + b = 7 ← b = 1. إذن f(x) = 3x + 1. نحسب f(−1) = 3(−1) + 1 = −3 + 1 = −2. التحقّق: f(2) = 6 + 1 = 7 ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('96dfbb09-bfc1-5e28-ba36-4ab38f89d6de', 'c01e7975-4f52-581d-b788-909e2ff408af', 'الدالة التآلفية f تُحقّق f(2) = 4 وبيانها يمرّ بالنقطة B(4 ; 6). النقطة C(−2 ; k) تنتمي إلى بيان f أيضًا. ما قيمة k ؟', '[{"id":"a","text":"−4"},{"id":"b","text":"2"},{"id":"c","text":"4"},{"id":"d","text":"0"}]'::jsonb, 'd', 'نُحدِّد a من النقطتَين اللتَين تنتميان إلى f: a = (6 − 4) ÷ (4 − 2) = 2 ÷ 2 = 1. نجد b من f(2) = 4: 1(2) + b = 4 ← b = 2. إذن f(x) = x + 2. نحسب k = f(−2) = −2 + 2 = 0. التحقّق: f(4) = 4 + 2 = 6 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('67a5b8df-d4b0-5146-b75c-1b5c3d297745', 'c01e7975-4f52-581d-b788-909e2ff408af', 'الدالة f تآلفية وبيانها يمرّ بـ M(1 ; 9) و N(−1 ; 3). الدالة g خطية وتُحقّق g(2) = −6. إذا كانت P نقطة تقاطع بياني f و g، فما قيمة مجموع إحداثيَّي P (أي x_P + y_P) ؟', '[{"id":"a","text":"5"},{"id":"b","text":"−1"},{"id":"c","text":"3"},{"id":"d","text":"2"}]'::jsonb, 'd', 'الدالة f: a = (9 − 3) ÷ (1 − (−1)) = 6 ÷ 2 = 3. نجد b: 3(1) + b = 9 ← b = 6. إذن f(x) = 3x + 6. الدالة g خطية: g(x) = cx؛ من g(2) = −6 نجد c = −3، إذن g(x) = −3x. نجد التقاطع: 3x + 6 = −3x ← 6x = −6 ← x_P = −1. الصورة: y_P = g(−1) = 3. التحقّق: f(−1) = −3 + 6 = 3 ✓. مجموع الإحداثيَّين: x_P + y_P = −1 + 3 = 2.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'a1dc4ef0-cc8f-54bd-a3f4-9d4f4e1dc851', 'math', '📝 تدريب ⭐⭐⭐: الدوال الخطية والتآلفية (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
