  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('470b2abb-e2d1-5315-b0af-5a59725ad1e9', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'الدالة التآلفية f تُعرَّف بـ f(x) = 3x − 5. ما قيمة f(4) ؟', '[{"id":"a","text":"−2"},{"id":"b","text":"7"},{"id":"c","text":"12"},{"id":"d","text":"17"}]'::jsonb, 'b', 'f(4) = 3 × 4 − 5 = 12 − 5 = 7. نعوّض x بـ 4 ثمّ نحسب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eb9ef195-275c-578d-8948-feb571f8b0f2', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'الدالة الخطية f تُعرَّف بـ f(x) = ax وتحقّق f(4) = 12. ما هو تعبير f؟', '[{"id":"a","text":"f(x) = 3x"},{"id":"b","text":"f(x) = 4x"},{"id":"c","text":"f(x) = 8x"},{"id":"d","text":"f(x) = 48x"}]'::jsonb, 'a', 'من f(4) = 12 نجد a = 12 ÷ 4 = 3. إذن f(x) = 3x. التحقّق: f(4) = 3 × 4 = 12 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b51d59e1-2dd4-58e6-bfcb-0c018e325a4f', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'بيان دالة تآلفية يمرّ بالنقطتَين A(1 ; 7) وB(3 ; 11). ما هو تعبيرها؟', '[{"id":"a","text":"f(x) = 4x + 3"},{"id":"b","text":"f(x) = 2x + 7"},{"id":"c","text":"f(x) = 2x + 5"},{"id":"d","text":"f(x) = −2x + 9"}]'::jsonb, 'c', 'معامل التوجيه a = (11 − 7) ÷ (3 − 1) = 4 ÷ 2 = 2. بما أنّ فاصلة A لا تساوي 0 لا نقرأ b مباشرةً، بل نحسب: b = 7 − 2 × 1 = 5. إذن f(x) = 2x + 5. التحقّق: f(3) = 6 + 5 = 11 ✓.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d01578db-cdb6-5429-948d-0af4b218293a', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'الدالة f تُعرَّف بـ f(x) = 3x − 12. ما قيمة x حين f(x) = 0 (الصفر)؟', '[{"id":"a","text":"−4"},{"id":"b","text":"4"},{"id":"c","text":"12"},{"id":"d","text":"36"}]'::jsonb, 'b', 'نحلّ 3x − 12 = 0 → 3x = 12 → x = 4. هذه هي قيمة x التي يقطع عندها البيان محور الفواصل. التحقّق: f(4) = 3(4) − 12 = 0 ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac721d06-1e23-5b71-a645-d75539ffa1a3', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'أيّ مستقيم من المستقيمات التالية نازل (تناقصي)؟', '[{"id":"a","text":"f(x) = 2x − 3"},{"id":"b","text":"f(x) = x"},{"id":"c","text":"f(x) = 4x + 2"},{"id":"d","text":"f(x) = −0,5x + 1"}]'::jsonb, 'd', 'المستقيم نازل (تناقصي) إذا كان معامل التوجيه a سالبًا. الوحيد ذو المعامل السالب هو f(x) = −0,5x + 1 حيث a = −0,5 < 0.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d210975c-8a82-5ce6-a253-c3d8df7a2dec', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'مستقيمان: f(x) = 3x − 1 وg(x) = x + 5. ما إحداثيّا نقطة تقاطعهما؟', '[{"id":"a","text":"(3 ; 8)"},{"id":"b","text":"(2 ; 5)"},{"id":"c","text":"(3 ; 5)"},{"id":"d","text":"(1 ; 6)"}]'::jsonb, 'a', 'نحلّ 3x − 1 = x + 5 → 2x = 6 → x = 3. الصورة: f(3) = 3(3) − 1 = 8. نقطة التقاطع (3 ; 8). التحقّق: g(3) = 3 + 5 = 8 ✓. الخطأ الشائع: التوقّف عند x = 3 وأخذ y = 5 (الحدّ الثابت في g) دون حساب الصورة f(3) = 8.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
