INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c206254-1a5d-5f89-9405-19436cb62a41', '7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', 'علامات 6 تلاميذ مرتّبة تصاعديًّا: 5 ، 9 ، 9 ، 11 ، 13 ، 13. ما هو المعدّل الحسابي؟', '[{"id":"a","text":"10"},{"id":"b","text":"9"},{"id":"c","text":"11"},{"id":"d","text":"10,5"}]'::jsonb, 'a', 'المعدّل الحسابي = مجموع القيم ÷ عددها. المجموع = 5 + 9 + 9 + 11 + 13 + 13 = 60، وعدد القيم 6، إذن المعدّل = 60 ÷ 6 = 10. تحقّق: 10 يقع ضمن المدى [5 ; 13] ✓.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('da2cdf7b-de2a-5a15-af0f-ba0384fae853', '7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', 'في السلسلة المرتّبة ذاتها (n = 6): 5 ، 9 ، 9 ، 11 ، 13 ، 13. ما هو الوسيط؟', '[{"id":"a","text":"9"},{"id":"b","text":"10"},{"id":"c","text":"11"},{"id":"d","text":"9,5"}]'::jsonb, 'b', 'n = 6 (زوجي)، نأخذ متوسّط قيمتَي الرتبتين 3 و4. القيمة الثالثة = 9 والرابعة = 11. الوسيط = (9 + 11) ÷ 2 = 10.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1f27784-df99-5e5e-99c5-db6baa9da9ed', '7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', 'حصل 5 تلاميذ على العلامة 12، و3 تلاميذ على العلامة 8، و2 تلاميذ على العلامة 16 (n = 10). ما هو المعدّل الحسابي؟', '[{"id":"a","text":"12"},{"id":"b","text":"11"},{"id":"c","text":"11,6"},{"id":"d","text":"10,8"}]'::jsonb, 'c', 'المجموع = (5 × 12) + (3 × 8) + (2 × 16) = 60 + 24 + 32 = 116. المعدّل = 116 ÷ 10 = 11,6.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac35bf2e-668e-5f5f-9d8f-b2c572a3747a', '7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', 'في فصل من 60 تلميذًا، حصل 15 تلميذًا على علامة 10. ما هي زاوية القطاع الدائري المقابل لهذه الفئة؟', '[{"id":"a","text":"60°"},{"id":"b","text":"54°"},{"id":"c","text":"90°"},{"id":"d","text":"36°"}]'::jsonb, 'c', 'نحسب أوّلًا التواتر = التكرار ÷ التكرار الكلّي = 15 ÷ 60 = 0,25. ثمّ زاوية القطاع = التواتر × 360° = 0,25 × 360° = 90°. تحقّق: 90° هي ربع الدائرة، وفعلًا 15 تلميذًا = ربع الـ60 ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b10c460-3768-5fcb-8dcf-906f9469fdb8', '7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', 'علامات 5 تلاميذ: 13 ، 2 ، 15 ، 14 ، 16، ومعدّلها الحسابي 12. بعد حذف العلامة الشاذّة 2، ما هو معدّل العلامات الأربع المتبقّية؟', '[{"id":"a","text":"12"},{"id":"b","text":"14"},{"id":"c","text":"14,5"},{"id":"d","text":"15"}]'::jsonb, 'c', 'المجموع الكلّي = 13 + 2 + 15 + 14 + 16 = 60. بعد حذف 2: المجموع = 60 − 2 = 58 والعدد = 4، فالمعدّل الجديد = 58 ÷ 4 = 14,5. لاحظ أثر القيمة الشاذّة: المعدّل قفز من 12 إلى 14,5 بحذفها. الخطأ الشائع: القسمة على 4 مع إبقاء المجموع 60 (يعطي 15) — عند حذف قيمة يجب حذفها من المجموع أيضًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a3a4174f-3449-5d04-b13b-ba858351fcca', '7880a5ae-03cb-524b-aef9-ff8c1bb9b85b', 'سلسلة إحصائية من 8 قيم مرتّبة: 6 ، 6 ، 8 ، 10 ، 10 ، 12 ، 14 ، 14. ما هو الوسيط؟', '[{"id":"a","text":"8"},{"id":"b","text":"9"},{"id":"c","text":"10"},{"id":"d","text":"11"}]'::jsonb, 'c', 'n = 8 (زوجي)، نأخذ متوسّط قيمتَي الرتبتين 4 و5. القيمة الرابعة = 10 والخامسة = 10. الوسيط = (10 + 10) ÷ 2 = 10. الخطأ الشائع: أخذ قيمة الرتبة n ÷ 2 وحدها دون حساب متوسّط الرتبتين الوسطيَين — هنا تتصادف القيمتان، لكنّ القاعدة في السلسلة الزوجية هي المتوسّط دائمًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('31f9bc81-3462-51c0-a42a-4bc1079be296', '02eb650b-9f63-52d8-af00-acd3d01b6c4d', 'math', '⭐⭐ تمرين مراجعة: الإحصاء (نمط امتحان)', 2, 70, 15, 'practice', 'admin', 3)
