  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd5e6dd8-ea99-5933-a9a1-bace14e89610', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في السلسلة الإحصائية: 7 ، 9 ، 9 ، 11 ، 12 ، 12 ، 15. ما هو منوال هذه السلسلة؟', '[{"id":"a","text":"7 و15"},{"id":"b","text":"9 و12"},{"id":"c","text":"11"},{"id":"d","text":"12 فقط"}]'::jsonb, 'b', 'نعدّ التكرارات: 9 تظهر مرّتين و12 تظهر مرّتين، وبقية القيم مرّة واحدة. أعلى تكرار (2) مشترك بين قيمتين، فللسلسلة منوالان: 9 و12. أمّا 11 فهي الوسيط (القيمة الوسطى) لا المنوال، و7 و15 هما الطرفان فقط.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56c67eec-e7cc-51d9-b44b-d10607c08039', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في السلسلة المرتّبة: 4 ، 7 ، 9 ، 11 ، 15 (n = 5). ما هو الوسيط؟', '[{"id":"a","text":"8"},{"id":"b","text":"9"},{"id":"c","text":"9,2"},{"id":"d","text":"11"}]'::jsonb, 'b', 'n = 5 (فردي)، الوسيط هو القيمة ذات الرتبة الوسطى (الثالثة). القيمة الثالثة في السلسلة المرتّبة هي 9.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3924deed-45ce-50c4-bd9c-f2c73b7fedca', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'حصل 4 تلاميذ على العلامة 15، و6 تلاميذ على العلامة 10. ما هو المعدّل الحسابي للمجموعة (n = 10)؟', '[{"id":"a","text":"11,5"},{"id":"b","text":"12"},{"id":"c","text":"12,5"},{"id":"d","text":"25"}]'::jsonb, 'b', 'المجموع = (4 × 15) + (6 × 10) = 60 + 60 = 120. المعدّل = 120 ÷ 10 = 12.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ed0f229-7973-510f-b0d7-2d34cecd6e1a', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في فصلٍ، حصل 12 تلميذًا على العلامة 15، وكان تواترهم يساوي 25 %. كم عدد تلاميذ الفصل؟', '[{"id":"a","text":"3"},{"id":"b","text":"37"},{"id":"c","text":"48"},{"id":"d","text":"300"}]'::jsonb, 'c', 'التواتر = التكرار ÷ التكرار الكلّي، إذن التكرار الكلّي = التكرار ÷ التواتر = 12 ÷ 0,25 = 48 تلميذًا. تحقّق: 25 % من 48 = 12 ✓. الانتباه: الضرب بدل القسمة يعطي 12 × 0,25 = 3، والضرب في 25 دون تحويلها إلى 0,25 يعطي 300 — كلاهما خاطئ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8bf05e6-1c21-5ad3-b12f-3c2fda68efc0', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في مخطّط دائري لـ 200 شخص، تقابل فئةٌ زاوية قطاع قيسها 72°. كم عدد أفراد هذه الفئة؟', '[{"id":"a","text":"36"},{"id":"b","text":"40"},{"id":"c","text":"50"},{"id":"d","text":"72"}]'::jsonb, 'b', 'التواتر = زاوية القطاع ÷ 360° = 72 ÷ 360 = 0,2. عدد الأفراد = التواتر × الكلّ = 0,2 × 200 = 40. الخطأ الشائع: اعتبار قيس الزاوية (72) عدد الأفراد مباشرةً، أو قسمته على 2 (36) — لا بدّ من المرور بالتواتر 72/360.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31033c3d-18db-5262-a31c-24970a5413f3', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'سلسلة مرتّبة تصاعديًّا من 6 قيم: 4 ، 6 ، x ، 10 ، 12 ، 14، ووسيطها يساوي 8. ما قيمة x؟', '[{"id":"a","text":"6"},{"id":"b","text":"8"},{"id":"c","text":"9"},{"id":"d","text":"10"}]'::jsonb, 'a', 'n = 6 (زوجي)، فالوسيط هو متوسّط القيمتَين ذواتَي الرتبتين 3 و4: (x + 10) ÷ 2 = 8، إذن x + 10 = 16، أي x = 6. تحقّق: (6 + 10) ÷ 2 = 8 ✓ والترتيب التصاعدي محفوظ (6 ≤ 6 ≤ 10). الخطأ الشائع: اعتبار الوسيط مساويًا للقيمة الثالثة x مباشرةً (فيُختار 8) — في السلسلة الزوجية الوسيط متوسّط القيمتين الوسطيين لا إحداهما.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d90951c3-ed33-5ae4-86ac-aff741f3f599', '4d3cea13-a54f-55f1-ad8d-853c7c9ef05d', 'math', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('075bd18f-b446-5391-9188-c16ef59435ba', 'd90951c3-ed33-5ae4-86ac-aff741f3f599', 'ما الشرط الجوهري الذي يجب التحقّق منه قبل تطبيق نظرية طاليس في مثلّث ABC مع نقطتَي M على [AB] وN على [AC]؟', '[{"id":"a","text":"أن تكون AM = AN وأن يكون M منتصف الضلع [AB]"},{"id":"b","text":"أن يكون المثلّث ABC متساوي الأضلاع وأضلاعه معلومة"},{"id":"c","text":"أن يكون (MN) ∥ (BC) وأن تكون M وN داخل الضلعين"},{"id":"d","text":"أن يكون AB = AC وأن تكون الزاوية في A قائمة"}]'::jsonb, 'c', 'الشرط الجوهري هو أن يكون المستقيم (MN) موازيًا للضلع (BC)، وأن تكون النقطتان M وN داخل الضلعين (بين الرأس والقاعدة). دون هذين الشرطين لا تنطبق النظرية.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3368a55d-6afc-5355-a33e-d7eb5c4929f9', 'd90951c3-ed33-5ae4-86ac-aff741f3f599', 'في وضعية طاليس ((MN) ∥ (BC) في مثلّث ABC)، أيّ المعادلات التالية تعبّر بشكل صحيح عن نصّ النظرية؟', '[{"id":"a","text":"AM + AN = AB + AC"},{"id":"b","text":"AM/AB = AN/AC = MN/BC"},{"id":"c","text":"AB/AM = BC/MN"},{"id":"d","text":"AM × AC = AN × AB"}]'::jsonb, 'b', 'نصّ نظرية طاليس: AM/AB = AN/AC = MN/BC. كلّ نسبة تمثّل «الجزء على الكلّ» في الضلع المقابل، والنسب الثلاث متساوية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('690208b9-ff39-52ab-bb0c-c9208945043a', 'd90951c3-ed33-5ae4-86ac-aff741f3f599', 'في صيغة «الجزء على الجزء المتبقّي» لنظرية طاليس ((MN) ∥ (BC))، أيّ التساويات صحيح؟', '[{"id":"a","text":"AM/MB = BC/MN"},{"id":"b","text":"MB/AN = NC/AM"},{"id":"c","text":"AM/MB = AN/NC"},{"id":"d","text":"AM/MB = MN/BC"}]'::jsonb, 'c', 'صيغة «الجزء على الجزء المتبقّي» هي: AM/MB = AN/NC، وهي مفيدة حين تُعطى أطوال MB أو NC مباشرةً. الخطأ الشائع: إدخال MN/BC في هذه السلسلة — فالنسبة MN/BC تساوي AM/AB (الجزء على الضلع كاملًا) ولا تساوي AM/MB.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b6133a7-579e-537c-b1b9-058068093beb', 'd90951c3-ed33-5ae4-86ac-aff741f3f599', 'ما الذي تمكّننا منه النظرية العكسية لطاليس؟', '[{"id":"a","text":"حساب طول ضلع مجهول في المثلّث"},{"id":"b","text":"إثبات أنّ مثلّثًا ما قائم الزاوية"},{"id":"c","text":"إثبات توازي مستقيمَين بالتحقّق من تساوي نسبتَين"},{"id":"d","text":"تحديد نسبة التشابه بين مثلّثين"}]'::jsonb, 'c', 'النظرية العكسية تقول: إذا تحقّق AM/AB = AN/AC (مع كون M وN على نفس الجانب من A)، فإنّ (MN) ∥ (BC). تُستعمل لإثبات التوازي دون قياس زوايا أو استخدام أدوات رسم.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('522f5897-8a34-5993-a690-149ca504cb68', 'd90951c3-ed33-5ae4-86ac-aff741f3f599', 'في وضعية «الفراشة» (تقاطع مستقيمَين في نقطة O مع (AB) ∥ (CD))، أيّ التساوي ينتج من تطبيق نظرية طاليس؟', '[{"id":"a","text":"OA + OB = OC + OD"},{"id":"b","text":"OA/OC = OB/OD = AB/CD"},{"id":"c","text":"AB = CD"},{"id":"d","text":"OA/AB = OC/CD"}]'::jsonb, 'b', 'في وضعية الفراشة (مثلّثان OAB وOCD بحيث (AB) ∥ (CD))، تطبيق نظرية طاليس برأس O يعطي: OA/OC = OB/OD = AB/CD. الرأس هنا نقطة التقاطع O وليس رأس مثلّث عادي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

