  ('f326e9ff-8f5d-59a0-bc33-b53615d43f3d', '4d3cea13-a54f-55f1-ad8d-853c7c9ef05d', 'math', '⭐⭐ تمرين: تطبيق نظرية طاليس وحساب الأطوال', 2, 75, 15, 'practice', 'admin', 1)
