INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d59856b-0025-5edf-9712-df204c8cf43d', 'f326e9ff-8f5d-59a0-bc33-b53615d43f3d', 'في مثلّث ABC، (MN) ∥ (BC)، وM على [AB] بحيث AM = 5 cm وMB = 3 cm. ما هي نسبة AM/AB؟', '[{"id":"a","text":"5/3"},{"id":"b","text":"3/8"},{"id":"c","text":"5/8"},{"id":"d","text":"3/5"}]'::jsonb, 'c', 'AB = AM + MB = 5 + 3 = 8 cm. إذن AM/AB = 5/8.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('532e4f79-a180-595e-bad6-4db7449b7e9a', 'f326e9ff-8f5d-59a0-bc33-b53615d43f3d', 'في وضعية طاليس (في مثلّث ABC مع (MN) ∥ (BC))، أيّ النسب التالية تساوي AM/AB؟', '[{"id":"a","text":"AB/AM"},{"id":"b","text":"BC/MN"},{"id":"c","text":"MN/BC"},{"id":"d","text":"AN/AB"}]'::jsonb, 'c', 'نصّ نظرية طاليس: AM/AB = AN/AC = MN/BC. إذن MN/BC هي النسبة المساوية لـ AM/AB.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0afcd18c-829f-593d-8c89-713cffedf56f', 'f326e9ff-8f5d-59a0-bc33-b53615d43f3d', 'في مثلّث ABC، يقطع المستقيم (MN) الضلعَين [AB] و[AC] في M وN على الترتيب بحيث (MN) ∥ (BC). إذا كان AM = 3 cm وAB = 6 cm وAN = 4 cm، فما قيمة AC؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"8 cm"},{"id":"c","text":"12 cm"},{"id":"d","text":"2 cm"}]'::jsonb, 'b', 'بتطبيق نظرية طاليس: AM/AB = AN/AC. إذن 3/6 = 4/AC، ومنه AC = 4 × 6 ÷ 3 = 8 cm.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07a1a81e-a0e8-5920-8870-56226919bf79', 'f326e9ff-8f5d-59a0-bc33-b53615d43f3d', 'في مثلّث ABC، (MN) ∥ (BC) حيث AM = 4 cm وAB = 12 cm وBC = 9 cm. ما طول MN؟', '[{"id":"a","text":"4 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"2 cm"},{"id":"d","text":"3 cm"}]'::jsonb, 'd', 'نسبة التشابه = AM/AB = 4/12 = 1/3. إذن MN = BC × (1/3) = 9 × (1/3) = 3 cm.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef9b12ce-7730-5e36-9549-eb0e6275914f', 'f326e9ff-8f5d-59a0-bc33-b53615d43f3d', 'في مثلّث ABC، M على [AB] وN على [AC]. إذا تحقّق AM/AB = AN/AC، ما الذي يمكن الاستنتاج بمقتضى النظرية العكسية لطاليس؟', '[{"id":"a","text":"(MN) ∥ (AB)"},{"id":"b","text":"(MN) ⊥ (BC)"},{"id":"c","text":"(MN) ∥ (BC)"},{"id":"d","text":"المثلّثَ AMN متساوي الأضلاع"}]'::jsonb, 'c', 'بمقتضى النظرية العكسية لطاليس: إذا كانت AM/AB = AN/AC وM وN على نفس الجانب من A، فإنّ (MN) ∥ (BC).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9920c496-e34b-56ca-ab36-d83a11a11bb2', 'f326e9ff-8f5d-59a0-bc33-b53615d43f3d', 'في مثلّث DEF، M على [DE] وN على [DF] بحيث DM = 6 cm وDE = 9 cm وDN = 4 cm وDF = 6 cm. هل (MN) ∥ (EF)؟', '[{"id":"a","text":"نعم، لأنّ DM/DE = DN/DF = 2/3"},{"id":"b","text":"لا، لأنّ 6/9 ≠ 4/6 فالنسبتان مختلفتان"},{"id":"c","text":"نعم، لأنّ DE − DM = DF − DN"},{"id":"d","text":"لا، لأنّ DM ≠ DN فالشرط غير متحقّق"}]'::jsonb, 'a', 'DM/DE = 6/9 = 2/3 وDN/DF = 4/6 = 2/3. النسبتان متساويتان، فبالنظرية العكسية لطاليس (MN) ∥ (EF). الخطأ الشائع: الحكم على 6/9 و4/6 بأنّهما مختلفان دون اختزال — كلاهما يساوي 2/3. ولاحظ أنّ الفرقين DE − DM = 3 وDF − DN = 2 مختلفان: النظرية تقارن النسب لا الفروق.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('24ddb42f-96f9-5d15-bda7-fadbd675c804', '4d3cea13-a54f-55f1-ad8d-853c7c9ef05d', 'math', '⚔️ زعيم الفصل ⭐⭐⭐: نظرية طاليس والأطوال المجهولة', 3, 120, 30, 'boss', 'admin', 2)
