INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2ceb13be-7d1a-5b30-857e-272159ecb34a', '24ddb42f-96f9-5d15-bda7-fadbd675c804', 'في مثلّث ABC، (MN) ∥ (BC) مع AM = 6 cm وMB = 4 cm وMN = 3 cm. ما طول BC؟', '[{"id":"a","text":"4 cm"},{"id":"b","text":"5 cm"},{"id":"c","text":"6 cm"},{"id":"d","text":"4,5 cm"}]'::jsonb, 'b', 'AB = AM + MB = 6 + 4 = 10 cm. نسبة التشابه = AM/AB = 6/10 = 3/5. إذن MN/BC = 3/5، ومنه BC = MN ÷ (3/5) = 3 × 5/3 = 5 cm.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
