  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e16c95ae-301f-5611-a556-0bc68fb575f7', '24ddb42f-96f9-5d15-bda7-fadbd675c804', 'في وضعية الفراشة، يتقاطع مستقيمان في O مع (AB) ∥ (CD). إذا كان OA = 4 cm وOC = 6 cm وAB = 5 cm، فما طول CD؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"7 cm"},{"id":"c","text":"7,5 cm"},{"id":"d","text":"8 cm"}]'::jsonb, 'c', 'بنظرية طاليس في وضعية الفراشة: OA/OC = AB/CD. إذن 4/6 = 5/CD، ومنه CD = 5 × 6/4 = 30/4 = 7,5 cm.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9dec898-598b-54a1-bc6e-ec5cb998972e', '24ddb42f-96f9-5d15-bda7-fadbd675c804', 'في مثلّث ABC، M على [AB] وN على [AC]. AM = 2 cm، MB = 6 cm، AN = 3 cm، NC = 9 cm. هل (MN) ∥ (BC)؟', '[{"id":"a","text":"نعم، لأنّ AM/AB = AN/AC = 1/4"},{"id":"b","text":"لا، لأنّ 2/8 ≠ 3/12 فالنسبتان مختلفتان"},{"id":"c","text":"نعم، لأنّ AM + AN = 2 + 3 = 5"},{"id":"d","text":"لا، لأنّ NC − MB = 9 − 6 = 3 ≠ 0"}]'::jsonb, 'a', 'AB = AM + MB = 2 + 6 = 8 cm، فـ AM/AB = 2/8 = 1/4. AC = AN + NC = 3 + 9 = 12 cm، فـ AN/AC = 3/12 = 1/4. النسبتان متساويتان، إذن بالنظرية العكسية (MN) ∥ (BC). الخطأ الشائع: الحكم على 2/8 و3/12 بأنّهما مختلفان دون اختزال، أو مقارنة الفروق بدل النسب — التوازي لا يتطلّب MB = NC.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('71d49b34-8c27-56e3-8e48-96ee2353f19b', '24ddb42f-96f9-5d15-bda7-fadbd675c804', 'في مثلّث ABC، AB = 15 cm و(MN) ∥ (BC) حيث AM/AB = 2/5 وBC = 10 cm. ما طول MN؟', '[{"id":"a","text":"3 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"4 cm"},{"id":"d","text":"5 cm"}]'::jsonb, 'c', 'بنظرية طاليس: MN/BC = AM/AB = 2/5. إذن MN = BC × (2/5) = 10 × (2/5) = 4 cm.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd9c01fe-fddb-523e-b8e5-0d67dbd39857', '24ddb42f-96f9-5d15-bda7-fadbd675c804', 'في مثلّث DEF، (MN) ∥ (EF) مع DM = 5 cm وME = 3 cm وNF = 1,8 cm. أوجد DN = x.', '[{"id":"a","text":"x = 2 cm"},{"id":"b","text":"x = 2,5 cm"},{"id":"c","text":"x = 3 cm"},{"id":"d","text":"x = 4 cm"}]'::jsonb, 'c', 'DE = DM + ME = 5 + 3 = 8 cm. DF = DN + NF = x + 1,8. نظرية طاليس: DM/DE = DN/DF. إذن 5/8 = x/(x + 1,8). بالتقاطع: 8x = 5(x + 1,8) = 5x + 9. ومنه 3x = 9، أي x = 3 cm. الخطأ الشائع: مزج «الجزء على الكلّ» مع «الجزء على الجزء» بكتابة DM/DE = DN/NF — يجب مقارنة DN بالضلع الكامل DF = x + 1,8.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1cd6a70c-c45e-5409-b6c4-048771ff3fc0', '24ddb42f-96f9-5d15-bda7-fadbd675c804', 'في مثلّث PQR، (ST) ∥ (QR) مع PS = x + 1 وPQ = 3x − 1 وPT = 4 cm وPR = 10 cm. ما قيمة x؟', '[{"id":"a","text":"x = 5"},{"id":"b","text":"x = 6"},{"id":"c","text":"x = 7"},{"id":"d","text":"x = 3"}]'::jsonb, 'c', 'بنظرية طاليس: PS/PQ = PT/PR، أي (x+1)/(3x−1) = 4/10 = 2/5. بالتقاطع: 5(x+1) = 2(3x−1)، أي 5x + 5 = 6x − 2، ومنه x = 7. التحقّق: PS = 8، PQ = 20، فـ 8/20 = 2/5. وPT/PR = 4/10 = 2/5. ✓ الخطأ الشائع: عدم توزيع الضرب على الحدّين (كتابة 5(x+1) = 5x + 1)، ممّا يقود إلى الجواب الخاطئ x = 3.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

