  ('f33ee550-688a-5f83-8b1c-f714109898ed', '4d3cea13-a54f-55f1-ad8d-853c7c9ef05d', 'math', '⭐⭐ تمرين مراجعة: نظرية طاليس وعكسها (نمط امتحان)', 2, 70, 15, 'practice', 'admin', 3)
