INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c198ec7-be2b-5c8d-ad88-51ed81b5d46c', 'f33ee550-688a-5f83-8b1c-f714109898ed', 'أيّ من العبارات التالية تعبّر بشكل صحيح عن النظرية العكسية لطاليس؟', '[{"id":"a","text":"إذا كان AM/AB = AN/AC وM وN داخل الضلعين، فإنّ (MN) ∥ (BC)"},{"id":"b","text":"إذا كانت (MN) ∥ (BC)، فإنّ AM = AN وMB = NC في كلّ الحالات"},{"id":"c","text":"إذا كان MN = BC وكانت M وN داخل الضلعين، فإنّ (MN) ∥ (BC)"},{"id":"d","text":"إذا كان AM/MB = AN/AC، فإنّ (MN) ∥ (BC) مهما كان موضع M وN"}]'::jsonb, 'a', 'النظرية العكسية لطاليس تنصّ على: إذا تحقّق AM/AB = AN/AC مع كون M وN على نفس الجانب من الرأس A (داخل الضلعين)، فإنّ (MN) ∥ (BC). الخطأ الشائع: مزج الصيغتين بكتابة AM/MB = AN/AC — يجب مقارنة «جزء على كلّ» مع «جزء على كلّ» (أو «جزء على جزء» مع «جزء على جزء»).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cca2fb5e-9ee4-5c71-89c0-cdba4e2b52f8', 'f33ee550-688a-5f83-8b1c-f714109898ed', 'في مثلّث ABC، M على [AB] وN على [AC]. هل (MN) ∥ (BC) إذا كان AM = 4 cm وAB = 6 cm وAN = 6 cm وAC = 9 cm؟', '[{"id":"a","text":"نعم، لأنّ AM/AB = AN/AC = 2/3"},{"id":"b","text":"لا، لأنّ 4/6 ≠ 6/9 فالنسبتان مختلفتان"},{"id":"c","text":"نعم، لأنّ AM + AN = 4 + 6 = 10"},{"id":"d","text":"لا، لأنّ AB − AM = 2 وAC − AN = 3"}]'::jsonb, 'a', 'AM/AB = 4/6 = 2/3 وAN/AC = 6/9 = 2/3. النسبتان متساويتان، فبالنظرية العكسية لطاليس (MN) ∥ (BC). الخطأ الشائع: الحكم على 4/6 و6/9 بأنّهما مختلفان دون اختزال — كلاهما 2/3. والنظرية تقارن النسب لا الفروق (MB = 2 وNC = 3 لا يمنعان التوازي).', 3)
