  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9e409479-42b0-5460-b5e0-2f31d6f2dba6', 'f33ee550-688a-5f83-8b1c-f714109898ed', 'في وضعية الفراشة، يتقاطع مستقيمان في O مع (AB) ∥ (CD). إذا كان OA = 3 cm وOC = 9 cm وOB = 4 cm، فما طول OD؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"9 cm"},{"id":"c","text":"10 cm"},{"id":"d","text":"12 cm"}]'::jsonb, 'd', 'بنظرية طاليس في وضعية الفراشة: OA/OC = OB/OD، إذن 3/9 = 4/OD، ومنه OD = 4 × 9 ÷ 3 = 12 cm.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4e7423e-350d-507a-8190-fd0f52071315', 'f33ee550-688a-5f83-8b1c-f714109898ed', 'في مثلّث ABC، (MN) ∥ (BC) حيث AM = 6 cm وAB = 9 cm وBC = 12 cm. ما طول MN؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"8 cm"},{"id":"c","text":"9 cm"},{"id":"d","text":"10 cm"}]'::jsonb, 'b', 'بنظرية طاليس: MN/BC = AM/AB = 6/9 = 2/3. إذن MN = BC × (2/3) = 12 × (2/3) = 8 cm.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cda3fe59-386a-5a33-9fca-650b899f6654', 'f33ee550-688a-5f83-8b1c-f714109898ed', 'في مثلّث DEF، (MN) ∥ (EF)، DM = x cm وME = 4 cm وDN = 3 cm وNF = 2 cm. ما قيمة x؟', '[{"id":"a","text":"x = 4 cm"},{"id":"b","text":"x = 5 cm"},{"id":"c","text":"x = 6 cm"},{"id":"d","text":"x = 8 cm"}]'::jsonb, 'c', 'DE = DM + ME = x + 4، وDF = DN + NF = 3 + 2 = 5 cm. بنظرية طاليس: DM/DE = DN/DF، أي x/(x+4) = 3/5. بالتقاطع: 5x = 3(x+4) = 3x + 12، ومنه 2x = 12، أي x = 6 cm. التحقّق: 6/10 = 3/5. ✓', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0140931b-06a1-57ea-8a77-4ec6e47fc316', '4d3cea13-a54f-55f1-ad8d-853c7c9ef05d', 'math', '👑 تحدّي النخبة ⭐⭐⭐⭐: نظرية طاليس — مسائل متقدّمة متعدّدة الخطوات', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('58d08233-af38-5efb-ac86-c8c038630619', '0140931b-06a1-57ea-8a77-4ec6e47fc316', 'في مثلّث ABC، النقطة M على [AB] والنقطة N على [AC] بحيث (MN) ∥ (BC). المعطيات: AM = x cm وMB = 6 cm وAN = 4 cm وNC = (x + 2) cm. أوجد x أوّلًا، ثمّ استنتج طول MN علمًا أنّ BC = 15 cm.', '[{"id":"a","text":"MN = 4 cm"},{"id":"b","text":"MN = 5 cm"},{"id":"c","text":"MN = 6 cm"},{"id":"d","text":"MN = 7,5 cm"}]'::jsonb, 'c', 'الخطوة 1 — إيجاد x بنظرية طاليس (صيغة الجزء على الجزء): AM/MB = AN/NC، إذن x/6 = 4/(x + 2). بالضرب التقاطعي: x(x + 2) = 24. نبحث عن عددين موجبين الفرق بينهما 2 وجداؤهما 24: هما 4 و6، إذن x = 4. التحقّق: 4 × 6 = 24 ✓. ومنه AM = 4 cm وNC = 6 cm. الخطوة 2 — حساب MN: AB = AM + MB = 4 + 6 = 10 cm. بنظرية طاليس: MN/BC = AM/AB = 4/10 = 2/5. إذن MN = 15 × (2/5) = 6 cm. الخطأ الشائع: مزج الصيغتين بكتابة AM/AB = AN/NC — صيغة «الجزء على الجزء» تقارن AM بـ MB وAN بـ NC حصرًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9497b139-438e-5002-8508-a1b2f086b343', '0140931b-06a1-57ea-8a77-4ec6e47fc316', 'في وضعية الفراشة، يتقاطع مستقيمان في النقطة O بحيث (AB) ∥ (CD). المعطيات: OA = 3 cm وOC = 9 cm وOB = 4 cm وAB = 8 cm. أوجد OD وCD، ثمّ احسب محيط المثلّث OCD.', '[{"id":"a","text":"المحيط = 36 cm"},{"id":"b","text":"المحيط = 40 cm"},{"id":"c","text":"المحيط = 42 cm"},{"id":"d","text":"المحيط = 45 cm"}]'::jsonb, 'd', 'الخطوة 1 — إيجاد OD بنظرية طاليس في وضعية الفراشة: OA/OC = OB/OD، إذن 3/9 = 4/OD، ومنه OD = (4 × 9)/3 = 12 cm. الخطوة 2 — إيجاد CD: AB/CD = OA/OC = 3/9 = 1/3، إذن CD = AB × 3 = 8 × 3 = 24 cm. التحقّق: OB/OD = 4/12 = 1/3 = OA/OC. ✓ الخطوة 3 — المحيط: OC + OD + CD = 9 + 12 + 24 = 45 cm. الخطأ الشائع: قسمة AB على 3 بدل الضرب — بما أنّ OC = 3 × OA فإنّ [CD] أبعد عن O وأطول من [AB]، فـ CD = 24 لا 8/3.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7d3ee860-ba3b-5ce3-8aba-7ef708ee7f39', '0140931b-06a1-57ea-8a77-4ec6e47fc316', 'في مثلّث ABC، المستقيمان (DE) و(FG) يوازيان (BC)، مع D وF على [AB] وE وG على [AC] بحيث AD = 4 cm وAF = 6 cm وAB = 12 cm وBC = 24 cm. ما قيمة FG − DE؟', '[{"id":"a","text":"FG − DE = 2 cm"},{"id":"b","text":"FG − DE = 4 cm"},{"id":"c","text":"FG − DE = 6 cm"},{"id":"d","text":"FG − DE = 8 cm"}]'::jsonb, 'b', 'الخطوة 1 — إيجاد DE: بنظرية طاليس مع (DE) ∥ (BC): DE/BC = AD/AB = 4/12 = 1/3، إذن DE = 24 × (1/3) = 8 cm. الخطوة 2 — إيجاد FG: بنظرية طاليس مع (FG) ∥ (BC): FG/BC = AF/AB = 6/12 = 1/2، إذن FG = 24 × (1/2) = 12 cm. الخطوة 3: FG − DE = 12 − 8 = 4 cm. ملاحظة: كلّما اقتربنا من B كلّما زادت القطعة المتوازية مع (BC)، فالترتيب صحيح: A وD وF وB على [AB] وFG > DE. الخطأ الشائع: حساب النسب بقسمة الأطوال بعضها على بعض (AD/AF = 4/6) بدل قسمة كلّ طول على الضلع الكامل AB انطلاقًا من الرأس A.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('daf7c0ca-51d5-50fc-9699-ae38472a6214', '0140931b-06a1-57ea-8a77-4ec6e47fc316', 'في مثلّث PQR، النقطة S على [PQ] بحيث PS = 8 cm وSQ = 4 cm، والنقطة T على [PR] بحيث PT = 10 cm وTR = 5 cm. أثبت أنّ (ST) ∥ (QR)، ثمّ أوجد ST إذا كان QR = 18 cm.', '[{"id":"a","text":"ST = 9 cm"},{"id":"b","text":"ST = 10 cm"},{"id":"c","text":"ST = 12 cm"},{"id":"d","text":"ST = 14 cm"}]'::jsonb, 'c', 'الخطوة 1 — إثبات التوازي بالنظرية العكسية: PQ = PS + SQ = 8 + 4 = 12 cm، فـ PS/PQ = 8/12 = 2/3. PR = PT + TR = 10 + 5 = 15 cm، فـ PT/PR = 10/15 = 2/3. النسبتان متساويتان (2/3) والنقطتان S وT من نفس جانب الرأس P، إذن بالنظرية العكسية لطاليس: (ST) ∥ (QR). ✓ الخطوة 2 — إيجاد ST: بنظرية طاليس: ST/QR = PS/PQ = 2/3، إذن ST = 18 × (2/3) = 12 cm. الخطأ الشائع: حساب القطعة الموازية بنسبة «الجزء على الجزء» (PS/SQ = 2) فيخرج ST = 36 — نسبة القطعة الموازية هي دائمًا «الجزء على الكلّ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('12cf9b49-156a-5d12-9f20-6321641c1d1d', '0140931b-06a1-57ea-8a77-4ec6e47fc316', 'في مثلّث ABC، النقطة D على [AB] والنقطة E على [AC] بحيث (DE) ∥ (BC)، مع AD = 6 cm وAB = 10 cm. النقطة F على [AD] والنقطة G على [AE] بحيث (FG) ∥ (DE)، مع AF = 3 cm. إذا كان BC = 20 cm، فما طول FG؟', '[{"id":"a","text":"FG = 6 cm"},{"id":"b","text":"FG = 10 cm"},{"id":"c","text":"FG = 12 cm"},{"id":"d","text":"FG = 24 cm"}]'::jsonb, 'a', 'نطبّق طاليس مرّتين. الخطوة 1 — في المثلّث ABC مع (DE) ∥ (BC): DE/BC = AD/AB = 6/10 = 3/5، إذن DE = 20 × (3/5) = 12 cm. الخطوة 2 — في المثلّث ADE مع (FG) ∥ (DE): FG/DE = AF/AD = 3/6 = 1/2، إذن FG = 12 × (1/2) = 6 cm. التحقّق: بما أنّ (FG) ∥ (BC) أيضًا، فمباشرةً FG = BC × AF/AB = 20 × 3/10 = 6 cm ✓. الخطأ الشائع: التوقّف عند DE = 12 واعتباره الجواب، أو قلب النسبة الثانية (FG = DE × AD/AF = 24).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d89c0aee-4979-58d1-b2d8-c9c4fa558b60', '0140931b-06a1-57ea-8a77-4ec6e47fc316', 'في وضعية الفراشة، يتقاطع مستقيمان في O بحيث (AB) ∥ (CD). المعطيات: OA = k cm وOC = (k + 6) cm وOB = 4 cm وOD = 8 cm وAB = 7 cm. أوجد k، ثمّ استنتج طول CD.', '[{"id":"a","text":"CD = 3,5 cm"},{"id":"b","text":"CD = 14 cm"},{"id":"c","text":"CD = 21 cm"},{"id":"d","text":"CD = 28 cm"}]'::jsonb, 'b', 'الخطوة 1 — إيجاد k بنظرية طاليس: OA/OC = OB/OD، إذن k/(k + 6) = 4/8 = 1/2. بالضرب التقاطعي: 2k = k + 6، ومنه k = 6. إذن OA = 6 cm وOC = 12 cm. التحقّق: 6/12 = 1/2 = 4/8 ✓. الخطوة 2 — إيجاد CD: AB/CD = OA/OC = 1/2، إذن CD = 7 × 2 = 14 cm. الخطأ الشائع: قلب النسبة وقسمة AB على 2 (يعطي 3,5 — لكنّ [CD] أبعد عن O فهو أطول)، أو تربيع النسبة كما في نسب المساحات (يعطي 28).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('bb04c882-d576-55ca-a4bc-95e36b356ece', '4d3cea13-a54f-55f1-ad8d-853c7c9ef05d', 'math', '📝 تدريب ⭐⭐⭐: نظرية طاليس (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56679dc7-5896-555f-a5e7-3f09eee7efdf', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث ABC، (MN) ∥ (BC) مع M على [AB] وN على [AC]. إذا كان MN = 6 cm وBC = 9 cm وAB = 12 cm، فما طول AM؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"8 cm"},{"id":"c","text":"9 cm"},{"id":"d","text":"18 cm"}]'::jsonb, 'b', 'بنظرية طاليس: AM/AB = MN/BC = 6/9 = 2/3. إذن AM = AB × (2/3) = 12 × (2/3) = 8 cm. الخطأ الشائع: قلب النسبة (AM = 12 × 9/6 = 18) — وهو مستحيل لأنّ M على [AB] فلا بدّ أن يكون AM أصغر من AB = 12.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b0151feb-0b03-5582-9fc3-4e405ee7c7cf', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في وضعية الفراشة، يتقاطع مستقيمان في O مع (AB) ∥ (CD). إذا كان OA = 4 cm وOB = 5 cm وOD = 15 cm، فما طول OC؟', '[{"id":"a","text":"9 cm"},{"id":"b","text":"10 cm"},{"id":"c","text":"12 cm"},{"id":"d","text":"18,75 cm"}]'::jsonb, 'c', 'في وضعية الفراشة بنظرية طاليس: OA/OC = OB/OD = 5/15 = 1/3. إذن 4/OC = 1/3، ومنه OC = 4 × 3 = 12 cm. التحقّق: 4/12 = 5/15 = 1/3 ✓. الخطأ الشائع: قلب الاقتران بين الأطوال (OC = OB × OD/OA = 18,75)، أو التفكير الجمعي بطرح OD − OB = 10 — العلاقة في طاليس تناسبية لا جمعية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('348408ff-9c0e-5c62-b105-75c53a036b85', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث ABC، M على [AB] وN على [AC] مع AM = 3 cm، AB = 7 cm، AN = 4 cm، AC = 9 cm. هل (MN) ∥ (BC)؟', '[{"id":"a","text":"لا، لأنّ 3/7 ≠ 4/9"},{"id":"b","text":"لا، لأنّ AM ≠ AN"},{"id":"c","text":"نعم، لأنّ 3/7 = 4/9"},{"id":"d","text":"نعم، لأنّ النسبتين متقاربتان والفرق مهمَل"}]'::jsonb, 'a', 'نقارن بالجداء التقاطعي: 3 × 9 = 27 و7 × 4 = 28، فـ 3/7 ≠ 4/9، إذن بحسب النظرية العكسية (MN) غير موازٍ لـ (BC). الخطأ الشائع: الاكتفاء بالتقريب — 3/7 ≈ 0,429 و4/9 ≈ 0,444 متقاربان، لكنّ عكس طاليس يتطلّب تساويًا تامًّا لا تقريبيًّا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('39ba41a1-3361-50af-a1f6-7821ad43d8de', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث ABC، (MN) ∥ (BC) مع AM = 4 cm وMB = 6 cm وAN = 5 cm. ما طول NC؟', '[{"id":"a","text":"3,33 cm"},{"id":"b","text":"5 cm"},{"id":"c","text":"6 cm"},{"id":"d","text":"7,5 cm"}]'::jsonb, 'd', 'بنظرية طاليس: AM/MB = AN/NC، أي 4/6 = 5/NC. بالتقاطع: 4 × NC = 6 × 5 = 30، إذن NC = 30 ÷ 4 = 7,5 cm. الخطأ الشائع: قلب النسبة وكتابة NC = AN × AM/MB = 5 × 4/6 ≈ 3,33 — بما أنّ MB > AM فلا بدّ أن يكون NC > AN.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82996a2b-263d-5605-871c-c58f97ccf090', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث ABC، (MN) ∥ (BC) مع AM = 4 cm، AN = 6 cm، NC = 9 cm. ما طول AB؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"8 cm"},{"id":"c","text":"10 cm"},{"id":"d","text":"13 cm"}]'::jsonb, 'c', 'AC = AN + NC = 6 + 9 = 15 cm. بنظرية طاليس: AM/AB = AN/AC، أي 4/AB = 6/15 = 2/5. بالتقاطع: 2 × AB = 4 × 5 = 20، إذن AB = 10 cm. الخطأ الشائع: استعمال AN/NC بدل AN/AC (4/AB = 6/9 يعطي AB = 6) — يجب أوّلًا حساب الضلع الكامل AC.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ef82e17-97db-5707-9533-d74dc3d11af9', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث PQR، (ST) ∥ (QR) مع PS = 2x وPQ = 12 cm وPT = x + 1 وPR = 8 cm. ما قيمة x؟', '[{"id":"a","text":"x = 1,5"},{"id":"b","text":"x = 2"},{"id":"c","text":"x = 3"},{"id":"d","text":"x = 4"}]'::jsonb, 'c', 'بنظرية طاليس: PS/PQ = PT/PR، أي 2x/12 = (x+1)/8. بالتقاطع: 8 × 2x = 12 × (x+1) → 16x = 12x + 12 → 4x = 12 → x = 3. التحقّق: PS=6، PT=4؛ 6/12 = 1/2 و4/8 = 1/2 ✓. الخطأ الشائع: مساواة الطولين PS = PT (أي 2x = x + 1) بدل مساواة النسبتين — التوازي يعني تناسب الأطوال لا تساويها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('1acebeb3-aac9-53d6-91ca-0eba4c7f3382', '4d3cea13-a54f-55f1-ad8d-853c7c9ef05d', 'math', '👑 تحدّي المناظرة ⭐⭐⭐⭐: طاليس في وضعيات مركّبة — طاليس وبيثاغورس والمساحات', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c62d86ee-589e-5a89-9a4b-0270a40e5368', '1acebeb3-aac9-53d6-91ca-0eba4c7f3382', 'المثلّث ABC قائم الزاوية في A، مع AB = 9 cm وAC = 12 cm. النقطة M على [AB] والنقطة N على [AC] بحيث (MN) ∥ (BC) وAM = 3 cm. احسب طول MN.', '[{"id":"a","text":"MN = 7 cm"},{"id":"b","text":"MN = 5 cm"},{"id":"c","text":"MN = 4 cm"},{"id":"d","text":"MN = 7,5 cm"}]'::jsonb, 'b', 'الخطوة 1 — حساب BC بنظرية بيثاغورس في المثلّث القائم في A: BC² = AB² + AC² = 9² + 12² = 81 + 144 = 225، إذن BC = 15 cm. الخطوة 2 — نسبة التصغير: AM/AB = 3/9 = 1/3. الخطوة 3 — بنظرية طاليس مع (MN) ∥ (BC): MN/BC = AM/AB = 1/3، إذن MN = 15 × (1/3) = 5 cm. ✓ الخطأ الشائع: حساب BC بجمع الضلعين (9 + 12 = 21) فيخرج MN = 7 cm — بيثاغورس يجمع المربّعات لا الأطوال؛ أو استعمال «الجزء على الجزء» AM/MB = 3/6 = 1/2 فيخرج 7,5 cm.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('17be556c-9802-59c4-ad49-abd0a7ba4f49', '1acebeb3-aac9-53d6-91ca-0eba4c7f3382', 'في مثلّث ABC مع (MN) ∥ (BC) وAM = 4 cm وAB = 10 cm وBC = 15 cm، أراد تلميذ حساب MN فكتب: «الخطوة 1: النسبة = AM/AB = 4/10 = 2/5. الخطوة 2: MN/BC = 2/5. الخطوة 3: MN = 15 × 5/2 = 37,5 cm.» ما الخطوة الخاطئة؟', '[{"id":"a","text":"الخطوة 1"},{"id":"b","text":"الخطوة 2"},{"id":"c","text":"الخطوة 3"},{"id":"d","text":"لا خطأ، الحلّ صحيح"}]'::jsonb, 'c', 'الخطوتان 1 و2 صحيحتان: النسبة AM/AB = 4/10 = 2/5، وبنظرية طاليس MN/BC = 2/5. الخطأ في الخطوة 3: من MN/BC = 2/5 نضرب في BC لا نقسم، أي MN = 15 × (2/5) = 6 cm، لا 15 × (5/2) = 37,5 cm. التلميذ قلب النسبة. (تمرين «صيد الخطأ»: الجواب الصحيح هو الخطوة التي تحوي الغلط.) تنبيه للتحقّق: بما أنّ MN أقصر من BC فلا يعقل أن يكون 37,5 > 15.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6c1ee59a-6412-5de8-bb85-c3aba13d10e1', '1acebeb3-aac9-53d6-91ca-0eba4c7f3382', 'في المثلّث ABC، النقطة D على [AB] والنقطة E على [AC] بحيث (DE) ∥ (BC) وAD/AB = 2/5. مساحة المثلّث ABC هي 100 cm². ما مساحة شبه المنحرف DBCE (الجزء المحصور بين (DE) و(BC))؟', '[{"id":"a","text":"60 cm²"},{"id":"b","text":"16 cm²"},{"id":"c","text":"36 cm²"},{"id":"d","text":"84 cm²"}]'::jsonb, 'd', 'بما أنّ (DE) ∥ (BC) فالمثلّث ADE مصغّر للمثلّث ABC بنسبة الأطوال k = AD/AB = 2/5. نسبة المساحات تساوي مربّع نسبة الأطوال: k² = (2/5)² = 4/25. الخطوة 1 — مساحة ADE = 100 × 4/25 = 16 cm². الخطوة 2 — مساحة شبه المنحرف = مساحة ABC − مساحة ADE = 100 − 16 = 84 cm². ✓ الخطأ الشائع: استعمال نسبة الأطوال 2/5 مباشرةً للمساحات (100 × 2/5 = 40، فيخرج شبه المنحرف 60 cm²) — نسبة المساحات هي مربّع نسبة الأطوال لا النسبة نفسها. الجواب 16 cm² هو مساحة ADE وحده لا شبه المنحرف.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7db3eb1a-213a-5e11-847f-358412dcdf1d', '1acebeb3-aac9-53d6-91ca-0eba4c7f3382', 'المثلّث ABC قائم الزاوية في A. النقطة M على [AB] والنقطة N على [AC] بحيث (MN) ∥ (BC)، مع AM = 4 cm وAN = 3 cm وMB = 4 cm. احسب cos(ABC︿) (جيب تمام الزاوية B في المثلّث ABC).', '[{"id":"a","text":"cos(B) = 0,8"},{"id":"b","text":"cos(B) = 0,6"},{"id":"c","text":"cos(B) = 0,75"},{"id":"d","text":"cos(B) = 1,33"}]'::jsonb, 'a', 'الخطوة 1 — في المثلّث AMN القائم في A: MN² = AM² + AN² = 4² + 3² = 25، إذن MN = 5 cm. الخطوة 2 — نسبة طاليس: AB = AM + MB = 4 + 4 = 8 cm، فـ k = AM/AB = 4/8 = 1/2. الخطوة 3 — الأضلاع في ABC: AC = AN/k = 3/(1/2) = 6 cm، وBC = MN/k = 5/(1/2) = 10 cm (أو بيثاغورس: BC = √(8² + 6²) = √100 = 10 cm ✓). الخطوة 4 — في المثلّث القائم في A، بالنسبة للزاوية B: الضلع المجاور هو AB والوتر هو BC، إذن cos(B) = AB/BC = 8/10 = 0,8. ✓ الخطأ الشائع: أخذ الضلع المقابل بدل المجاور cos = AC/BC = 6/10 = 0,6 (وهذا هو sin B)، أو حساب tan = AC/AB = 6/8 = 0,75، أو قلب النسبة AB/AC = 1,33 (مستحيل: جيب التمام لا يتجاوز 1).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('14e79bd8-81b2-5498-99f8-5b4e8819ca6b', '1acebeb3-aac9-53d6-91ca-0eba4c7f3382', 'في مثلّث ABC، النقطة M على [AB] والنقطة N على [AC] بحيث (MN) ∥ (BC). المعطيات: AM = (x − 1) cm وMB = 6 cm وAN = x cm وNC = 8 cm. أوجد x، ثمّ احسب MN علمًا أنّ BC = 15 cm.', '[{"id":"a","text":"MN = 7,5 cm"},{"id":"b","text":"MN = 6 cm"},{"id":"c","text":"MN = 5 cm"},{"id":"d","text":"MN = 4 cm"}]'::jsonb, 'c', 'الخطوة 1 — إيجاد x بنظرية طاليس (صيغة الجزء على الجزء): AM/MB = AN/NC، إذن (x − 1)/6 = x/8. بالضرب التقاطعي: 8(x − 1) = 6x، أي 8x − 8 = 6x، ومنه 2x = 8 وx = 4. إذن AM = 3 cm وAN = 4 cm. التحقّق: 3/6 = 4/8 = 1/2 ✓. الخطوة 2 — حساب MN: AB = AM + MB = 3 + 6 = 9 cm، فالنسبة AM/AB = 3/9 = 1/3، إذن MN = BC × (1/3) = 15 × (1/3) = 5 cm. الخطأ الشائع: استعمال «الجزء على الجزء» AM/MB = 3/6 = 1/2 لحساب القطعة الموازية فيخرج 7,5 cm — نسبة القطعة الموازية هي دائمًا «الجزء على الكلّ». الجواب 4 cm ناتج عن الاكتفاء بقيمة x دون حساب MN.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('313e52a5-15e3-5b63-bfb7-4be0cefeab7f', '1acebeb3-aac9-53d6-91ca-0eba4c7f3382', 'عمود شاقوليّ طوله 6 m يُلقي في الشمس ظلًّا طوله 8 m، وفي اللحظة نفسها تُلقي شجرة مجاورة ظلًّا طوله 20 m على الأرض الأفقيّة. ما المسافة المستقيمة من قمّة الشجرة إلى الطرف البعيد لظلّها؟', '[{"id":"a","text":"25 m"},{"id":"b","text":"15 m"},{"id":"c","text":"35 m"},{"id":"d","text":"17 m"}]'::jsonb, 'a', 'العمود وظلّه، والشجرة وظلّها، يكوّنان مثلّثين قائمين متشابهين (الأشعّة الشمسيّة متوازية → نظرية طاليس). الخطوة 1 — ارتفاع الشجرة h: ارتفاع/ظلّ ثابت، إذن 6/8 = h/20، ومنه h = (6 × 20)/8 = 15 m. الخطوة 2 — المسافة المطلوبة هي وتر المثلّث القائم الذي ضلعاه القائمان هما ارتفاع الشجرة (15 m) وظلّها (20 m): d = √(15² + 20²) = √(225 + 400) = √625 = 25 m. ✓ (تحقّق: وتر مثلّث العمود = √(6² + 8²) = 10 m، والنسبة 20/8 = 2,5، و10 × 2,5 = 25 m ✓.) الخطأ الشائع: الخلط بين الارتفاع 15 m والمسافة المائلة، أو جمع 15 + 20 = 35 بدل تطبيق بيثاغورس، أو استعمال ظلّ العمود 8 بدل ظلّ الشجرة 20 فيخرج √(15² + 8²) = 17 m.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

