  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('51bd4869-6785-596b-a9f8-ec026d774363', '3b45c6b0-a990-57dc-9859-74a56930d2e2', 'في المثلث ABC القائم في B، الزاوية A = 30° والوتر AC = 8 cm. ما طول الضلع BC؟', '[{"id":"a","text":"4 cm"},{"id":"b","text":"4√3 cm"},{"id":"c","text":"8√3 cm"},{"id":"d","text":"16 cm"}]'::jsonb, 'a', 'BC يقابل الزاوية A، إذن جا(A) = BC/AC. نكتب: جا(30°) = BC/8، أي 1/2 = BC/8، فينتج BC = 4 cm.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
