INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d20f096e-13e3-5f7c-aa12-9a58fb391cdb', '3b45c6b0-a990-57dc-9859-74a56930d2e2', 'أيّ العلاقات التالية صحيحة دائمًا لأيّ زاوية حادّة x؟', '[{"id":"a","text":"جا(x) + جتا(x) = 1"},{"id":"b","text":"جا²(x) + جتا²(x) = 1"},{"id":"c","text":"جا(x) × جتا(x) = 1"},{"id":"d","text":"ظا(x) = جتا(x) ÷ جا(x)"}]'::jsonb, 'b', 'العلاقة المثلثية الأساسية المشتقّة من فيثاغورس: جا²(x) + جتا²(x) = 1. يمكن التحقّق: جا²(30°) + جتا²(30°) = (1/2)² + (√3/2)² = 1/4 + 3/4 = 1.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('80e5983d-9550-5c46-b8da-75359679e18f', 'fa8e46c4-235e-5b70-a34b-17b1a9a1920b', 'math', '⚔️ زعيم الفصل ⭐⭐⭐: فيثاغورس والنسب المثلثية — مواجهة الأوتار', 3, 120, 30, 'boss', 'admin', 2)
