INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eca425d1-2139-5def-96d3-cc196a9f4ec3', '80e5983d-9550-5c46-b8da-75359679e18f', 'في المثلث ABC القائم في B، AB = 5 cm وBC = 12 cm. ما طول الوتر AC؟', '[{"id":"a","text":"13 cm"},{"id":"b","text":"17 cm"},{"id":"c","text":"√17 cm"},{"id":"d","text":"169 cm"}]'::jsonb, 'a', 'بنظرية فيثاغورس: AC² = AB² + BC² = 25 + 144 = 169، إذن AC = √169 = 13 cm. هذه هي الثلاثية المشهورة (5 ; 12 ; 13).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7756d42f-d6b8-597e-9ac8-561228ef119c', '80e5983d-9550-5c46-b8da-75359679e18f', 'في المثلث ABC القائم في B، AB = 3 cm وAC = 6 cm. ما قيمة الزاوية A؟', '[{"id":"a","text":"30°"},{"id":"b","text":"45°"},{"id":"c","text":"60°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'جتا(A) = المجاور/الوتر = AB/AC = 3/6 = 1/2. ومن جدول القيم المشهورة: جتا(60°) = 1/2، إذن الزاوية A = 60°.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3be61ed8-9dad-5bd8-96bd-658b7bf37cdb', '80e5983d-9550-5c46-b8da-75359679e18f', 'مثلث أضلاعه 7 cm و24 cm و25 cm. هل هو قائم الزاوية؟', '[{"id":"a","text":"نعم، لأنّ 7² + 24² = 25²"},{"id":"b","text":"لا، لأنّ 7 + 24 ≠ 25"},{"id":"c","text":"نعم، لأنّ 7 + 24 > 25"},{"id":"d","text":"لا، لأنّ 7² + 24² ≠ 25²"}]'::jsonb, 'a', 'نحسب: 7² + 24² = 49 + 576 = 625 = 25². بما أنّ مجموع مربّعي الضلعين الأصغرين يساوي مربّع الضلع الأكبر، فالمثلث قائم الزاوية بعكس فيثاغورس.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e58b813c-6f19-5dc1-8956-6fd01e9b3f54', '80e5983d-9550-5c46-b8da-75359679e18f', 'في مثلث قائم، الزاوية A حادّة وظا(A) = √3. ما قيمة الزاوية A؟', '[{"id":"a","text":"30°"},{"id":"b","text":"45°"},{"id":"c","text":"60°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'من جدول القيم المشهورة: ظا(60°) = √3. إذن الزاوية A = 60°. تذكّر: ظا(30°) = √3/3 وظا(45°) = 1.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c2b81dea-f750-5535-8070-b2ff6fb7cc6e', '80e5983d-9550-5c46-b8da-75359679e18f', 'إذا كانت جا(x) = √3/2 وكانت x زاوية حادّة، فما قيمة جتا(x)؟', '[{"id":"a","text":"√3/2"},{"id":"b","text":"1/2"},{"id":"c","text":"√2/2"},{"id":"d","text":"1"}]'::jsonb, 'b', 'جا(x) = √3/2 يعني x = 60°. إذن جتا(60°) = 1/2. يمكن التحقّق باستعمال العلاقة الأساسية: جتا²(x) = 1 − جا²(x) = 1 − 3/4 = 1/4، فجتا(x) = 1/2. الخطأ الشائع: اختيار √3/2 ظنًّا أنّ الجيب وجيب التمام متساويان دائمًا — لا يتساويان إلّا عند 45°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cbd6cbe7-2f11-59c5-b6be-0ba8bd2f84f3', '80e5983d-9550-5c46-b8da-75359679e18f', 'في المثلث ABC القائم في B، الزاوية C = 45° والوتر AC = 10 cm. ما طول الضلع BC؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"5√2 cm"},{"id":"c","text":"10√2 cm"},{"id":"d","text":"10 cm"}]'::jsonb, 'b', 'جتا(C) = BC/AC، إذن جتا(45°) = BC/10، أي √2/2 = BC/10، فينتج BC = 10 × √2/2 = 5√2 cm ≈ 7,07 cm. الخطأ الشائع: الضرب في √2 بدل √2/2 (يعطي 10√2 وهو أطول من الوتر — مستحيل)، أو الخلط مع جتا(60°) = 1/2 (يعطي 5).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

