INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('62b743c1-f651-569a-a772-66e5937c98c9', '45ea24b7-4622-54df-a97f-ccfa0ea12ad5', 'في مثلّث ABC قائم الزاوية في B، الوتر AC = 25 cm وAB = 7 cm. ما طول BC؟', '[{"id":"a","text":"18 cm"},{"id":"b","text":"24 cm"},{"id":"c","text":"√674 cm"},{"id":"d","text":"32 cm"}]'::jsonb, 'b', 'AC هو الوتر (المقابل للزاوية القائمة). بفيثاغورس: AC² = AB² + BC²، إذن BC² = 25² − 7² = 625 − 49 = 576، ومنه BC = √576 = 24 cm. هذه الثلاثية المشهورة (7 ; 24 ; 25). الخطأ الشائع: جمع المربّعين (√674) وكأنّ AC ضلع قائم — عند البحث عن ضلع قائم نطرح من مربّع الوتر.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0fcda9a1-fa34-5768-8c5c-e1850330d1d2', '45ea24b7-4622-54df-a97f-ccfa0ea12ad5', 'في مثلّث ABC قائم الزاوية في B، زاوية A = 45°. أيّ من القيم التالية صحيحة؟', '[{"id":"a","text":"جتا(45°) = 1"},{"id":"b","text":"جا(45°) = √3/2"},{"id":"c","text":"جتا(45°) = √2/2"},{"id":"d","text":"ظا(45°) = √3"}]'::jsonb, 'c', 'الزوايا المشهورة: جا(45°) = جتا(45°) = √2/2 ≈ 0,707، وظا(45°) = 1. إذن جتا(45°) = √2/2 هي الإجابة الصحيحة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3fab56a3-4d34-5074-84da-a46a457be4dc', '45ea24b7-4622-54df-a97f-ccfa0ea12ad5', 'مثلث أضلاعه 8 cm و15 cm و17 cm. هل هو قائم الزاوية؟', '[{"id":"a","text":"لا، لأنّ 8 + 15 ≠ 17"},{"id":"b","text":"لا، لأنّ 8² + 17² ≠ 15²"},{"id":"c","text":"لا يمكن التحقّق بدون رسم"},{"id":"d","text":"نعم، لأنّ 8² + 15² = 17²"}]'::jsonb, 'd', 'نحسب: 8² + 15² = 64 + 225 = 289 و17² = 289. بما أنّ 8² + 15² = 17²، فبعكس نظرية فيثاغورس المثلث قائم الزاوية (الزاوية القائمة مقابلة للضلع الأطول 17).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f53e2aa0-860e-5353-bd2f-01e50007afa6', '45ea24b7-4622-54df-a97f-ccfa0ea12ad5', 'في مثلّث ABC قائم الزاوية في B، زاوية A = 45° وAB = 7 cm. ما طول BC؟', '[{"id":"a","text":"7 cm"},{"id":"b","text":"7√2 cm"},{"id":"c","text":"7√3 cm"},{"id":"d","text":"3,5 cm"}]'::jsonb, 'a', 'ظا(A) = BC/AB، إذن ظا(45°) = BC/7. بما أنّ ظا(45°) = 1، فإنّ BC = 7 × 1 = 7 cm. (المثلث قائم وزاوياه الحادّتان متساويتان، فضلعاه القائمان متساويان.)', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d31d49f-8079-543b-b628-3aa0bc442b2d', '45ea24b7-4622-54df-a97f-ccfa0ea12ad5', 'في مثلّث ABC قائم الزاوية في B، زاوية A = 60° والوتر AC = 10 cm. ما طول AB؟', '[{"id":"a","text":"5√3 cm"},{"id":"b","text":"5√2 cm"},{"id":"c","text":"8 cm"},{"id":"d","text":"5 cm"}]'::jsonb, 'd', 'جتا(A) = AB/AC، إذن جتا(60°) = AB/10. بما أنّ جتا(60°) = 1/2، فإنّ AB = 10 × (1/2) = 5 cm.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e82d4cb-c9ef-5832-be9f-84c2f258b709', '45ea24b7-4622-54df-a97f-ccfa0ea12ad5', 'في مثلّث ABC قائم الزاوية في B، AB = 5 cm وBC = 5√3 cm. ما قيمة ظا(A)؟', '[{"id":"a","text":"1/2"},{"id":"b","text":"√3/3"},{"id":"c","text":"√3"},{"id":"d","text":"3"}]'::jsonb, 'c', 'الضلع المقابل للزاوية A هو BC والمجاور هو AB. إذن ظا(A) = BC/AB = 5√3/5 = √3 (وبالتالي A = 60°). الخطأ الشائع: قلب النسبة (AB/BC = √3/3 — وهي ظا(C) لا ظا(A))، أو الخلط مع جتا(A): الوتر AC = √(25 + 75) = 10، فجتا(A) = 5/10 = 1/2.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f895511b-ba4e-5e81-a2a8-6fa474cdf87f', 'fa8e46c4-235e-5b70-a34b-17b1a9a1920b', 'math', '👑 تحدّي النخبة ⭐⭐⭐⭐: المثلث القائم والنسب المثلثية', 4, 300, 60, 'challenge', 'admin', 4)
