INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2d82760c-bbd3-501a-aa2a-0e048ed6c34e', 'f895511b-ba4e-5e81-a2a8-6fa474cdf87f', 'في المثلث ABC القائم في B، AB = 6 cm وBC = 8 cm. ما قيمة جتا(∠BAC)؟', '[{"id":"a","text":"4/5"},{"id":"b","text":"3/5"},{"id":"c","text":"3/4"},{"id":"d","text":"5/6"}]'::jsonb, 'b', 'أولًا نحسب الوتر AC بنظرية فيثاغورس: AC² = AB² + BC² = 36 + 64 = 100، إذن AC = 10 cm. الضلع المجاور للزاوية BAC هو AB والوتر هو AC. إذن: جتا(∠BAC) = AB/AC = 6/10 = 3/5. الخطأ الشائع: اختيار 4/5 وهو جا(∠BAC) = BC/AC (المقابل على الوتر)، أو 3/4 وهي النسبة AB/BC بين الضلعين القائمين — جيب التمام يقسم على الوتر دائمًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a82de751-f769-5298-b7ab-53ad32f2da1f', 'f895511b-ba4e-5e81-a2a8-6fa474cdf87f', 'في مثلث قائم، الزاوية A حادّة وظا(A) = 2/3. ما قيمة جا(A)؟', '[{"id":"a","text":"3√13/13"},{"id":"b","text":"2/3"},{"id":"c","text":"2√13/13"},{"id":"d","text":"√13/2"}]'::jsonb, 'c', 'ظا(A) = الضلع المقابل / الضلع المجاور = 2/3. نضع المقابل = 2k والمجاور = 3k. بنظرية فيثاغورس: الوتر = √((2k)² + (3k)²) = √(4k² + 9k²) = k√13. إذن: جا(A) = المقابل / الوتر = 2k / (k√13) = 2/√13 = 2√13/13. الخيار c هو الصحيح. الخطأ الشائع: اختيار 2/3 مباشرةً وكأنّ مقام ظا(A) وترٌ — مقام الظلّ هو الضلع المجاور، فلا بدّ من حساب الوتر k√13 أوّلًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7f9b6a73-6cbe-59e0-8a08-b40387e5e01d', 'f895511b-ba4e-5e81-a2a8-6fa474cdf87f', 'في المثلث ABC القائم في B، الزاوية A = 30° وAB = 3√3 cm. نرسم الارتفاع BH من B على AC (H على AC). ما طول BH؟', '[{"id":"a","text":"3√3/2 cm"},{"id":"b","text":"3/2 cm"},{"id":"c","text":"3√3 cm"},{"id":"d","text":"√3 cm"}]'::jsonb, 'a', 'في المثلث ABC (قائم في B، الزاوية A = 30°): ظا(30°) = BC/AB → BC = AB × ظا(30°) = 3√3 × (√3/3) = 3 cm. جتا(30°) = AB/AC → AC = AB / جتا(30°) = 3√3 / (√3/2) = 6 cm. مساحة المثلث: S = (1/2) × AB × BC = (1/2) × 3√3 × 3 = 9√3/2 cm². أيضًا: S = (1/2) × AC × BH = (1/2) × 6 × BH = 3 BH. إذن: 3 BH = 9√3/2 → BH = 3√3/2 cm. الخطأ الشائع: الخلط بين الارتفاع BH والضلع القائم BC = 3 cm — الارتفاع النازل على الوتر أقصر من كلا الضلعين القائمين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('18e8e3c2-5e2e-56c6-84f2-07e7e4c5da0b', 'f895511b-ba4e-5e81-a2a8-6fa474cdf87f', 'زاوية حادّة x حيث جتا(x) = √6/3. ما قيمة جا(x) × ظا(x)؟', '[{"id":"a","text":"√2/3"},{"id":"b","text":"√3/6"},{"id":"c","text":"1/3"},{"id":"d","text":"√6/6"}]'::jsonb, 'd', 'جتا(x) = √6/3، إذن جتا²(x) = 6/9 = 2/3. بالعلاقة الأساسية: جا²(x) = 1 − جتا²(x) = 1 − 2/3 = 1/3، فجا(x) = √(1/3) = √3/3. ظا(x) = جا(x)/جتا(x) = (√3/3)/(√6/3) = √3/√6 = √3/(√3×√2) = 1/√2 = √2/2. إذن: جا(x) × ظا(x) = (√3/3) × (√2/2) = √6/6. الخيار d هو الصحيح. الخطأ الشائع: التوقّف عند جا²(x) = 1/3 واستعماله قيمةً لجا(x) — يجب أخذ الجذر (جا(x) = √3/3) قبل حساب الجداء.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae5b69a0-2a15-5b42-940b-5f91220a82e9', 'f895511b-ba4e-5e81-a2a8-6fa474cdf87f', 'مثلث ABC متساوي الساقين حيث AB = AC = 10 cm وBC = 12 cm. نرسم الارتفاع AH من A على BC. نضع جا(∠ABH) = p وجتا(∠ABH) = q. ما قيمة p² + 4q² − 1؟', '[{"id":"a","text":"1"},{"id":"b","text":"27/25"},{"id":"c","text":"52/25"},{"id":"d","text":"0"}]'::jsonb, 'b', 'المثلث متساوي الساقين، فـ H منتصف BC: BH = 6 cm. في المثلث ABH القائم في H: AH² = AB² − BH² = 100 − 36 = 64، إذن AH = 8 cm. جا(∠ABH) = p = AH/AB = 8/10 = 4/5. جتا(∠ABH) = q = BH/AB = 6/10 = 3/5. نحسب: p² = 16/25، 4q² = 4 × 9/25 = 36/25. إذن: p² + 4q² − 1 = 16/25 + 36/25 − 25/25 = 27/25. الخيار b هو الصحيح. الخطأ الشائع: تطبيق العلاقة الأساسية على p² + 4q² واختيار 0 — العلاقة جا² + جتا² = 1 تنطبق على p² + q² فقط، والمقدار المطلوب يساوي (p² + q² − 1) + 3q² = 3q² = 27/25.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7073588-2022-5ac9-affd-62ce1a97fa50', 'f895511b-ba4e-5e81-a2a8-6fa474cdf87f', 'في مثلث قائم MNP (قائم في N)، ظا(M) = √5/2. ما قيمة جا²(M) − جتا²(M)؟', '[{"id":"a","text":"5/9"},{"id":"b","text":"1/3"},{"id":"c","text":"1/9"},{"id":"d","text":"√5/9"}]'::jsonb, 'c', 'ظا(M) = √5/2 → المقابل = √5k والمجاور = 2k. الوتر = √(5k² + 4k²) = √(9k²) = 3k. جا(M) = √5k/(3k) = √5/3، فجا²(M) = 5/9. جتا(M) = 2k/(3k) = 2/3، فجتا²(M) = 4/9. إذن: جا²(M) − جتا²(M) = 5/9 − 4/9 = 1/9. الخيار c هو الصحيح. تحقّق: جا²(M) + جتا²(M) = 5/9 + 4/9 = 9/9 = 1 ✓ الخطأ الشائع: التوقّف عند جا²(M) = 5/9 واعتباره الجواب دون طرح جتا²(M) = 4/9.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('8fcc50fd-f426-5868-b797-35a0bdc92829', 'fa8e46c4-235e-5b70-a34b-17b1a9a1920b', 'math', '📝 تدريب ⭐⭐⭐: فيثاغورس والنسب المثلثية (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
