  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dfde8594-7f9d-5279-9ae7-07c51d52d0a6', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في المثلث ABC القائم في B، AB = 8 cm وBC = 6 cm. ما طول الوتر AC؟', '[{"id":"a","text":"√14 cm"},{"id":"b","text":"100 cm"},{"id":"c","text":"10 cm"},{"id":"d","text":"14 cm"}]'::jsonb, 'c', 'بنظرية فيثاغورس: AC² = AB² + BC² = 64 + 36 = 100، إذن AC = √100 = 10 cm. هذه الثلاثية المشهورة (6 ; 8 ; 10) من مضاعفات (3 ; 4 ; 5).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9889a97c-458b-557a-95f0-512fc6ded20b', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في المثلث ABC القائم في B، AC = 13 cm وAB = 5 cm. ما طول BC؟', '[{"id":"a","text":"8 cm"},{"id":"b","text":"12 cm"},{"id":"c","text":"18 cm"},{"id":"d","text":"√194 cm"}]'::jsonb, 'b', 'AC هو الوتر. بفيثاغورس: AC² = AB² + BC² → 13² = 5² + BC² → 169 = 25 + BC² → BC² = 144 → BC = 12 cm. الثلاثية (5 ; 12 ; 13).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c986e021-1f47-5951-a459-a127caba0567', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'مثلث أضلاعه 7 cm و9 cm و11 cm. هل هو قائم الزاوية؟', '[{"id":"a","text":"نعم، لأنّ 7 + 9 > 11"},{"id":"b","text":"نعم، لأنّ 7² + 9² ≈ 11² والفرق ضئيل"},{"id":"c","text":"لا، لأنّ 7 + 9 ≠ 11"},{"id":"d","text":"لا، لأنّ 7² + 9² ≠ 11²"}]'::jsonb, 'd', 'نحسب: 7² + 9² = 49 + 81 = 130 و11² = 121. بما أنّ 130 ≠ 121، فالمثلث غير قائم الزاوية بعكس فيثاغورس. الخطأ الشائع: الاكتفاء بالتقارب (130 «قريب» من 121) — عكس فيثاغورس يتطلّب تساويًا تامًّا. أمّا 7 + 9 > 11 فهي متراجحة المثلث: تضمن وجود المثلث لا قائمته.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68dd2292-5551-5e45-8852-262481a36870', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في مثلث قائم، الزاوية الحادّة A تحقّق جا(A) = 1/2. ما قيمة A؟', '[{"id":"a","text":"30°"},{"id":"b","text":"45°"},{"id":"c","text":"60°"},{"id":"d","text":"90°"}]'::jsonb, 'a', 'من جدول القيم المشهورة: جا(30°) = 1/2. إذن A = 30°. تذكّر: جا(45°) = √2/2 وجا(60°) = √3/2.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ea0a760-4e4a-5e7d-b9d5-17a7ac759091', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في المثلث ABC القائم في B، الزاوية C = 60° والوتر AC = 14 cm. ما طول الضلع BC (المجاور للزاوية C)؟', '[{"id":"a","text":"7 cm"},{"id":"b","text":"7√2 cm"},{"id":"c","text":"7√3 cm"},{"id":"d","text":"28 cm"}]'::jsonb, 'a', 'BC هو الضلع المجاور للزاوية C وAC هو الوتر: جتا(C) = BC/AC. إذن جتا(60°) = BC/14، أي 1/2 = BC/14، فينتج BC = 14 × 1/2 = 7 cm. الخطأ الشائع: استعمال جا(60°) = √3/2 (يعطي 7√3 وهو طول AB المقابل)، أو القسمة على 1/2 بدل الضرب (يعطي 28 وهو أطول من الوتر — مستحيل).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5ed6a19c-2f76-549e-829a-3e952ee94469', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في مثلث قائم، الزاوية الحادّة x تحقّق جتا(x) = √2/2. ما قيمة جا(x) ؟', '[{"id":"a","text":"1"},{"id":"b","text":"√2/2"},{"id":"c","text":"1/2"},{"id":"d","text":"√3/2"}]'::jsonb, 'b', 'جتا(x) = √2/2 يعني x = 45°. إذن جا(45°) = √2/2. التحقّق بالعلاقة الأساسية: جا²(x) + جتا²(x) = 1/2 + 1/2 = 1 ✓. الخطأ الشائع: الظنّ أنّ جا(x) يجب أن يخالف جتا(x) فاختيار 1/2 — عند 45° (وعندها فقط) يتساوى الجيب وجيب التمام.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('18bf832b-a270-582f-b1ef-0a2905197003', 'fa8e46c4-235e-5b70-a34b-17b1a9a1920b', 'math', '👑 تحدّي المناظرة ⭐⭐⭐⭐: المثلّث القائم والنسب المثلّثية في وضعيات مركّبة', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3dba3fa1-3ce1-5ad4-9c21-ab58a3120e80', '18bf832b-a270-582f-b1ef-0a2905197003', 'المثلّث ABC قائم الزاوية في A، مع AB = 5 cm وAC = 12 cm. ما قيمة جتا(∠ABC)؟', '[{"id":"a","text":"12/13"},{"id":"b","text":"5/13"},{"id":"c","text":"5/12"},{"id":"d","text":"12/5"}]'::jsonb, 'b', 'أوّلًا نحسب الوتر بنظرية بيثاغورس: BC² = AB² + AC² = 25 + 144 = 169، إذن BC = 13 cm. بالنسبة للزاوية B في المثلّث القائم في A: الضلع المجاور هو AB والوتر هو BC، إذن جتا(B) = المجاور/الوتر = AB/BC = 5/13. ✓ (5-12-13 ثلاثي فيثاغوري). الخطأ الشائع: أخذ الضلع المقابل AC بدل المجاور (12/13، وهو جا(B))؛ أو حساب ظا = AB/AC = 5/12؛ أو قلب النسبة (12/5).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('990baabb-e96c-5ec5-a5c8-0e753d3350f7', '18bf832b-a270-582f-b1ef-0a2905197003', 'في مثلّث قائم في A بزاوية B، كتب تلميذ: «جتا(B) = الضلع المقابل / الوتر». هل من خطأ، وما الصواب؟', '[{"id":"a","text":"نعم، جتا = المجاور/الوتر (لا المقابل)"},{"id":"b","text":"نعم، جتا = المقابل/المجاور"},{"id":"c","text":"نعم، جتا = الوتر/المجاور"},{"id":"d","text":"لا خطأ، التعريف صحيح"}]'::jsonb, 'a', 'جيب التمام جتا = الضلع المجاور / الوتر. أمّا المقابل/الوتر فهو الجيب جا. (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط في ثلاثيّة النسب — جتا للمجاور، جا للمقابل، ظا = المقابل/المجاور.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eabd491f-c90f-554f-a3d5-7eadecc64e90', '18bf832b-a270-582f-b1ef-0a2905197003', 'زاوية حادّة x حيث جتا(x) = 3/5. ما قيمة ظا(x)؟', '[{"id":"a","text":"3/4"},{"id":"b","text":"2/3"},{"id":"c","text":"4/3"},{"id":"d","text":"5/4"}]'::jsonb, 'c', 'نستعمل جا²(x) + جتا²(x) = 1: جا²(x) = 1 − (3/5)² = 1 − 9/25 = 16/25، وبما أنّ x حادّة فـ جا(x) = 4/5 (موجب). ثمّ ظا(x) = جا(x)/جتا(x) = (4/5)/(3/5) = 4/3. ✓ (3-4-5). الخطأ الشائع: قلب النسبة ظا = جتا/جا = 3/4؛ أو حساب جا = 1 − 3/5 = 2/5 (الخلط بين المتطابقة الفيثاغورية والطرح المباشر) فيخرج 2/3.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9780f599-e158-53dd-90d9-3ec6760e0e61', '18bf832b-a270-582f-b1ef-0a2905197003', 'سُلّم طوله 4 m مسنَد إلى حائط شاقوليّ ويصنع زاوية 45° مع الأرض الأفقيّة. إلى أيّ ارتفاع يلامس الحائط؟ (جا 45° = √2/2)', '[{"id":"a","text":"4√2 m"},{"id":"b","text":"2√2 m"},{"id":"c","text":"2 m"},{"id":"d","text":"√2 m"}]'::jsonb, 'b', 'الارتفاع هو الضلع المقابل للزاوية 45°، والوتر هو السُّلّم (4 m). إذن الارتفاع = 4 × جا 45° = 4 × (√2/2) = 2√2 m ≈ 2,83 m. ✓ الخطأ الشائع: الضرب في √2 بدل √2/2 (فيخرج 4√2)؛ أو اعتبار جا 45° = 1/2 (فيخرج 2 m) — وهي قيمة جا 30° لا جا 45°.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('420a8a09-9705-5a9e-927e-fe25e0bff2b9', '18bf832b-a270-582f-b1ef-0a2905197003', 'المثلّث ABC قائم في A، مع ∠ABC = 60° وAB = 4 cm. ما طول AC؟ (ظا 60° = √3)', '[{"id":"a","text":"4√3 cm"},{"id":"b","text":"8 cm"},{"id":"c","text":"4/√3 cm"},{"id":"d","text":"2√3 cm"}]'::jsonb, 'a', 'بالنسبة للزاوية B (= 60°) في المثلّث القائم في A: AC هو الضلع المقابل وAB هو المجاور، وظا(B) = المقابل/المجاور = AC/AB. إذن AC = AB × ظا 60° = 4 × √3 = 4√3 cm. ✓ (تحقّق: الوتر BC = AB/جتا60° = 4/(1/2) = 8، و√(BC² − AB²) = √(64 − 16) = √48 = 4√3). الخطأ الشائع: إعطاء طول الوتر BC = 8 بدل AC؛ أو استعمال ظا 30° = 1/√3 بدل ظا 60°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('287ba799-1ba1-526d-9a87-431429457fc8', '18bf832b-a270-582f-b1ef-0a2905197003', 'المثلّث ABC قائم في A، مع جا(∠ABC) = 0,6 وBC = 20 cm. ما طول AB؟', '[{"id":"a","text":"12 cm"},{"id":"b","text":"16 cm"},{"id":"c","text":"8 cm"},{"id":"d","text":"10 cm"}]'::jsonb, 'b', 'جا(B) = المقابل/الوتر = AC/BC، إذن AC = 0,6 × 20 = 12 cm. ثمّ AB بنظرية بيثاغورس: AB = √(BC² − AC²) = √(400 − 144) = √256 = 16 cm. (أو جتا(B) = √(1 − 0,6²) = 0,8، وAB = 0,8 × 20 = 16.) ✓ (12-16-20 = 4×(3-4-5)). الخطأ الشائع: إعطاء AC = 12 على أنّه AB (خلط الضلعين)؛ أو طرح الأطوال 20 − 12 = 8 بدل تطبيق بيثاغورس.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b772b8d9-c085-5955-8cc6-af66b54cf2c8', '069523c8-c228-5326-bbc1-31ad25257541', 'math', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30ce1ea7-3aef-513b-85ac-192597814cff', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'ما الفرق الجوهري بين الزاوية المركزية والزاوية المحيطية في الدائرة؟', '[{"id":"a","text":"الزاوية المركزية رأسها على الدائرة؛ والمحيطية رأسها في المركز"},{"id":"b","text":"الزاوية المركزية رأسها مركز الدائرة وضلعاها نصفا قطرين؛ والمحيطية رأسها نقطة على الدائرة وضلعاها وتران"},{"id":"c","text":"لا فرق؛ كلتاهما تساوي قيس القوس ذاته"},{"id":"d","text":"الزاوية المحيطية دائمًا أكبر من المركزية لنفس القوس"}]'::jsonb, 'b', 'الزاوية المركزية: رأسها المركز O وضلعاها نصفا قطرَين. الزاوية المحيطية: رأسها نقطة على الدائرة وضلعاها وتران. هذا هو التمييز التعريفي بينهما.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7852d3bf-c345-5dbf-8cbe-3ebbb25e8a3b', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'ما العلاقة الرياضية بين الزاوية المحيطية والزاوية المركزية المقابلتَين لنفس القوس؟', '[{"id":"a","text":"الزاوية المحيطية = الزاوية المركزية"},{"id":"b","text":"الزاوية المحيطية = 2 × الزاوية المركزية"},{"id":"c","text":"الزاوية المحيطية = نصف الزاوية المركزية"},{"id":"d","text":"الزاوية المحيطية + الزاوية المركزية = 180°"}]'::jsonb, 'c', 'النظرية الكبرى: الزاوية المحيطية = (1/2) × الزاوية المركزية المقابلة لنفس القوس. وبالتالي الزاوية المركزية = 2 × الزاوية المحيطية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63768b0e-3a26-5eea-ae59-a034ac1fc46f', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'في دائرة مركزها O، إذا كانت الزاوية المركزية AOB = 140°، فما قيمة الزاوية المحيطية ACB (حيث C على القوس الكبير)؟', '[{"id":"a","text":"280°"},{"id":"b","text":"140°"},{"id":"c","text":"70°"},{"id":"d","text":"40°"}]'::jsonb, 'c', 'الزاوية المحيطية = نصف الزاوية المركزية لنفس القوس. إذن ACB = 140° ÷ 2 = 70°.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b3d3699-c897-5da7-9806-c38b02fac914', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'إذا كانت [AC] قطرًا في دائرة وB نقطة على الدائرة غير A وC، فما قيمة الزاوية ABC وما مبرّرها؟', '[{"id":"a","text":"60°؛ لأنّ المثلّث ABC متساوي الأضلاع"},{"id":"b","text":"45°؛ لأنّ B منتصف القوس"},{"id":"c","text":"180°؛ لأنّ A وB وC على خطّ واحد"},{"id":"d","text":"90°؛ لأنّ الزاوية المحيطية المحصورة في نصف دائرة قائمة دائمًا"}]'::jsonb, 'd', 'القطر AC يقابل زاوية مركزية = 180°. إذن الزاوية المحيطية ABC = 180° ÷ 2 = 90°. «الزاوية المحيطية المحصورة في نصف دائرة قائمة» — جملة يجب حفظها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b57e4cb3-047d-5c19-98c4-e8a04074c9ae', 'b772b8d9-c085-5955-8cc6-af66b54cf2c8', 'إذا كانت C وD نقطتَين على دائرة من نفس الجهة بالنسبة للوتر [AB]، فما العلاقة بين الزاويتَين ACB وADB؟', '[{"id":"a","text":"ACB + ADB = 360°"},{"id":"b","text":"ACB = ADB (الزاويتان متقايستان)"},{"id":"c","text":"ACB = 2 × ADB"},{"id":"d","text":"لا علاقة تربطهما"}]'::jsonb, 'b', 'الزوايا المحيطية التي تحصر نفس القوس وتنتمي إلى نفس الجهة تكون متقايسة. كلتاهما تساوي نصف الزاوية المركزية المقابلة لذلك القوس.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('93dfdc12-2b72-5865-99a2-cbfa62c0ded0', '069523c8-c228-5326-bbc1-31ad25257541', 'math', '⭐⭐ تمرين: الزاوية المركزية والزاوية المحيطية', 2, 75, 15, 'practice', 'admin', 1)
