INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fb18edd-29f6-5550-9dee-b73269be157c', '873efa4f-bd3f-5abb-be22-b8b08bd96d7f', 'في دائرة مركزها O، الزاوية المركزية AOB = 130°، وC نقطة على القوس الكبير. ما قيمة الزاوية ACB؟', '[{"id":"a","text":"65°"},{"id":"b","text":"130°"},{"id":"c","text":"260°"},{"id":"d","text":"115°"}]'::jsonb, 'a', 'الزاوية المحيطية = نصف الزاوية المركزية. الزاوية ACB = 130° ÷ 2 = 65°.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae3c1d6a-9a72-5eab-a89c-c82382f6b662', '873efa4f-bd3f-5abb-be22-b8b08bd96d7f', 'في دائرة مركزها O، C وD وE ثلاث نقاط على الدائرة. الزاوية المحيطية DCE = 48°. ما قيمة الزاوية المركزية DOE؟', '[{"id":"a","text":"24°"},{"id":"b","text":"48°"},{"id":"c","text":"96°"},{"id":"d","text":"144°"}]'::jsonb, 'c', 'الزاوية المركزية = ضعف الزاوية المحيطية المقابلة لنفس القوس. الزاوية DOE = 2 × 48° = 96°.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7c8161d-6c86-5f6f-9e2c-da87f6a61832', '873efa4f-bd3f-5abb-be22-b8b08bd96d7f', 'في دائرة مركزها O، [MN] قطر وP نقطة على الدائرة. إذا كانت الزاوية PMN = 28°، ما قيمة الزاوية MNP؟', '[{"id":"a","text":"28°"},{"id":"b","text":"62°"},{"id":"c","text":"90°"},{"id":"d","text":"152°"}]'::jsonb, 'b', 'بما أنّ [MN] قطر، فالزاوية MPN = 90° (زاوية في نصف دائرة). في المثلث MPN: الزاوية MNP = 180° − 90° − 28° = 62°.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f8279b5-8479-5070-9d46-ff30e896b74d', '873efa4f-bd3f-5abb-be22-b8b08bd96d7f', 'في دائرة، الزاوية المحيطية ACB = 38°. وD نقطة على القوس الكبير (من نفس الجهة). ما مجموع الزاويتين ACB وADB؟', '[{"id":"a","text":"76°"},{"id":"b","text":"180°"},{"id":"c","text":"38°"},{"id":"d","text":"90°"}]'::jsonb, 'a', 'الزاوية ADB = الزاوية ACB = 38° (زاويتان محيطيتان تحصران نفس القوس من الجهة نفسها). إذن المجموع = 38° + 38° = 76°.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('20dafbd3-0c09-52ce-9a14-7c00cc3af209', '873efa4f-bd3f-5abb-be22-b8b08bd96d7f', 'في دائرة، C وD نقطتان على جهتَين مختلفتَين من الوتر [AB]. الزاوية ACB = 70° حيث C على القوس الكبير. ما قيمة الزاوية ADB؟', '[{"id":"a","text":"110°"},{"id":"b","text":"70°"},{"id":"c","text":"140°"},{"id":"d","text":"220°"}]'::jsonb, 'a', 'الخطوة 1: القوس الصغير AB = 2 × 70° = 140°، فالقوس الكبير = 360° − 140° = 220°. الخطوة 2: الزاوية ADB تحصر القوس الكبير (لأنّ D على القوس الصغير)، إذن ADB = 220° ÷ 2 = 110°. الخطأ الشائع: اختيار 70° بدعوى تساوي الزوايا المحيطية — التساوي يصحّ فقط عندما تكون النقطتان في الجهة نفسها من الوتر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba79d051-2cff-575e-bfc7-acfca8574f01', '873efa4f-bd3f-5abb-be22-b8b08bd96d7f', 'في دائرة، الزاوية المحيطية ACB = 63°. ما قيس القوس الصغير AB الذي تحصره هذه الزاوية؟', '[{"id":"a","text":"63°"},{"id":"b","text":"126°"},{"id":"c","text":"31,5°"},{"id":"d","text":"297°"}]'::jsonb, 'b', 'الزاوية المركزية المقابلة = 2 × الزاوية المحيطية = 2 × 63° = 126°. وقيس الزاوية المركزية يساوي قيس قوسها، إذن القوس الصغير AB = 126°. الخطأ الشائع: قسمة 63° على 2 فاختيار 31,5° — القوس ضعف الزاوية المحيطية لا نصفها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

