INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('796d0d63-c384-51f3-8d91-4122e08a62f4', '1723a195-8a7d-58a9-aca8-4e9271a11138', 'في دائرة مركزها O، الزاوية المركزية AOB = 120°. النقطة C على الدائرة في الجهة المقابلة للقوس الصغير AB. ما قيمة الزاوية المحيطية ACB؟', '[{"id":"a","text":"120°"},{"id":"b","text":"60°"},{"id":"c","text":"240°"},{"id":"d","text":"30°"}]'::jsonb, 'b', 'الزاوية المحيطية = نصف الزاوية المركزية المقابلة لنفس القوس. إذن الزاوية ACB = 120° ÷ 2 = 60°.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f87fb1de-6040-55a9-884b-8166d6f6a0ff', '1723a195-8a7d-58a9-aca8-4e9271a11138', 'في دائرة مركزها O، الزاوية المحيطية MKN = 41° تحصر القوس MN. ما قيمة الزاوية المركزية MON؟', '[{"id":"a","text":"82°"},{"id":"b","text":"41°"},{"id":"c","text":"20,5°"},{"id":"d","text":"139°"}]'::jsonb, 'a', 'الزاوية المركزية = ضعف الزاوية المحيطية المقابلة لنفس القوس. إذن الزاوية MON = 2 × 41° = 82°.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b7fa255-8ccf-594f-a969-4b1a864e2901', '1723a195-8a7d-58a9-aca8-4e9271a11138', 'في دائرة مركزها O، [AB] قطر، والنقطة C على الدائرة بحيث CA = CB. ما قيمة الزاوية CAB؟', '[{"id":"a","text":"22,5°"},{"id":"b","text":"30°"},{"id":"c","text":"45°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'بما أنّ [AB] قطر، فالزاوية ACB = 90° (زاوية محيطية محصورة في نصف دائرة). والمثلث ACB متساوي الساقين (CA = CB)، فزاويتا القاعدة متقايستان: CAB = CBA = (180° − 90°) ÷ 2 = 45°. الخطأ الشائع: اختيار 90° وهي زاوية الرأس C لا زاوية القاعدة، أو قسمة 45° مرّة أخرى فاختيار 22,5°.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a81341fd-e00e-5771-8372-84d54917f7a5', '1723a195-8a7d-58a9-aca8-4e9271a11138', 'في دائرة مركزها O، الزاوية المركزية AOB = 140°. ما قيس القوس الكبير AB؟', '[{"id":"a","text":"70°"},{"id":"b","text":"140°"},{"id":"c","text":"180°"},{"id":"d","text":"220°"}]'::jsonb, 'd', 'قيس القوس الصغير AB يساوي قيس زاويته المركزية، أي 140°. القوس الكبير = 360° − 140° = 220°. الخطأ الشائع: اختيار 140° وهو قيس القوس الصغير لا الكبير، أو افتراض أنّ القوس الكبير نصف دائرة (180°).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d3e65af-6ac2-573e-806e-333c73ba31ee', '1723a195-8a7d-58a9-aca8-4e9271a11138', 'في دائرة مركزها O، الزاوية المركزية AOB = 150°. النقطة C على القوس الكبير (الجهة المقابلة). ما قيمة الزاوية ACB؟', '[{"id":"a","text":"300°"},{"id":"b","text":"75°"},{"id":"c","text":"30°"},{"id":"d","text":"150°"}]'::jsonb, 'b', 'الزاوية المحيطية = نصف الزاوية المركزية المقابلة لنفس القوس. إذن الزاوية ACB = 150° ÷ 2 = 75°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bef76b66-7e0a-534f-a565-358ea8541c18', '1723a195-8a7d-58a9-aca8-4e9271a11138', 'في دائرة مركزها O، [AB] قطر، والنقطة C على الدائرة. إذا كانت الزاوية CAB = 55°، ما قيمة الزاوية ABC؟', '[{"id":"a","text":"35°"},{"id":"b","text":"55°"},{"id":"c","text":"90°"},{"id":"d","text":"125°"}]'::jsonb, 'a', 'بما أنّ [AB] قطر، فالزاوية ACB = 90° (زاوية محيطية محصورة في نصف دائرة). في المثلث ABC: الزاوية ABC = 180° − 90° − 55° = 35°.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('84749d30-447f-5dfa-8689-137294ddc1c7', '069523c8-c228-5326-bbc1-31ad25257541', 'math', '👑 تحدّي النخبة ⭐⭐⭐⭐: الزوايا في الدائرة — مسائل التفوّق', 4, 300, 60, 'challenge', 'admin', 4)
