INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('54d41e06-4afa-5d8d-9fa3-9a7f31fc56d2', '84749d30-447f-5dfa-8689-137294ddc1c7', 'رباعيّ ABCD مرسوم في دائرة مركزها O. قيس القوس AB = 100°، قيس القوس BC = 80°، قيس القوس CD = 70°. ما قيمة الزاوية المحيطية DAB؟', '[{"id":"a","text":"65°"},{"id":"b","text":"80°"},{"id":"c","text":"75°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'مجموع الأقواس الأربعة = 360°، إذن قيس القوس DA = 360° − 100° − 80° − 70° = 110°. الزاوية المحيطية DAB ترى القوس BCD (الذي لا يحتوي A)، وقيسه = قوس BC + قوس CD = 80° + 70° = 150°. وبتطبيق النظرية الكبرى: الزاوية DAB = 150° ÷ 2 = 75°.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cec03466-a650-573e-815a-a3b714907a93', '84749d30-447f-5dfa-8689-137294ddc1c7', 'في دائرة مركزها O، [BC] قطر وA نقطة على الدائرة غير B وC. إذا كانت الزاوية ABC = 54°، ما قيمة الزاوية المركزية AOC؟', '[{"id":"a","text":"108°"},{"id":"b","text":"54°"},{"id":"c","text":"36°"},{"id":"d","text":"72°"}]'::jsonb, 'a', 'الزاوية ABC محيطية ترى القوس AC الذي لا يحتوي B. بالنظرية الكبرى: قيس القوس AC = 2 × الزاوية ABC = 2 × 54° = 108°. والزاوية المركزية AOC تساوي قيس قوسها المقابل، إذن الزاوية AOC = 108°. (تحقّق: [BC] قطر → قوس BAC = 180° → قوس BA = 180° − 108° = 72°، والزاوية ACB المحيطية = 72°/2 = 36°، وبالتحقّق في المثلث ABC: 90° + 54° + 36° = 180° ✓).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5cb34a95-184f-55db-9214-bed2bda40e2f', '84749d30-447f-5dfa-8689-137294ddc1c7', 'في دائرة مركزها O، النقاط A وB وC وD على الدائرة. قيس القوس الصغير AB = 80° وقيس القوس BC = 110°، والنقطة D على القوس الذي لا يحتوي A ولا B ولا C. ما قيمة الزاوية ADC؟', '[{"id":"a","text":"85°"},{"id":"b","text":"100°"},{"id":"c","text":"190°"},{"id":"d","text":"95°"}]'::jsonb, 'd', 'الزاوية المحيطية ADC ترى القوس ABC الذي لا يحتوي D. قيس هذا القوس = قوس AB + قوس BC = 80° + 110° = 190°. بتطبيق النظرية الكبرى: الزاوية ADC = 190° ÷ 2 = 95°. (يجوز أن تتجاوز الزاوية المحيطية 90° عندما يكون القوس الذي تراه أكبر من نصف الدائرة).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f90ef0b-5711-529c-bf26-011b4f1d67a5', '84749d30-447f-5dfa-8689-137294ddc1c7', 'خماسيّ منتظم ABCDE مرسوم في دائرة. ما قيمة الزاوية المحيطية ACE؟', '[{"id":"a","text":"72°"},{"id":"b","text":"36°"},{"id":"c","text":"54°"},{"id":"d","text":"108°"}]'::jsonb, 'b', 'الخماسيّ المنتظم يقسم الدائرة إلى خمسة أقواس متساوية، قيس كلّ منها = 360° ÷ 5 = 72°. الزاوية المحيطية ACE ترى القوس AE (الذي لا يحتوي C)، وهو قوس مفرد قيسه 72°. بالنظرية الكبرى: الزاوية ACE = 72° ÷ 2 = 36°.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5631b3d0-233c-5ab2-9d6e-6811d645dcce', '84749d30-447f-5dfa-8689-137294ddc1c7', 'في دائرة مركزها O، [AB] قطر، والنقطتان C وD على نفس القوس (نفس الجهة بالنسبة لـ AB). الزاوية BAC = 28° والزاوية CAD = 20°. ما قيمة الزاوية DBA؟', '[{"id":"a","text":"42°"},{"id":"b","text":"48°"},{"id":"c","text":"56°"},{"id":"d","text":"24°"}]'::jsonb, 'a', 'الخطوة 1: الزاوية BAC محيطية ترى القوس BC (بين B وC لا يحتوي A). الزاوية BAD = الزاوية BAC + الزاوية CAD = 28° + 20° = 48°، وهي محيطية ترى القوس BD، إذن قيس القوس BD = 2 × 48° = 96°. الخطوة 2: [AB] قطر، إذن القوس ADB (من A إلى B مارًّا بـ D) قيسه 180°. القوس DA (من D إلى A لا يحتوي B) = 180° − قوس BD = 180° − 96° = 84°. الخطوة 3: الزاوية DBA محيطية ترى القوس DA (لا يحتوي B)، إذن الزاوية DBA = 84° ÷ 2 = 42°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0400787a-1bf1-595b-b7fe-a09b8da2d322', '84749d30-447f-5dfa-8689-137294ddc1c7', 'خماسيّ منتظم ABCDE مرسوم في دائرة. قطريّا AC وBD يتقاطعان عند النقطة M داخل الدائرة. ما قيمة الزاوية AMB؟', '[{"id":"a","text":"36°"},{"id":"b","text":"108°"},{"id":"c","text":"72°"},{"id":"d","text":"54°"}]'::jsonb, 'c', 'قيس كلّ قوس من أقواس الخماسيّ المنتظم = 72°. في المثلث ABM: الزاوية MAB = الزاوية CAB (محيطية ترى القوس BC = 72°) = 36°. الزاوية MBA = الزاوية DBA (محيطية ترى القوس DA = قوسان = 2 × 72° = 144°) = 72°. إذن الزاوية AMB = 180° − 36° − 72° = 72°. (تحقّق بديل: الزاوية في M = مجموع زاويتين محيطيتين حوله = 36° + 36° = 72° — لكنّ الطريقة الصحيحة هي استعمال مجموع زوايا المثلث ABM كما تبيّن).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

