INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('347c6beb-2894-5fa6-9855-1658fff2add1', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة مركزها O، الزاوية المركزية AOB = 110°، وC نقطة على القوس الكبير. ما قيمة الزاوية المحيطية ACB؟', '[{"id":"a","text":"55°"},{"id":"b","text":"70°"},{"id":"c","text":"110°"},{"id":"d","text":"220°"}]'::jsonb, 'a', 'الزاوية المحيطية = نصف الزاوية المركزية المقابلة لنفس القوس. ACB = 110° ÷ 2 = 55°.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
