INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac6fd8cf-2009-5ca5-a70d-28bcebcf296b', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة مركزها O، الزاوية المركزية AOB = 60° والزاوية المركزية BOC = 40° حيث B بين A وC على الدائرة، وD نقطة على القوس الكبير AC. ما قيمة الزاوية ADC؟', '[{"id":"a","text":"25°"},{"id":"b","text":"30°"},{"id":"c","text":"50°"},{"id":"d","text":"100°"}]'::jsonb, 'c', 'الزاوية المركزية AOC = AOB + BOC = 60° + 40° = 100°. الزاوية المحيطية ADC = نصف الزاوية المركزية = 100° ÷ 2 = 50°. اختيار 100° يعني نسيان القسمة على 2، واختيار 30° يعني قسمة زاوية واحدة فقط.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('253fac3f-1b6c-57d8-83fc-3ea1177d0df2', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة مركزها O، [AB] قطر وC نقطة على الدائرة بحيث الزاوية ABC = 30°. ما قيمة الزاوية المركزية AOC؟', '[{"id":"a","text":"30°"},{"id":"b","text":"60°"},{"id":"c","text":"90°"},{"id":"d","text":"120°"}]'::jsonb, 'b', 'الزاوية المحيطية ABC تحصر القوس AC، والزاوية المركزية AOC تحصر القوس نفسه. إذن AOC = 2 × ABC = 2 × 30° = 60°. كون [AB] قطرًا يعطي ACB = 90° لكنّه لا يغيّر القاعدة. الخطأ الشائع: اختيار 30° بنسيان المضاعفة، أو 90° بالخلط مع زاوية نصف الدائرة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b903fee-9e5b-5af1-a92d-255687213b58', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة، الزاويتان المحيطيتان ACB وADB تحصران القوس الصغير AB نفسه، وقيس كلّ منهما 31°. ما قيس القوس الصغير AB؟', '[{"id":"a","text":"31°"},{"id":"b","text":"62°"},{"id":"c","text":"124°"},{"id":"d","text":"298°"}]'::jsonb, 'b', 'الزاوية المركزية المقابلة للقوس AB = ضعف الزاوية المحيطية = 2 × 31° = 62°، وقيس القوس يساوي قيس زاويته المركزية. إذن القوس الصغير AB = 62°. اختيار 31° يخلط بين قيس الزاوية المحيطية وقيس القوس.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
