  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a26d1a7-cbef-59b4-9541-8d3f57bb2cfa', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة مركزها O، الزاوية المركزية AOB = 120°. ما قيس القوس الصغير AB؟', '[{"id":"a","text":"30°"},{"id":"b","text":"60°"},{"id":"c","text":"120°"},{"id":"d","text":"240°"}]'::jsonb, 'c', 'قيس الزاوية المركزية يساوي قيس قوسها المقابل. إذن قيس القوس الصغير AB = 120°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
