INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4b6092af-fe1c-59f9-92fa-22d6183c0df4', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة، الزاوية المحيطية ACB = 54°. ما قيس القوس الكبير AB (الذي لا يحوي C)؟', '[{"id":"a","text":"108°"},{"id":"b","text":"126°"},{"id":"c","text":"252°"},{"id":"d","text":"306°"}]'::jsonb, 'c', 'القوس الصغير AB المقابل للزاوية المحيطية = 2 × 54° = 108°. القوس الكبير = 360° − 108° = 252°. الخطأ الشائع: اختيار 108° (القوس الصغير) بالخلط بين القوسين، أو نسيان الطرح من 360°.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('c454f3ce-b206-527f-8ceb-4894b5ed3dc8', '2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
