  ('d5ed3185-e602-5baa-a49f-a68b1191ac7f', '2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', '⭐⭐ تمرين: الأشعّة وعلاقة شال', 2, 75, 15, 'practice', 'admin', 1)
