INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4642479-04db-524b-8493-07275599ab8a', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ما ناتج مجموع الشعاعين AB + BC وفق علاقة شال؟', '[{"id":"a","text":"AC"},{"id":"b","text":"CA"},{"id":"c","text":"BA"},{"id":"d","text":"الشعاع الصفري"}]'::jsonb, 'a', 'علاقة شال تنصّ على: AB + BC = AC. نتتبّع الحروف: نبدأ من A وننتهي في C مرورًا بـ B.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9c8d407-2396-539e-864e-40d48e430134', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ما ناتج مجموع الشعاعين AB + BA؟', '[{"id":"a","text":"2AB"},{"id":"b","text":"BA"},{"id":"c","text":"الشعاع الصفري"},{"id":"d","text":"AB"}]'::jsonb, 'c', 'بتطبيق شال: AB + BA = AA = الشعاع الصفري. فالشعاع BA هو معاكس الشعاع AB، ومجموع شعاع ومعاكسه هو الشعاع الصفري — لا AB ولا BA.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d31b6e9-d3c9-5b12-8a64-9b080894d622', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ABCD متوازي أضلاع. أيّ من المساواات الشعاعية التالية صحيحة؟', '[{"id":"a","text":"AB = CD"},{"id":"b","text":"AB = DC"},{"id":"c","text":"AB = CB"},{"id":"d","text":"AD = CB"}]'::jsonb, 'b', 'في متوازي الأضلاع ABCD: الضلعان AB وDC متوازيان ومتساويان في الطول وبالمنحى نفسه، إذن AB = DC. انتبه: الشعاع CD معاكس المنحى للشعاع DC.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fa1aa792-ea33-5d2e-b34f-db59004f7bef', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'M نقطة في المستوي. صورتها بالانسحاب ذي الشعاع AB هي النقطة M'' التي تحقّق:', '[{"id":"a","text":"M''M = AB (شعاعان)"},{"id":"b","text":"MM'' = AB (شعاعان)"},{"id":"c","text":"MM'' = 0 (طول)"},{"id":"d","text":"M'' = M"}]'::jsonb, 'b', 'الانسحاب ذو الشعاع AB ينقل كلّ نقطة M إلى M'' بحيث يكون الشعاع MM'' مساويًا للشعاع AB. المنشأ هو M والطرف هو M''.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('59416d62-ddd9-569b-93cf-947e49de5bbb', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ما ناتج مجموع الأشعّة AB + BC + CD؟', '[{"id":"a","text":"BD"},{"id":"b","text":"AC"},{"id":"c","text":"AD"},{"id":"d","text":"الشعاع الصفري"}]'::jsonb, 'c', 'نطبّق شال تدريجيًا: AB + BC = AC، ثمّ AC + CD = AD.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7ffa1eaa-9c2c-592c-8187-09ebaa1a178d', 'd5ed3185-e602-5baa-a49f-a68b1191ac7f', 'ABCD متوازي أضلاع مركزه O. ما ناتج مجموع الشعاعين OA + OC؟', '[{"id":"a","text":"AC"},{"id":"b","text":"2OC"},{"id":"c","text":"OB"},{"id":"d","text":"الشعاع الصفري"}]'::jsonb, 'd', 'O هو منتصف [AC] في متوازي الأضلاع، إذن الشعاع OA هو معاكس الشعاع OC، ومنه OA + OC = الشعاع الصفري. الخطأ الشائع: محاولة تطبيق شال على OA + OC رغم أنّ طرف الأوّل (A) ليس منشأ الثاني (O) — شال يصلح لـ AO + OC = AC لا لهذا المجموع.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('93d7ec3c-499d-5401-afbd-44d801bd6165', '2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', '⚔️ زعيم الفصل ⭐⭐⭐: الأشعّة والانسحاب — المعركة الكبرى', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4609e772-5f83-5574-8c5e-b07651940b89', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'ABCD متوازي أضلاع. بسّط مجموع الأشعّة: CA + AB + BD', '[{"id":"a","text":"CD"},{"id":"b","text":"AD"},{"id":"c","text":"CB"},{"id":"d","text":"الشعاع الصفري"}]'::jsonb, 'a', 'نطبّق شال تدريجيًا: CA + AB = CB، ثمّ CB + BD = CD. النتيجة هي الشعاع CD.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1029d23d-c758-50bc-b5ba-adcdadbe99a5', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'A وB وC ثلاث نقاط، والشعاع u يحقّق: AB + CA = u. ما هو الشعاع u؟', '[{"id":"a","text":"CB"},{"id":"b","text":"BC"},{"id":"c","text":"AC"},{"id":"d","text":"الشعاع الصفري"}]'::jsonb, 'a', 'نرتّب الشعاعين (الجمع تبديلي): CA + AB، فبتطبيق شال: CA + AB = CB. إذن u = CB.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f58c292-0423-585e-8b48-f312610e77c9', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'صورة المثلث ABC بالانسحاب ذي الشعاع AB هي المثلث A''B''C''. ماذا يساوي الشعاع AA''؟', '[{"id":"a","text":"AC"},{"id":"b","text":"BA"},{"id":"c","text":"AB"},{"id":"d","text":"الشعاع الصفري"}]'::jsonb, 'c', 'في الانسحاب ذي الشعاع AB، كلّ نقطة M تنتقل بحيث MM'' = AB. وبما أنّ A تنتقل إلى A''، فإنّ AA'' = AB. أمّا الخيارات الأخرى فخاطئة: BA معاكسٌ له، وAC شعاعٌ آخر، والشعاع الصفري يعني انعدام الانتقال.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1e2bc92-9483-533f-bad1-ea11b4139ae1', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'في متوازي الأضلاع ABCD، ما ناتج مجموع الشعاعين BA + BC؟', '[{"id":"a","text":"BD"},{"id":"b","text":"DB"},{"id":"c","text":"AC"},{"id":"d","text":"الشعاع الصفري"}]'::jsonb, 'a', 'بقاعدة متوازي الأضلاع: مجموع شعاعين من نفس المنشأ يساوي شعاع قطر متوازي الأضلاع المبنيّ عليهما. هنا BA + BC = BD (القطر المنطلق من B). الخطأ الشائع: عكس المنحى فاختيار DB، أو الخلط مع القطر الآخر AC.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd7385bc-2ffb-56eb-b657-793013a9961b', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'الشعاع v يحقّق: AB + v = AC. ما هو الشعاع v؟', '[{"id":"a","text":"AB"},{"id":"b","text":"BC"},{"id":"c","text":"CA"},{"id":"d","text":"CB"}]'::jsonb, 'b', 'نعزل v: v = AC − AB = AC + BA (لأنّ معاكس AB هو BA). بالترتيب وتطبيق شال: BA + AC = BC. إذن v = BC. التحقّق: AB + BC = AC ✓. الخطأ الشائع: عكس المنحى فاختيار CB — عوّض دائمًا في المساواة الأصلية للتأكّد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9dd95e83-07c3-5549-80c2-14c2faecbfe6', '93d7ec3c-499d-5401-afbd-44d801bd6165', 'ABCDEF سداسي منتظم مركزه O. ما ناتج مجموع الأشعّة AB + CD + EF؟', '[{"id":"a","text":"AC"},{"id":"b","text":"AD"},{"id":"c","text":"الشعاع الصفري"},{"id":"d","text":"AE"}]'::jsonb, 'c', 'الأشعّة الثلاثة AB وCD وEF متساوية الطول (أضلاع السداسي المنتظم) ومنحياتها متباعدة بـ 120° فيما بينها بالتناظر الدوراني. إذا رسمناها متسلسلة (طرف كلّ شعاع منشأ الذي يليه) أغلقت مثلّثًا، ومجموع أشعّة مسار مغلق هو الشعاع الصفري. الخطأ الشائع: الظنّ أنّ الأشعّة الثلاثة متوازية بالمنحى نفسه — منحياتها مختلفة فلا يصحّ جمع أطوالها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3f4fdade-ea1f-5e7e-8045-6e0c9acaa369', '2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', '⭐⭐ تمرين مراجعة: الأشعّة والانسحاب (نمط امتحان)', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a4a428a-aab2-59a3-b224-8000dced190c', '3f4fdade-ea1f-5e7e-8045-6e0c9acaa369', 'بسّط مجموع الأشعّة بتطبيق علاقة شال: MN + NP + PQ', '[{"id":"a","text":"MQ"},{"id":"b","text":"MP"},{"id":"c","text":"NQ"},{"id":"d","text":"QM"}]'::jsonb, 'a', 'نطبّق شال تدريجيًا: MN + NP = MP، ثمّ MP + PQ = MQ. الحرفان الوسيطان N وP يختفيان ويبقى الشعاع MQ من نقطة الانطلاق إلى نقطة الوصول. التوقّف عند MP يعني نسيان الحدّ الأخير.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6b41809-6203-570a-b2d9-4782a36702c4', '3f4fdade-ea1f-5e7e-8045-6e0c9acaa369', 'ما صورة الدائرة التي مركزها O ونصف قطرها 3 cm بالانسحاب ذي الشعاع u غير الصفري؟', '[{"id":"a","text":"الدائرة نفسها، لأنّ الانسحاب لا يحرّك المركز"},{"id":"b","text":"دائرة مركزها O'' صورة O، ونصف قطرها 3 cm"},{"id":"c","text":"دائرة مركزها O'' صورة O، ونصف قطرها 6 cm"},{"id":"d","text":"قطعة مستقيم طولها 3 cm تصل O بصورته"}]'::jsonb, 'b', 'الانسحاب يحفظ الأطوال والأشكال: صورة دائرة هي دائرة لها نصف القطر نفسه، ومركزها صورة المركز. إذن الصورة دائرة مركزها O'' حيث OO'' = u ونصف قطرها 3 cm. بما أنّ u غير صفري فالمركز يتحرّك فعلًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c995f255-e02a-52f9-9003-3b04f4b3c64c', '3f4fdade-ea1f-5e7e-8045-6e0c9acaa369', 'A وB وC وD أربع نقاط ليست على استقامة واحدة، والشعاعان AB وDC متساويان: AB = DC. ما طبيعة الرباعي ABCD؟', '[{"id":"a","text":"معيّن"},{"id":"b","text":"مربّع"},{"id":"c","text":"متوازي أضلاع"},{"id":"d","text":"شبه منحرف ليس متوازي أضلاع"}]'::jsonb, 'c', 'تساوي الشعاعين AB = DC يعني أنّ الضلعين [AB] و[DC] متوازيان ومتساويان في الطول وبالمنحى نفسه، وهذا هو بالضبط ما يجعل ABCD متوازي أضلاع. لا شيء في المعطى يضمن تساوي ضلعين متجاورين (معيّن) أو وجود زاوية قائمة (مربّع).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d7ef7b66-5e08-58fe-973c-147c56ee9e9b', '3f4fdade-ea1f-5e7e-8045-6e0c9acaa369', 'ما ناتج مجموع الأشعّة AB + BC + CA؟', '[{"id":"a","text":"الشعاع الصفري"},{"id":"b","text":"AC"},{"id":"c","text":"2AB"},{"id":"d","text":"CA"}]'::jsonb, 'a', 'بتطبيق شال تدريجيًا: AB + BC = AC، ثمّ AC + CA = AA = الشعاع الصفري. مجموع الأشعّة على مضلّع مغلق يساوي دائمًا الشعاع الصفري — التوقّف عند AC أو CA يعني نسيان الحدّ الأخير من المجموع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c63e54a0-7b36-546c-925b-5dff53d2bb59', '3f4fdade-ea1f-5e7e-8045-6e0c9acaa369', 'ما الشعاع v الذي يحقّق: v + BC = BA؟', '[{"id":"a","text":"AC"},{"id":"b","text":"AB"},{"id":"c","text":"CB"},{"id":"d","text":"CA"}]'::jsonb, 'd', 'نعزل v: v = BA − BC = BA + CB (لأنّ معاكس BC هو CB). بالترتيب وتطبيق شال: CB + BA = CA. إذن v = CA. التحقّق: BC + CA = BA ✓ (شال). الخطأ الشائع: عكس المنحى فاختيار AC — عوّض دائمًا في المساواة الأصلية للتأكّد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30b4278a-9635-5f41-a8ac-c0408817170a', '3f4fdade-ea1f-5e7e-8045-6e0c9acaa369', 'صورة النقطة A بالانسحاب ذي الشعاع u هي النقطة B، وصورة B بالانسحاب نفسه هي النقطة C. ماذا نستنتج؟', '[{"id":"a","text":"A منتصف [BC]"},{"id":"b","text":"C منتصف [AB]"},{"id":"c","text":"B منتصف [AC]"},{"id":"d","text":"النقاط A وB وC رؤوس مثلّث"}]'::jsonb, 'c', 'من تعريف الانسحاب: AB = u وBC = u، إذن AB = BC. الشعاعان متساويان وطرف الأوّل هو منشأ الثاني، فالنقاط A وB وC على استقامة واحدة وB تبعد عن A بقدر ما تبعد عنها C: إذن B منتصف [AC]. الخطأ الشائع: الخلط في ترتيب النقاط فاختيار A أو C منتصفًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f96bfb8e-ae28-5157-8576-b49148829b89', '2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', '👑 تحدّي النخبة ⭐⭐⭐⭐: الأشعّة والانسحاب — مستوى المتفوّقين', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c9d6f98-209e-5468-8a6c-4c87ba7f359c', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'A وB وC وD أربع نقاط. بسّط مجموع الأشعّة: AB − DB + DC', '[{"id":"a","text":"AD"},{"id":"b","text":"AC"},{"id":"c","text":"BC"},{"id":"d","text":"CA"}]'::jsonb, 'b', 'نحوّل الطرح إلى جمع بالشعاع المعاكس: −DB = BD، فالمجموع يصبح AB + BD + DC. بشال: AB + BD = AD، ثمّ AD + DC = AC. إذن الناتج هو AC. الخطأ الشائع: نسيان قلب الحرفين عند أخذ المعاكس فيتعطّل تسلسل شال، أو التوقّف عند AD بإهمال الحدّ الأخير.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d48d4549-5b64-528a-acf7-a8e9a88aa0b2', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'M نقطة في المستوي. صورة M بالانسحاب ذي الشعاع AB هي M''، وصورة M'' بالانسحاب ذي الشعاع BC هي M''''. ما هو الشعاع MM''''؟', '[{"id":"a","text":"AB"},{"id":"b","text":"MB"},{"id":"c","text":"AC"},{"id":"d","text":"BC"}]'::jsonb, 'c', 'من تعريف الانسحاب: MM'' = AB وM''M'''' = BC. بتطبيق شال: MM'''' = MM'' + M''M'''' = AB + BC = AC. إذن تركيب انسحابَين متتاليَين يعطي انسحابًا شعاعه مجموع الشعاعَين. الخطأ الشائع: الاكتفاء بأحد الشعاعين AB أو BC دون تركيب الانسحابَين.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('896f4d8e-0e34-5870-8775-7f52b4b92a18', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'A وB وC وD وE خمس نقاط. بسّط: AC − BC + BD − ED', '[{"id":"a","text":"AB"},{"id":"b","text":"CE"},{"id":"c","text":"AD"},{"id":"d","text":"AE"}]'::jsonb, 'd', 'نحوّل الطرح إلى جمع: AC − BC = AC + CB، وبشال: AC + CB = AB. ثمّ BD − ED = BD + DE، وبشال: BD + DE = BE. الناتج الكلّي: AB + BE = AE (شال مرّة أخرى). إذن النتيجة هي AE. الخطأ الشائع: التوقّف عند AB ونسيان الشطر الثاني من التعبير.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('160fd90e-d7df-5bfc-94e0-7c35ae98bbb4', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'M نقطة. صورتها بالانسحاب ذي الشعاع u هي M''، ثمّ صورة M'' بالانسحاب ذي الشعاع المعاكس −u هي M''''. ماذا يساوي الشعاع MM''''؟', '[{"id":"a","text":"الشعاع الصفري"},{"id":"b","text":"2u"},{"id":"c","text":"u"},{"id":"d","text":"−u"}]'::jsonb, 'a', 'من تعريف الانسحاب: MM'' = u وM''M'''' = −u. بتطبيق شال: MM'''' = MM'' + M''M'''' = u + (−u) = الشعاع الصفري. هذا يعني أنّ M'''' = M: تطبيق انسحاب ثمّ معاكسه يعيد كلّ نقطة إلى مكانها. الخطأ الشائع: جمع الطولين فاختيار 2u — الشعاعان متعاكسان فيُلغي أحدهما الآخر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('529b64f3-4a2a-5866-b77d-a883f9003aa4', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'ABCD متوازي أضلاع مركزه O. بسّط مجموع الأشعّة: AO + OC + CB', '[{"id":"a","text":"AC"},{"id":"b","text":"AB"},{"id":"c","text":"AD"},{"id":"d","text":"الشعاع الصفري"}]'::jsonb, 'b', 'بشال مباشرة: AO + OC = AC (المرور بالنقطة O لا يغيّر شيئًا)، ثمّ AC + CB = AB. كون O مركز متوازي الأضلاع معلومةٌ فخّ لا حاجة إليها هنا. الخطأ الشائع: الظنّ أنّ المرور بالمركز يجعل المجموع صفريًا، أو التوقّف عند AC بإهمال الحدّ الأخير.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6c6381e-0ba0-5e85-b3b5-1cc4ea5d7faa', 'f96bfb8e-ae28-5157-8576-b49148829b89', 'ABCD متوازي أضلاع. بسّط مجموع الأشعّة: AB + CD + AD', '[{"id":"a","text":"AD"},{"id":"b","text":"AC"},{"id":"c","text":"DB"},{"id":"d","text":"الشعاع الصفري"}]'::jsonb, 'a', 'في متوازي الأضلاع ABCD: AB = DC، فمعاكسه CD = BA. إذن AB + CD = AB + BA = الشعاع الصفري، ويبقى من المجموع AD فقط. الخطأ الشائع: الظنّ أنّ المجموع كلّه صفري — الشعاع الثالث AD لا يُلغيه شيء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3497cf16-c3a6-509e-95ad-376ce8a5e5af', '2ed2e3ac-7b29-5351-abd6-b9343cc9a4f9', 'math', '📝 تدريب ⭐⭐⭐: الأشعّة والانسحاب (مراجعة شاملة)', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
