INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56c73ae6-21ea-50a7-ae5f-36e41527d3e8', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'أكمل التفكيك وفق علاقة شال بإدخال النقطة M: الشعاع AC = ؟', '[{"id":"a","text":"AM + MC"},{"id":"b","text":"AM + CM"},{"id":"c","text":"MA + MC"},{"id":"d","text":"MA + CM"}]'::jsonb, 'a', 'علاقة شال تُقرأ أيضًا بالعكس: يمكن تفكيك أيّ شعاع بإدخال نقطة وسيطة: AC = AM + MC (من A إلى M ثمّ من M إلى C). الترتيب مهمّ: طرف الشعاع الأوّل يجب أن يكون منشأ الثاني.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7bfdffd3-9742-582c-b215-fb9538e3e4b4', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'بسّط مجموع الأشعّة: AB + BC + CD + DA', '[{"id":"a","text":"AD"},{"id":"b","text":"الشعاع الصفري"},{"id":"c","text":"AC"},{"id":"d","text":"DA"}]'::jsonb, 'b', 'بشال تدريجيًا: AB + BC = AC، ثمّ AC + CD = AD، ثمّ AD + DA = AA = الشعاع الصفري. مسار مغلق يبدأ وينتهي في A مجموعه دائمًا الشعاع الصفري. التوقّف عند AD يعني نسيان الحدّ الأخير.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b458517-ac01-509a-8c23-f0dda8c64a2f', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'الرباعي ABCD يحقّق المساواة الشعاعية AB = DC. ماذا نستنتج عن قطريه [AC] و[BD]؟', '[{"id":"a","text":"متعامدان"},{"id":"b","text":"متساويان في الطول"},{"id":"c","text":"لهما المنتصف نفسه"},{"id":"d","text":"لا توجد بينهما علاقة خاصّة"}]'::jsonb, 'c', 'AB = DC يعني أنّ ABCD متوازي أضلاع، وفي متوازي الأضلاع يتقاطع القطران [AC] و[BD] في منتصف كلّ منهما — أي لهما المنتصف نفسه. أمّا التعامد فخاصّ بالمعيّن، وتساوي الطول خاصّ بالمستطيل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc6fd815-3864-588a-afcc-0bcbfccd1ce3', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'في الانسحاب ذي الشعاع u، النقطة N هي صورة النقطة P (أي P هي سابقة N). أيّ علاقة شعاعية صحيحة؟', '[{"id":"a","text":"NP = u"},{"id":"b","text":"PN = الشعاع الصفري"},{"id":"c","text":"N = P"},{"id":"d","text":"PN = u"}]'::jsonb, 'd', 'تعريف الانسحاب: الشعاع ينطلق من السابقة نحو الصورة، إذن PN = u. الخطأ الشائع: قلب المنحى وكتابة NP = u — للعودة من الصورة إلى سابقتها نستعمل الشعاع المعاكس −u.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21ca47be-6794-51f0-8fea-5408c9214d64', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'I منتصف القطعة [AB]. أيّ مساواة شعاعية صحيحة؟', '[{"id":"a","text":"IA + IB = الشعاع الصفري"},{"id":"b","text":"IA = IB"},{"id":"c","text":"AI = BI"},{"id":"d","text":"IA + IB = AB"}]'::jsonb, 'a', 'بما أنّ I منتصف [AB] فإنّ الشعاعين IA وIB متساويان في الطول ومتعاكسان في المنحى، أي IB هو معاكس IA، ومجموعهما الشعاع الصفري. الخطأ الشائع: كتابة IA = IB — الطولان متساويان لكنّ المنحيين متعاكسان فالشعاعان غير متساويين.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2aa4dc51-0b7d-53b4-bdb6-2cf08ff2336b', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'بسّط الفرق بين الشعاعين: AB − CB', '[{"id":"a","text":"BA"},{"id":"b","text":"AC"},{"id":"c","text":"CA"},{"id":"d","text":"CB"}]'::jsonb, 'b', 'نحوّل الطرح إلى جمع بالشعاع المعاكس: AB − CB = AB + BC (لأنّ معاكس CB هو BC). بشال: AB + BC = AC. الخطأ الشائع: نسيان قلب الحرفين عند أخذ المعاكس، أو عكس المنحى في النهاية فاختيار CA.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

