INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('407ecc53-5aaa-5a28-903e-69bc33e312e0', '8a45a71b-b2f9-5c7c-ad4d-674eab139c61', 'A(2 ; 4) وB(8 ; 4). ما إحداثيّات منتصف I للقطعة [AB]؟', '[{"id":"a","text":"(4 ; 4)"},{"id":"b","text":"(5 ; 4)"},{"id":"c","text":"(5 ; 8)"},{"id":"d","text":"(3 ; 4)"}]'::jsonb, 'b', 'المنتصف I له الإحداثيّات: ((2 + 8)/2 ; (4 + 4)/2) = (10/2 ; 8/2) = (5 ; 4).', 2)
