INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7c5cade-1693-5c8c-91c9-b41aa36e44e5', '8a45a71b-b2f9-5c7c-ad4d-674eab139c61', 'A(−1 ; 2) وB(3 ; 5). ما إحداثيّات منتصف [AB]؟', '[{"id":"a","text":"(2 ; 3,5)"},{"id":"b","text":"(1 ; 3,5)"},{"id":"c","text":"(1 ; 7)"},{"id":"d","text":"(4 ; 7)"}]'::jsonb, 'b', 'صيغة المنتصف: I = ((xA + xB)/2 ; (yA + yB)/2) = ((−1 + 3)/2 ; (2 + 5)/2) = (1 ; 3,5). الخطأ الشائع: الجمع دون القسمة على 2، أو الخلط بين الإحداثيّتين.', 5)
ON CONFLICT (id) DO UPDATE SET
