  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('092c32a9-516a-5bb5-982e-63f573d04e0f', '8a45a71b-b2f9-5c7c-ad4d-674eab139c61', 'A(1 ; 1) وB(4 ; 5). ما المسافة AB؟', '[{"id":"a","text":"7"},{"id":"b","text":"√7"},{"id":"c","text":"√34"},{"id":"d","text":"5"}]'::jsonb, 'd', 'AB = √((4 − 1)² + (5 − 1)²) = √(3² + 4²) = √(9 + 16) = √25 = 5.', 6)
