INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('48cb8baf-edce-5753-8d55-cbb25021aa96', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(−2 ; 1) وB(4 ; 5). نقطة C(1 ; 3). هل C هي منتصف [AB]؟', '[{"id":"a","text":"لا، المنتصف هو (1 ; 2)"},{"id":"b","text":"نعم، C هي منتصف [AB]"},{"id":"c","text":"لا، المنتصف هو (2 ; 3)"},{"id":"d","text":"لا، المنتصف هو (1 ; 4)"}]'::jsonb, 'b', 'نحسب المنتصف: ((−2 + 4)/2 ; (1 + 5)/2) = (2/2 ; 6/2) = (1 ; 3). وبما أنّ C(1 ; 3) فإنّ C هي فعلًا منتصف [AB].', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
