INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a0d2297-0ecc-5787-ac5a-94aa07e50e80', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'ABCD متوازي أضلاع بـ A(1 ; 2) وB(5 ; 2) وC(6 ; 5). ما إحداثيّات D؟', '[{"id":"a","text":"D(3 ; 5)"},{"id":"b","text":"D(2 ; 5)"},{"id":"c","text":"D(7 ; 5)"},{"id":"d","text":"D(0 ; 5)"}]'::jsonb, 'b', 'في متوازي الأضلاع ABCD: AB = DC (شعاعان). AB(4 ; 0)، إذن xC − xD = 4 فـ xD = 6 − 4 = 2، وyC − yD = 0 فـ yD = 5. إذن D(2 ; 5). التحقّق: AD(1 ; 3) وBC(1 ; 3) متساويان ✓. الخطأ الشائع: الخلط بين DC وCD فينعكس اتجاه الإزاحة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a7359118-a246-5e74-affa-d0f61216527d', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(2 ; −1) وB(6 ; −1) وC(6 ; 4). هل المثلّث ABC قائم الزاوية؟ وأين القائمة؟', '[{"id":"a","text":"نعم، القائمة في A لأنّ AB² + AC² = BC²"},{"id":"b","text":"لا، ليس قائمًا"},{"id":"c","text":"نعم، القائمة في B لأنّ AB² + BC² = AC²"},{"id":"d","text":"نعم، القائمة في C لأنّ AC² + BC² = AB²"}]'::jsonb, 'c', 'AB = √((6 − 2)² + 0²) = 4، وBC = √(0² + (4 + 1)²) = 5، وAC = √((6 − 2)² + (4 + 1)²) = √(16 + 25) = √41. نتحقّق: AB² + BC² = 16 + 25 = 41 = AC² ✓ (عكس فيثاغورس). إذن القائمة في B. لاحظ أيضًا: [AB] أفقي و[BC] عمودي فهما متعامدان عند B. الخطأ الشائع: نسبة القائمة إلى الرأس المقابل للوتر بدل الرأس الذي تلتقي عنده الساقان.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3c8e5bbe-7712-5a11-8da7-b237b1b6b03c', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'A(0 ; 0) وB(6 ; 0) وC(0 ; 8). I منتصف [BC]. ما المسافة AI؟', '[{"id":"a","text":"5"},{"id":"b","text":"7"},{"id":"c","text":"√45"},{"id":"d","text":"10"}]'::jsonb, 'a', 'المنتصف I = ((6 + 0)/2 ; (0 + 8)/2) = (3 ; 4). ثمّ AI = √(3² + 4²) = √(9 + 16) = √25 = 5. ملاحظة: المثلّث ABC قائم في A وBC = 10، والوسيط المتعلّق بالوتر يساوي نصفه = 5 ✓. الخطأ الشائع: حساب منتصف [AB] أو [AC] بدل [BC] قبل تطبيق صيغة المسافة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd648144-7179-5365-9d15-3babfef30bf3', '244944cd-952e-56c0-91ae-7dde1326a5d6', 'ما صورة النقطة C(4 ; 2) بالانسحاب الذي ينقل A(−3 ; 1) إلى B(1 ; 4)؟', '[{"id":"a","text":"C''(8 ; 5)"},{"id":"b","text":"C''(7 ; 6)"},{"id":"c","text":"C''(4 ; 3)"},{"id":"d","text":"C''(0 ; −1)"}]'::jsonb, 'a', 'شعاع الانسحاب هو AB(1 − (−3) ; 4 − 1) = AB(4 ; 3). صورة C تحقّق CC'' = AB، إذن C''(4 + 4 ; 2 + 3) = C''(8 ; 5). الخطأ الشائع: طرح الشعاع بدل جمعه فيُحصل على (0 ; −1)، أو قلب مركّبتي الشعاع فيُحصل على (7 ; 6).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('64f5f198-b1d7-59c2-9dfd-288814c2030a', '67e1970d-7e67-5193-acd3-1729b90b0cb2', 'math', '⭐⭐ تمرين مراجعة: المعلّم في المستوي (نمط امتحان)', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
