INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1568e6ec-a611-52ce-8d7b-38e16af2592e', '64f5f198-b1d7-59c2-9dfd-288814c2030a', 'A(−2 ; 3) وB(4 ; −1). ما إحداثيّا الشعاع AB؟', '[{"id":"a","text":"AB(−6 ; 4)"},{"id":"b","text":"AB(6 ; −4)"},{"id":"c","text":"AB(2 ; 2)"},{"id":"d","text":"AB(4 ; −2)"}]'::jsonb, 'b', 'إحداثيّا الشعاع AB: xB − xA = 4 − (−2) = 6 وyB − yA = −1 − 3 = −4. إذن AB(6 ; −4). القاعدة: «طرف ناقص منشأ».', 1)
