INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4cd8ac5-ef31-5a95-acf7-5a4d19cd083e', '64f5f198-b1d7-59c2-9dfd-288814c2030a', 'ما إحداثيّا منتصف I للقطعة [AB] إذا كانت A(3 ; 5) وB(−1 ; 7)؟', '[{"id":"a","text":"I(1 ; 6)"},{"id":"b","text":"I(2 ; 6)"},{"id":"c","text":"I(4 ; 12)"},{"id":"d","text":"I(1 ; 1)"}]'::jsonb, 'a', 'منتصف [AB]: xI = (3 + (−1))/2 = 2/2 = 1 وyI = (5 + 7)/2 = 12/2 = 6. إذن I(1 ; 6).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
