INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f95b203a-045b-5942-9dd9-c3548cb363c7', '64f5f198-b1d7-59c2-9dfd-288814c2030a', 'A(0 ; 0) وB(5 ; 12). ما قيمة المسافة AB؟', '[{"id":"a","text":"AB = 7"},{"id":"b","text":"AB = 17"},{"id":"c","text":"AB = √119"},{"id":"d","text":"AB = 13"}]'::jsonb, 'd', 'AB = √((5 − 0)² + (12 − 0)²) = √(25 + 144) = √169 = 13. المثلّث 5-12-13 مثلّث قائم كلاسيكي: 5² + 12² = 25 + 144 = 169 = 13².', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
