  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0e3aa295-fdcd-5246-8df6-db9226c80367', '64f5f198-b1d7-59c2-9dfd-288814c2030a', 'A(2 ; −4) وB(6 ; 8). ما إحداثيّا منتصف I للقطعة [AB]؟', '[{"id":"a","text":"I(8 ; 4)"},{"id":"b","text":"I(4 ; 2)"},{"id":"c","text":"I(2 ; 2)"},{"id":"d","text":"I(4 ; −2)"}]'::jsonb, 'b', 'xI = (2 + 6)/2 = 8/2 = 4 وyI = (−4 + 8)/2 = 4/2 = 2. إذن I(4 ; 2). تحقّق: AI(2 ; 6) وIB(2 ; 6) متساويان ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
