INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27a6be4d-a962-5679-8ff5-496ff0036083', '64f5f198-b1d7-59c2-9dfd-288814c2030a', 'A(−1 ; 2) وB(3 ; 5). احسب المسافة AB.', '[{"id":"a","text":"AB = 7"},{"id":"b","text":"AB = √7"},{"id":"c","text":"AB = √41"},{"id":"d","text":"AB = 5"}]'::jsonb, 'd', 'فرق الفاصلتين: 3 − (−1) = 4، وفرق الترتيبتين: 5 − 2 = 3. AB = √(4² + 3²) = √(16 + 9) = √25 = 5. المثلّث 3-4-5 من المثلّثات القياسية في الامتحانات.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6769452a-dee4-5955-98b1-a5bba6570cf5', '64f5f198-b1d7-59c2-9dfd-288814c2030a', 'ABCD متوازي أضلاع. B(2 ; 1)، C(7 ; 3)، D(4 ; 6). ما إحداثيّا A؟', '[{"id":"a","text":"A(5 ; −2)"},{"id":"b","text":"A(4 ; −1)"},{"id":"c","text":"A(−1 ; 4)"},{"id":"d","text":"A(9 ; 8)"}]'::jsonb, 'c', 'في متوازي الأضلاع ABCD: AB = DC (شعاعان). نحسب DC(7 − 4 ; 3 − 6) = DC(3 ; −3). إذن xB − xA = 3 فـ xA = 2 − 3 = −1، وyB − yA = −3 فـ yA = 1 − (−3) = 4. إذن A(−1 ; 4). التحقّق: AD(5 ; 2) وBC(5 ; 2) متساويان ✓. الخطأ الشائع: جمع الشعاع إلى B بدل طرحه فيُحصل على (5 ; −2).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('82ea5e0f-bd45-5a46-8c9d-dce60f426754', '67e1970d-7e67-5193-acd3-1729b90b0cb2', 'math', '👑 تحدّي النخبة ⭐⭐⭐⭐: المعلّم في المستوي — مستوى الامتياز', 4, 300, 60, 'challenge', 'admin', 4)
