INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cbb52ab4-8c54-57d9-8a55-a25f53f3e20f', '82ea5e0f-bd45-5a46-8c9d-dce60f426754', 'في معلّم متعامد ومتجانس، لدينا A(1 ; 1) وB(5 ; 2) وC(7 ; 6) وD(3 ; 5). احسب الشعاعين AB وDC ثمّ AD وBC، واستنتج طبيعة ABCD.', '[{"id":"a","text":"ABCD معيّن (لوزيّ الشكل) لأنّ AB = AD"},{"id":"b","text":"ABCD مستطيل لأنّ AB = DC وزواياه قائمة"},{"id":"c","text":"ABCD متوازي أضلاع لأنّ AB = DC (شعاعان)، وليس معيّنًا ولا مستطيلًا"},{"id":"d","text":"ABCD شبه منحرف فقط لأنّ ضلعًا واحدًا موازٍ للآخر"}]'::jsonb, 'c', 'نحسب: AB(5 − 1 ; 2 − 1) = AB(4 ; 1) وDC(7 − 3 ; 6 − 5) = DC(4 ; 1)، إذن AB = DC. كذلك AD(2 ; 4) وBC(2 ; 4) متساويان. استنتاج: ABCD متوازي أضلاع. — هل هو معيّن؟ AB = √(4² + 1²) = √17 وAD = √(2² + 4²) = √20، فالضلعان المتجاوران غير متساويين، ليس معيّنًا. — هل هو مستطيل؟ نختبر الزاوية A بعكس فيثاغورس في المثلّث ABD: AB² + AD² = 17 + 20 = 37، بينما BD² = (3 − 5)² + (5 − 2)² = 4 + 9 = 13. بما أنّ 37 ≠ 13 فالزاوية A ليست قائمة، ليس مستطيلًا. إذن ABCD متوازي أضلاع فحسب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6f401cf-cfa4-528a-91f1-5a7b3cdc07d4', '82ea5e0f-bd45-5a46-8c9d-dce60f426754', 'I هي منتصف القطعة [AC] حيث I(2 ; 3) وA(−1 ; 1). أوجد إحداثيّات C، ثمّ احسب المسافة AC.', '[{"id":"a","text":"C(5 ; 5) والمسافة AC = √13"},{"id":"b","text":"C(5 ; 5) والمسافة AC = 2√13"},{"id":"c","text":"C(3 ; 5) والمسافة AC = √20"},{"id":"d","text":"C(5 ; 3) والمسافة AC = √40"}]'::jsonb, 'b', 'بما أنّ I منتصف [AC]: 2 = (−1 + xC)/2 فـ xC = 5، و3 = (1 + yC)/2 فـ yC = 5. إذن C(5 ; 5). — المسافة: AC = √((5 − (−1))² + (5 − 1)²) = √(6² + 4²) = √(36 + 16) = √52 = 2√13 ✓. الخطأ الشائع: حساب المسافة AI بدل AC فيُحصل على √13 (نصف المسافة)، أو الخطأ في تطبيق صيغة المنتصف فتُقلب الإحداثيّات.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dd58941e-a1c7-54c8-92c2-9cf66f08d7e5', '82ea5e0f-bd45-5a46-8c9d-dce60f426754', 'النقاط A(1 ; 2) وB(3 ; 5) وC(5 ; 8). ادرس وضعيّة النقاط الثلاث. أيّ عبارة صحيحة؟', '[{"id":"a","text":"B منتصف [AC]، فالنقاط الثلاث على استقامة واحدة"},{"id":"b","text":"A منتصف [BC]"},{"id":"c","text":"C منتصف [AB]"},{"id":"d","text":"النقاط الثلاث رؤوس مثلّث (ليست على استقامة واحدة)"}]'::jsonb, 'a', 'نحسب منتصف [AC]: ((1 + 5)/2 ; (2 + 8)/2) = (3 ; 5) وهي بالضبط إحداثيّات B. إذن B منتصف [AC]، ومنه النقاط A وB وC على استقامة واحدة. التحقّق بالمسافات: AB = √(2² + 3²) = √13 وBC = √(2² + 3²) = √13 وAC = √(4² + 6²) = √52 = 2√13، فعلًا AB + BC = AC ✓. الخطأ الشائع: الاكتفاء بالنظر إلى الإحداثيّات دون حساب المنتصف أو المسافات.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('492b7e8d-ba24-52cb-b003-830e65e71671', '82ea5e0f-bd45-5a46-8c9d-dce60f426754', 'المثلّث ABC بـ A(−2 ; 1) وB(4 ; 1) وC(1 ; 5). أثبت أنّه متساوي الساقين ثمّ احسب محيطه. ما محيط المثلّث؟', '[{"id":"a","text":"المحيط = 6 + 5 + 5 = 16"},{"id":"b","text":"المحيط = 6 + √13 + √13"},{"id":"c","text":"المحيط = 6 + √20 + √20"},{"id":"d","text":"المحيط = √36 + √25 + √20"}]'::jsonb, 'a', 'AB = √((4 − (−2))² + (1 − 1)²) = √(6² + 0) = 6. وAC = √((1 − (−2))² + (5 − 1)²) = √(3² + 4²) = √(9 + 16) = √25 = 5. وBC = √((1 − 4)² + (5 − 1)²) = √(9 + 16) = √25 = 5. بما أنّ AC = BC = 5، فالمثلّث متساوي الساقين رأسه C. المحيط = AB + AC + BC = 6 + 5 + 5 = 16. الخطأ الشائع: خطأ في فرق الفاصلتين (2 بدل 3) يعطي √20 بدل √25.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c33642b2-a7fa-54aa-b661-684a7c14d002', '82ea5e0f-bd45-5a46-8c9d-dce60f426754', 'ABCD متوازي أضلاع حيث A(2 ; −1) وB(6 ; 1) وC(7 ; 5). أوجد إحداثيّات D ثمّ تحقّق بحساب منتصفَي قطرَي المتوازي.', '[{"id":"a","text":"D(4 ; 3)، ومنتصف [AC] = منتصف [BD] = (4,5 ; 2)"},{"id":"b","text":"D(3 ; 3)، ومنتصف [AC] = منتصف [BD] = (4,5 ; 2)"},{"id":"c","text":"D(3 ; 3)، ومنتصف [AC] = منتصف [BD] = (4 ; 3)"},{"id":"d","text":"D(4 ; 3)، ومنتصف [AC] = منتصف [BD] = (5 ; 2)"}]'::jsonb, 'b', 'في متوازي الأضلاع ABCD: AB = DC (شعاعان). AB(6 − 2 ; 1 − (−1)) = AB(4 ; 2). إذن xC − xD = 4 فـ xD = 3، وyC − yD = 2 فـ yD = 3، أي D(3 ; 3). — التحقّق بالأقطار: منتصف [AC] = ((2 + 7)/2 ; (−1 + 5)/2) = (4,5 ; 2)، ومنتصف [BD] = ((6 + 3)/2 ; (1 + 3)/2) = (4,5 ; 2). المنتصفان متطابقان ✓ وهذا يؤكّد أنّ ABCD متوازي أضلاع. الخطأ الشائع: الخلط بين DC وCD فيُحصل على D(11 ; 7).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b43d900d-c5bc-56b7-b13a-cf2e61b1f98a', '82ea5e0f-bd45-5a46-8c9d-dce60f426754', 'A(−3 ; 2) وB(1 ; −2). النقطة M هي مماثلة A بالنسبة إلى B (أي B منتصف [AM]). أوجد إحداثيّات M ثمّ احسب المسافة OM حيث O أصل المعلّم.', '[{"id":"a","text":"M(5 ; −6) والمسافة OM = √61"},{"id":"b","text":"M(5 ; −6) والمسافة OM = 11"},{"id":"c","text":"M(−1 ; 0) والمسافة OM = 1"},{"id":"d","text":"M(−7 ; 6) والمسافة OM = √85"}]'::jsonb, 'a', 'B منتصف [AM] يعني: 1 = (−3 + xM)/2 فـ xM = 5، و−2 = (2 + yM)/2 فـ yM = −6. إذن M(5 ; −6). المسافة: OM = √(5² + (−6)²) = √(25 + 36) = √61. الخطأ الشائع: حساب منتصف [AB] بدل تطبيق الشرط «B منتصف [AM]» فيُحصل على (−1 ; 0)، أو جمع 5 و6 دون تربيع فيُحصل على 11.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

