INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2eeb1f26-7df6-5d41-a80e-ed3e39328bd1', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'ABCD متوازي أضلاع بـ A(0 ; 0) وB(4 ; 1) وD(1 ; 3). ما إحداثيّات C؟', '[{"id":"a","text":"C(5 ; 4)"},{"id":"b","text":"C(3 ; 2)"},{"id":"c","text":"C(5 ; 1)"},{"id":"d","text":"C(4 ; 4)"}]'::jsonb, 'a', 'في متوازي الأضلاع ABCD: AB = DC (شعاعان). AB(4 ; 1)، إذن C(1 + 4 ; 3 + 1) = C(5 ; 4). التحقّق: AD(1 ; 3) وBC(1 ; 3) متساويان ✓. الخطأ الشائع: تطبيق AB = CD بدل AB = DC فينعكس اتجاه الإزاحة.', 4)
