INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5474864-0c4c-5a96-a6ce-e7028ab46829', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'المثلّث ABC حيث A(1 ; 1) وB(4 ; 7) وC(7 ; 1). ما طبيعة المثلّث ABC؟', '[{"id":"a","text":"متساوي الأضلاع"},{"id":"b","text":"متساوي الساقين رأسه B"},{"id":"c","text":"قائم الزاوية في B"},{"id":"d","text":"مختلف الأضلاع"}]'::jsonb, 'b', 'AB = √((4 − 1)² + (7 − 1)²) = √(9 + 36) = √45، وBC = √((7 − 4)² + (1 − 7)²) = √(9 + 36) = √45، وAC = √((7 − 1)² + 0²) = 6. بما أنّ AB = BC ≠ AC فالمثلّث متساوي الساقين رأسه B. وليس قائمًا في B لأنّ AB² + BC² = 45 + 45 = 90 ≠ 36 = AC². الخطأ الشائع: الحكم من الشكل الظاهري دون حساب المسافات.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89fd3865-98f6-5a03-9663-21869c46aa69', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'الانسحاب ذو الشعاع u(−2 ; 5) ينقل النقطة M إلى M''(3 ; 4). ما إحداثيّات النقطة M (السابقة)؟', '[{"id":"a","text":"M(1 ; 9)"},{"id":"b","text":"M(−1 ; 5)"},{"id":"c","text":"M(5 ; −1)"},{"id":"d","text":"M(−5 ; 1)"}]'::jsonb, 'c', 'تعريف الانسحاب: MM'' = u، أي xM'' − xM = −2 وyM'' − yM = 5. إذن xM = 3 − (−2) = 5 وyM = 4 − 5 = −1، فالنقطة M(5 ; −1). التحقّق: من M(5 ; −1) بإضافة u(−2 ; 5) نصل إلى (3 ; 4) = M'' ✓. الخطأ الشائع: إضافة الشعاع إلى M'' بدل طرحه فيُحصل على (1 ; 9) — للعودة إلى السابقة نطرح شعاع الانسحاب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3a51242e-ec62-53a0-92f7-0080b8a3978d', '0c844ff1-0195-5d0c-a7ab-f03a2bc2863e', 'math', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
