  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('515f2a05-a4eb-5cfc-9467-d9d72552e21f', '3a51242e-ec62-53a0-92f7-0080b8a3978d', 'ما الفرق الجوهري بين الموشور القائم والهرم من حيث الشكل والقواعد؟', '[{"id":"a","text":"الموشور له قاعدة واحدة مضلّعة وقمّة نقطيّة؛ الهرم له قاعدتان متطابقتان"},{"id":"b","text":"الموشور له قاعدتان متوازيتان متطابقتان ووجوه جانبية مستطيلة؛ الهرم له قاعدة واحدة وقمّة نقطيّة"},{"id":"c","text":"الموشور والهرم لهما نفس الشكل ولكن مقياس مختلف"},{"id":"d","text":"الهرم له قاعدتان دائريّتان؛ الموشور له قاعدة واحدة مضلّعة"}]'::jsonb, 'b', 'الموشور القائم: قاعدتان متوازيتان متطابقتان (أيّ مضلّع) ووجوه جانبية مستطيلة. الهرم: قاعدة مضلّعة واحدة + وجوه جانبية مثلّثية تلتقي في قمّة نقطيّة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0308f2e5-db35-5664-acf3-53ebbce6a913', '3a51242e-ec62-53a0-92f7-0080b8a3978d', 'ما صيغة حجم الموشور القائم؟', '[{"id":"a","text":"V = (1/3) × S(قاعدة) × h"},{"id":"b","text":"V = (4/3) × π × r³"},{"id":"c","text":"V = S(قاعدة) × h"},{"id":"d","text":"V = π × r² × h"}]'::jsonb, 'c', 'حجم الموشور القائم = مساحة القاعدة × الارتفاع. القاعدة يمكن أن تكون أيّ مضلّع (مستطيل، مثلّث، وغيره).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f7707a70-81ca-5863-ab2f-802343c5a75a', '3a51242e-ec62-53a0-92f7-0080b8a3978d', 'العلاقة بين حجم الهرم وحجم الموشور ذي نفس القاعدة والارتفاع هي:', '[{"id":"a","text":"حجم الهرم = حجم الموشور"},{"id":"b","text":"حجم الهرم = ضعف حجم الموشور"},{"id":"c","text":"حجم الهرم = ثلث حجم الموشور"},{"id":"d","text":"حجم الهرم = نصف حجم الموشور"}]'::jsonb, 'c', 'V(هرم) = (1/3) × S(قاعدة) × h، بينما V(موشور) = S(قاعدة) × h. إذن الهرم يساوي ثلث الموشور ذي نفس القاعدة والارتفاع. وكذلك المخروط مقارنةً بالأسطوانة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0933b11c-809b-55a6-b3b3-d9334658266c', '3a51242e-ec62-53a0-92f7-0080b8a3978d', 'ما صيغة حجم الكرة ذات نصف القطر r؟', '[{"id":"a","text":"V = 4π r²"},{"id":"b","text":"V = (4/3) π r³"},{"id":"c","text":"V = (1/3) π r² h"},{"id":"d","text":"V = π r² h"}]'::jsonb, 'b', 'حجم الكرة = (4/3) π r³. أمّا 4πr² فهي مساحة سطح الكرة وليس حجمها. للمخروط: (1/3)πr²h، وللأسطوانة: πr²h.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9cb0b0f5-0ea5-59a5-a159-27401a4757e5', '3a51242e-ec62-53a0-92f7-0080b8a3978d', 'أسطوانة قاعدتها دائرة نصف قطرها r وارتفاعها h. ما مساحتها الجانبية؟', '[{"id":"a","text":"π r² h"},{"id":"b","text":"2π r²"},{"id":"c","text":"2π r h"},{"id":"d","text":"π r h"}]'::jsonb, 'c', 'المساحة الجانبية للأسطوانة = محيط القاعدة × الارتفاع = 2πr × h = 2πrh. أمّا 2πr² فهي مساحة القاعدتَين معًا، وπr²h هو الحجم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

