  ('c0f4caab-6fe4-5cc1-9698-141918f14e73', '0c844ff1-0195-5d0c-a7ab-f03a2bc2863e', 'math', '⭐ تمرين: حساب حجوم المجسّمات', 1, 50, 10, 'practice', 'admin', 1)
