INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f938f51c-9d1e-5da4-b531-8b543a4792c2', 'c0f4caab-6fe4-5cc1-9698-141918f14e73', 'موشور قائم قاعدته مستطيل طوله 5 cm وعرضه 3 cm وارتفاعه 4 cm. ما حجمه؟', '[{"id":"a","text":"60 cm³"},{"id":"b","text":"45 cm³"},{"id":"c","text":"30 cm³"},{"id":"d","text":"20 cm³"}]'::jsonb, 'a', 'حجم الموشور القائم = مساحة القاعدة × الارتفاع. القاعدة مستطيل مساحته 5 × 3 = 15 cm²، إذن V = 15 × 4 = 60 cm³. تنبيه: نحسب مساحة القاعدة أوّلًا ثمّ نضربها في الارتفاع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('223302f2-2f16-52d3-bbbc-10faa71ed40a', 'c0f4caab-6fe4-5cc1-9698-141918f14e73', 'أيّ صيغة تعطي حجم الأسطوانة؟', '[{"id":"a","text":"(1/3)πr²h"},{"id":"b","text":"(4/3)πr³"},{"id":"c","text":"πr²h"},{"id":"d","text":"2πrh"}]'::jsonb, 'c', 'حجم الأسطوانة = مساحة القاعدة × الارتفاع = πr² × h. أمّا (1/3)πr²h فهي حجم المخروط، و(4/3)πr³ هي حجم الكرة، و2πrh هي المساحة الجانبية للأسطوانة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd3dc54f-1c0c-598c-8515-f4773e66e73f', 'c0f4caab-6fe4-5cc1-9698-141918f14e73', 'أسطوانة نصف قطرها 4 cm وارتفاعها 3 cm. ما حجمها؟ (π ≈ 3,14)', '[{"id":"a","text":"37,68 cm³"},{"id":"b","text":"75,36 cm³"},{"id":"c","text":"150,72 cm³"},{"id":"d","text":"602,88 cm³"}]'::jsonb, 'c', 'حجم الأسطوانة = مساحة القاعدة الدائرية × الارتفاع = πr²h. نربّع نصف القطر أوّلًا: r² = 4² = 16، إذن V = 3,14 × 16 × 3 = 3,14 × 48 = 150,72 cm³. انتبه: نسيان التربيع يعطي 3,14 × 4 × 3 = 37,68، واستعمال القطر 8 بدل نصف القطر يعطي 602,88.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('750dd55f-9959-5972-9ca2-885a2342710f', 'c0f4caab-6fe4-5cc1-9698-141918f14e73', 'هرم قاعدته مربّع ضلعه 6 cm وارتفاعه 4 cm. ما حجمه؟', '[{"id":"a","text":"144 cm³"},{"id":"b","text":"72 cm³"},{"id":"c","text":"48 cm³"},{"id":"d","text":"16 cm³"}]'::jsonb, 'c', 'V = (1/3) × S(قاعدة) × h = (1/3) × 6² × 4 = (1/3) × 36 × 4 = 144/3 = 48 cm³. لا تنسَ معامل الثلث الخاصّ بالهرم.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('546ec25e-87b5-5290-bf81-399849944cf6', 'c0f4caab-6fe4-5cc1-9698-141918f14e73', 'مخروط نصف قطر قاعدته 3 cm وارتفاعه 4 cm. ما حجمه؟ (π ≈ 3,14)', '[{"id":"a","text":"113,04 cm³"},{"id":"b","text":"75,36 cm³"},{"id":"c","text":"37,68 cm³"},{"id":"d","text":"25,12 cm³"}]'::jsonb, 'c', 'حجم المخروط = ثلث حجم الأسطوانة ذات القاعدة والارتفاع نفسهما: V = (1/3)πr²h. نحسب πr²h = 3,14 × 9 × 4 = 113,04، ثمّ نأخذ الثلث: V = 113,04 ÷ 3 = 37,68 cm³.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc3acdeb-df34-5d99-827b-46cad1675a03', 'c0f4caab-6fe4-5cc1-9698-141918f14e73', 'ما مساحة سطح كرة نصف قطرها 5 cm؟ (π ≈ 3,14)', '[{"id":"a","text":"78,5 cm²"},{"id":"b","text":"314 cm²"},{"id":"c","text":"523,33 cm²"},{"id":"d","text":"157 cm²"}]'::jsonb, 'b', 'مساحة سطح الكرة = 4πr². نربّع نصف القطر: r² = 5² = 25، إذن S = 4 × 3,14 × 25 = 314 cm². انتبه إلى التمييز: 4πr² هي المساحة، أمّا الحجم فهو (4/3)πr³.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

