INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eca58638-841d-588b-9108-5ed680a14f01', '00789172-89dd-5cc2-8af9-730645c3c113', 'أسطوانة نصف قطرها 5 cm وارتفاعها 8 cm. ما حجمها؟ (π ≈ 3,14)', '[{"id":"a","text":"314 cm³"},{"id":"b","text":"502,4 cm³"},{"id":"c","text":"628 cm³"},{"id":"d","text":"251,2 cm³"}]'::jsonb, 'c', 'حجم الأسطوانة = مساحة القاعدة الدائرية × الارتفاع = πr²h. نربّع نصف القطر: r² = 5² = 25، إذن V = 3,14 × 25 × 8 = 3,14 × 200 = 628 cm³.', 1)
ON CONFLICT (id) DO UPDATE SET
