INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cfca19fb-620b-5f95-9212-1b6ef4bfafcf', '00789172-89dd-5cc2-8af9-730645c3c113', 'مخروط نصف قطر قاعدته 6 cm وارتفاعه 9 cm. ما حجمه؟ (π ≈ 3,14)', '[{"id":"a","text":"1017,36 cm³"},{"id":"b","text":"678,24 cm³"},{"id":"c","text":"169,56 cm³"},{"id":"d","text":"339,12 cm³"}]'::jsonb, 'd', 'حجم المخروط = ثلث حجم الأسطوانة المقابلة: V = (1/3)πr²h. نربّع نصف القطر: r² = 6² = 36، ونحسب πr²h = 3,14 × 36 × 9 = 1017,36، ثمّ نأخذ الثلث: V = 1017,36 ÷ 3 = 339,12 cm³.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('04e02825-43bc-5b75-a62d-875aa956e3da', '00789172-89dd-5cc2-8af9-730645c3c113', 'هرم قاعدته مثلّث قائم ساقاه 3 cm و4 cm، وارتفاع الهرم 10 cm. ما حجم الهرم؟', '[{"id":"a","text":"60 cm³"},{"id":"b","text":"40 cm³"},{"id":"c","text":"30 cm³"},{"id":"d","text":"20 cm³"}]'::jsonb, 'd', 'مساحة القاعدة المثلّثية: S = (1/2) × 3 × 4 = 6 cm². إذن V = (1/3) × 6 × 10 = 60/3 = 20 cm³. الخطأ الشائع: نسيان معامل الثلث الخاصّ بالهرم فيُحسب 6 × 10 = 60 cm³ (الخيار أ).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d3df261-f148-5b0b-84a6-74ef0aa0e9c4', '00789172-89dd-5cc2-8af9-730645c3c113', 'كرة نصف قطرها 3 cm وأسطوانة نصف قطرها 3 cm وارتفاعها 4 cm. أيّهما حجمه أكبر؟', '[{"id":"a","text":"الكرة أكبر"},{"id":"b","text":"الأسطوانة أكبر بوضوح (36π مقابل 27π)"},{"id":"c","text":"حجماهما متساويان"},{"id":"d","text":"الأسطوانة أكبر بقليل (48π مقابل 36π)"}]'::jsonb, 'c', 'حجم الكرة: V = (4/3)π × 3³ = (4/3) × 27π = 36π cm³. حجم الأسطوانة: V = π × 3² × 4 = 36π cm³. الحجمان متساويان! هذه نتيجة مدهشة تستحقّ الحفظ. الخطأ الشائع: نسيان المعامل 4/3 في صيغة الكرة فيُحصل على πr³ = 27π مقابل 36π (الخيار ب)، أو تطبيق 4/3 على الأسطوانة فيُحصل على 48π مقابل 36π (الخيار د).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03d725a0-aedc-5bd2-a40d-fa740eee3cba', '00789172-89dd-5cc2-8af9-730645c3c113', 'هرم قاعدته مربّع ضلعه 4 cm وارتفاعه 3 cm. إذا ضاعف الارتفاع فقط ليصبح 6 cm، فبكم يتضاعف الحجم؟', '[{"id":"a","text":"يتضاعف مرّتين (×2)"},{"id":"b","text":"يتضاعف ثلاث مرّات (×3)"},{"id":"c","text":"يتضاعف أربع مرّات (×4)"},{"id":"d","text":"يبقى كما هو"}]'::jsonb, 'a', 'V₁ = (1/3) × 16 × 3 = 16 cm³ وV₂ = (1/3) × 16 × 6 = 32 cm³. النسبة V₂/V₁ = 32/16 = 2. الحجم يتضاعف مرّتين لأنّ صيغة الحجم خطّية في h. الخطأ الشائع: تطبيق قاعدة k³ (×8) أو k² (×4) — هذه تخصّ تكبير جميع الأبعاد، أمّا هنا فالارتفاع وحده تغيّر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce97f02a-d74c-52b0-b0e1-7239b8e55545', '00789172-89dd-5cc2-8af9-730645c3c113', 'مخروط نصف قطر قاعدته 6 cm وارتفاعه 8 cm. ما المساحة الجانبية له؟ (π ≈ 3,14)', '[{"id":"a","text":"150,72 cm²"},{"id":"b","text":"301,44 cm²"},{"id":"c","text":"188,4 cm²"},{"id":"d","text":"376,8 cm²"}]'::jsonb, 'c', 'الطول المائل: l = √(r² + h²) = √(6² + 8²) = √(36 + 64) = √100 = 10 cm. المساحة الجانبية: S = πrl = 3,14 × 6 × 10 = 188,4 cm². الخطأ الشائع: استعمال الارتفاع h = 8 بدل الطول المائل l = 10 فيُحصل على 3,14 × 6 × 8 = 150,72 cm² (الخيار أ).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

