  ('3baad67a-a282-5810-90d2-589f56042a87', '0c844ff1-0195-5d0c-a7ab-f03a2bc2863e', 'math', '⭐⭐ تمرين مراجعة: الهندسة في الفضاء (نمط امتحان)', 2, 70, 15, 'practice', 'admin', 3)
