INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4b74883-fa9b-534d-af23-d0f23f600417', '3baad67a-a282-5810-90d2-589f56042a87', 'أسطوانة نصف قطرها 5 cm وارتفاعها 4 cm. ما حجمها تقريبًا؟ (π ≈ 3,14)', '[{"id":"a","text":"314 cm³"},{"id":"b","text":"62,8 cm³"},{"id":"c","text":"125,6 cm³"},{"id":"d","text":"628 cm³"}]'::jsonb, 'a', 'V = πr²h = π × 5² × 4 = π × 25 × 4 = 100π ≈ 100 × 3,14 = 314 cm³. انتبه: نربّع نصف القطر وليس القطر.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d0411eb3-f2e1-58fe-b6b0-3921da7f87df', '3baad67a-a282-5810-90d2-589f56042a87', 'هرم قاعدته مربّع ضلعه 6 cm وارتفاعه 8 cm. ما حجمه؟', '[{"id":"a","text":"288 cm³"},{"id":"b","text":"144 cm³"},{"id":"c","text":"96 cm³"},{"id":"d","text":"48 cm³"}]'::jsonb, 'c', 'S(قاعدة) = 6² = 36 cm². V = (1/3) × S(قاعدة) × h = (1/3) × 36 × 8 = 288/3 = 96 cm³. الهرم دائمًا ثلث الموشور ذي نفس القاعدة والارتفاع.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f98b05b-c8bb-55bc-8b73-a18a556d7258', '3baad67a-a282-5810-90d2-589f56042a87', 'مخروط نصف قطر قاعدته 6 cm وحجمه 108π cm³. ما ارتفاعه h؟', '[{"id":"a","text":"3 cm"},{"id":"b","text":"9 cm"},{"id":"c","text":"27 cm"},{"id":"d","text":"54 cm"}]'::jsonb, 'b', 'V = (1/3)πr²h، إذن 108π = (1/3) × π × 36 × h = 12πh. نعزل الارتفاع: h = 108π ÷ 12π = 9 cm. تحقّق: (1/3) × π × 36 × 9 = 108π ✓. انتبه: نسيان معامل الثلث يعطي h = 108/36 = 3 (الخيار أ)، ونسيان تربيع نصف القطر يعطي h = 54 (الخيار د).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d459fcab-1737-56cb-a40c-a7c8cf4981bb', '3baad67a-a282-5810-90d2-589f56042a87', 'أسطوانة نصف قطرها 4 cm وارتفاعها 5 cm. ما حجمها تقريبًا؟ (π ≈ 3,14)', '[{"id":"a","text":"125,6 cm³"},{"id":"b","text":"62,8 cm³"},{"id":"c","text":"251,2 cm³"},{"id":"d","text":"502,4 cm³"}]'::jsonb, 'c', 'V = πr²h = 3,14 × 4² × 5 = 3,14 × 16 × 5 = 3,14 × 80 = 251,2 cm³. تذكّر: نربّع نصف القطر أوّلًا ثمّ نضرب في الارتفاع.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9f4b96c-9e1b-5c77-9a00-08d4fdde4565', '3baad67a-a282-5810-90d2-589f56042a87', 'كرة نصف قطرها 6 cm. ما حجمها تقريبًا؟ (π ≈ 3,14)', '[{"id":"a","text":"150,72 cm³"},{"id":"b","text":"452,16 cm³"},{"id":"c","text":"678,24 cm³"},{"id":"d","text":"904,32 cm³"}]'::jsonb, 'd', 'V = (4/3)πr³ = (4/3) × 3,14 × 6³ = (4/3) × 3,14 × 216 = (4 × 678,24)/3 = 2712,96/3 = 904,32 cm³.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9c55a8c-88c9-5368-a0cd-075e6be633de', '3baad67a-a282-5810-90d2-589f56042a87', 'موشور قائم قاعدته مثلّث قائم ساقاه 6 cm و8 cm، وارتفاعه 10 cm. ما حجمه؟', '[{"id":"a","text":"240 cm³"},{"id":"b","text":"480 cm³"},{"id":"c","text":"120 cm³"},{"id":"d","text":"400 cm³"}]'::jsonb, 'a', 'مساحة القاعدة المثلّثية: S = (1/2) × 6 × 8 = 24 cm². حجم الموشور: V = S × h = 24 × 10 = 240 cm³. الخطوة الأولى دائمًا: احسب مساحة القاعدة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('d1421795-a726-56b0-9cad-50aaa5188d83', '0c844ff1-0195-5d0c-a7ab-f03a2bc2863e', 'math', '👑 تحدّي النخبة ⭐⭐⭐⭐: الحجوم والأسطح والمجسّمات المركّبة', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
