INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b26ae99-e537-509d-aa4d-f124c526e5cf', 'd1421795-a726-56b0-9cad-50aaa5188d83', 'هرم قاعدته مثلّث قائم ساقاه 6 cm و8 cm وارتفاع الهرم 9 cm. إذا كبّرنا جميع أبعاد هذا الهرم بمعامل k = 2 (أي ضُرب كلّ بُعد في 2)، فما حجم الهرم الجديد؟', '[{"id":"a","text":"144 cm³"},{"id":"b","text":"576 cm³"},{"id":"c","text":"288 cm³"},{"id":"d","text":"216 cm³"}]'::jsonb, 'b', 'الخطوة 1 — مساحة القاعدة المثلّثية: القاعدة مثلّث قائم ساقاه 6 cm و8 cm، إذن S(قاعدة) = (1/2) × 6 × 8 = 24 cm².

الخطوة 2 — حجم الهرم الأصلي: V₁ = (1/3) × 24 × 9 = 216/3 = 72 cm³.

الخطوة 3 — أثر التكبير على الحجم: عند التكبير بمعامل k، تنضرب جميع الأبعاد الثلاثة في k، فينضرب الحجم في k³. هنا k = 2، إذن k³ = 8.

الخطوة 4 — الحجم الجديد: V₂ = k³ × V₁ = 8 × 72 = 576 cm³.

تحذير: الأخطاء الشائعة هي ضرب الحجم في k = 2 (فيُعطي 144) أو في k² = 4 (فيُعطي 288). يجب دائمًا الضرب في k³ لأنّ الحجم يعتمد على ثلاثة أبعاد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ed040a2c-55f6-5da9-ac2a-df50d6089dee', 'd1421795-a726-56b0-9cad-50aaa5188d83', 'هرم قاعدته مربّعة ضلعها 8 cm وارتفاعه 3 cm. قمّته فوق مركز القاعدة. ما طول الحافّة الجانبية من القمّة إلى أيٍّ من رؤوس القاعدة الأربعة؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"√41 cm"},{"id":"c","text":"√73 cm"},{"id":"d","text":"4√2 cm"}]'::jsonb, 'b', 'الخطوة 1 — إيجاد المسافة من مركز القاعدة إلى أحد رؤوسها: القاعدة مربّع ضلعه 8 cm. قطر المربّع = 8√2 cm، ونصف القطر (من المركز إلى الرأس) = 8√2 ÷ 2 = 4√2 cm.

الخطوة 2 — تطبيق فيثاغورس في الفضاء: في المثلّث القائم الذي تشكّله الحافّة الجانبية والارتفاع ونصف قطر القاعدة:
l² = h² + (4√2)² = 3² + 32 = 9 + 32 = 41، إذن l = √41 cm.

تحذير: الخطأ الأكثر شيوعًا هو استخدام نصف الضلع (4 cm) عوضًا عن نصف القطر (4√2 cm)، وهو ما يُعطي √(9 + 16) = √25 = 5 cm — إجابة خاطئة! الخطأ الثاني هو استخدام الضلع الكامل (8 cm): √(9 + 64) = √73 cm.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7582bfe6-a255-5956-b423-62ec96f8d40c', 'd1421795-a726-56b0-9cad-50aaa5188d83', 'مجسّم مركّب يتكوّن من أسطوانة نصف قطرها 6 cm وارتفاعها 10 cm، فوقها نصف كرة نفس نصف القطر 6 cm (وجهها المستوي يلتصق بالقاعدة العلوية للأسطوانة). ما الحجم الكلّي لهذا المجسّم؟ استعمل π رمزيًّا.', '[{"id":"a","text":"648π cm³"},{"id":"b","text":"576π cm³"},{"id":"c","text":"360π cm³"},{"id":"d","text":"504π cm³"}]'::jsonb, 'd', 'الخطوة 1 — حجم الأسطوانة: V(أسطوانة) = πr²h = π × 6² × 10 = π × 36 × 10 = 360π cm³.

الخطوة 2 — حجم نصف الكرة: الكرة الكاملة حجمها (4/3)πr³ = (4/3)π × 216 = 288π cm³، إذن نصف الكرة: V(نصف كرة) = 288π ÷ 2 = 144π cm³.

الخطوة 3 — الحجم الكلّي: V(كلّي) = 360π + 144π = 504π cm³.

تحذير: الخطأ الشائع هو استخدام حجم الكرة الكاملة (288π) بدلًا من نصف الكرة (144π)، فيُعطي 360π + 288π = 648π. الخطأ الآخر هو إهمال نصف الكرة كلّيًّا والإجابة بـ 360π.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6484172-24af-5b73-b361-f3cfcabfac58', 'd1421795-a726-56b0-9cad-50aaa5188d83', 'مخروط ارتفاعه h = 2r (أي ارتفاعه يساوي ضعف نصف قطر قاعدته). وكرة نصف قطرها r. ما نسبة حجم المخروط إلى حجم الكرة؟', '[{"id":"a","text":"1/3"},{"id":"b","text":"1/4"},{"id":"c","text":"1/2"},{"id":"d","text":"2/3"}]'::jsonb, 'c', 'الخطوة 1 — حجم المخروط (بـ h = 2r): V(مخروط) = (1/3)πr²h = (1/3)πr² × 2r = (2/3)πr³.

الخطوة 2 — حجم الكرة: V(كرة) = (4/3)πr³.

الخطوة 3 — النسبة: V(مخروط) ÷ V(كرة) = (2/3)πr³ ÷ (4/3)πr³ = 2/4 = 1/2.

إذن حجم المخروط يساوي نصف حجم الكرة حين يتشاركان نفس r وارتفاعه h = 2r. تأكّد من إلغاء πr³ من البسط والمقام معًا. الخطأ الشائع هو نسيان شرط h = 2r والإجابة بـ 1/3.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('465b46f2-fc97-54e3-9464-5aec0e1f19d3', 'd1421795-a726-56b0-9cad-50aaa5188d83', 'مخروط نصف قطر قاعدته 9 cm وارتفاعه 12 cm. ما مساحة سطحه الكلّية (القاعدة + السطح الجانبي)؟ استعمل π رمزيًّا.', '[{"id":"a","text":"135π cm²"},{"id":"b","text":"216π cm²"},{"id":"c","text":"297π cm²"},{"id":"d","text":"189π cm²"}]'::jsonb, 'b', 'الخطوة 1 — الطول المائل: بفيثاغورس في المثلّث القائم (r ; h ; l):
l = √(r² + h²) = √(9² + 12²) = √(81 + 144) = √225 = 15 cm.
(ثلاثيّة فيثاغورس: 9 = 3 × 3، 12 = 3 × 4، 15 = 3 × 5)

الخطوة 2 — المساحة الجانبية: S(جانبية) = πrl = π × 9 × 15 = 135π cm².

الخطوة 3 — مساحة القاعدة الدائرية: S(قاعدة) = πr² = π × 81 = 81π cm².

الخطوة 4 — المساحة الكلّية: S(كلّية) = 135π + 81π = 216π cm².

تحذير: الخطأ الشائع هو استخدام الارتفاع h بدلًا من الطول المائل l في صيغة المساحة الجانبية: π × 9 × 12 + 81π = 108π + 81π = 189π (الخيار د). خطأ آخر هو استخدام صيغة الأسطوانة 2πrh: 2π × 9 × 12 + 81π = 216π + 81π = 297π.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3cb33ba9-0c3d-5211-b47b-4ff5ca7fe80e', 'd1421795-a726-56b0-9cad-50aaa5188d83', 'موشور قائم قاعدته مثلّث متساوي الأضلاع ضلعه 6 cm وارتفاع الموشور 8 cm. وكرة حجمها يساوي حجم هذا الموشور. ما قيمة R³ حيث R نصف قطر الكرة؟ استعمل π رمزيًّا.', '[{"id":"a","text":"(54√3)/π cm³"},{"id":"b","text":"108/π cm³"},{"id":"c","text":"(18√3)/π cm³"},{"id":"d","text":"54π/√3 cm³"}]'::jsonb, 'a', 'الخطوة 1 — مساحة القاعدة (مثلّث متساوي الأضلاع ضلعه 6 cm): S(قاعدة) = (√3/4) × 6² = (√3/4) × 36 = 9√3 cm².

الخطوة 2 — حجم الموشور: V(موشور) = 9√3 × 8 = 72√3 cm³.

الخطوة 3 — معادلة حجم الكرة: (4/3)πR³ = 72√3.

الخطوة 4 — استخلاص R³: R³ = 72√3 × 3/(4π) = (216√3)/(4π) = (54√3)/π cm³.

تحذير: الخطأ الشائع هو استخدام مساحة المثلّث المتساوي الأضلاع الخطأ: (1/2) × 6 × 6 = 18 بدلًا من 9√3، فيُعطي V = 144 cm³ ثمّ R³ = (3 × 144)/(4π) = 108/π (الخيار ب). لا تنسَ الصيغة الصحيحة: S = (√3/4)a².', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

