INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db5b1cf9-ba85-585d-998f-e17a1ccbb96a', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'أسطوانة نصف قطرها 3 cm وارتفاعها 10 cm. ما حجمها؟ (π ≈ 3,14)', '[{"id":"a","text":"94,2 cm³"},{"id":"b","text":"188,4 cm³"},{"id":"c","text":"282,6 cm³"},{"id":"d","text":"565,2 cm³"}]'::jsonb, 'c', 'حجم الأسطوانة V = πr²h. نربّع نصف القطر: r² = 3² = 9. إذن V = 3,14 × 9 × 10 = 3,14 × 90 = 282,6 cm³.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddbdd453-8143-53da-9bbe-497286ee59a3', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'مخروط نصف قطر قاعدته 3 cm وارتفاعه 4 cm. ما طوله المائل l؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"7 cm"},{"id":"c","text":"√7 cm"},{"id":"d","text":"12 cm"}]'::jsonb, 'a', 'الطول المائل l = √(r² + h²) = √(3² + 4²) = √(9 + 16) = √25 = 5 cm (الثلاثية 3-4-5).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('778771b1-984e-5b3f-b318-5f9ed781b359', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'هرم قاعدته مربّع ضلعه 6 cm وارتفاعه 10 cm. ما حجمه؟', '[{"id":"a","text":"60 cm³"},{"id":"b","text":"100 cm³"},{"id":"c","text":"120 cm³"},{"id":"d","text":"360 cm³"}]'::jsonb, 'c', 'مساحة القاعدة المربّعة S = 6² = 36 cm². حجم الهرم V = (1/3) × S × h = (1/3) × 36 × 10 = 360/3 = 120 cm³.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1410b5e-9143-5d13-91f1-297686628498', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'كرة حجمها 972π cm³. ما نصف قطرها r؟', '[{"id":"a","text":"729 cm"},{"id":"b","text":"243 cm"},{"id":"c","text":"18 cm"},{"id":"d","text":"9 cm"}]'::jsonb, 'd', 'V = (4/3)πr³، إذن 972π = (4/3)πr³. نعزل: r³ = 972 × 3/4 = 729، ثمّ نأخذ الجذر التكعيبي: r = 9 cm لأنّ 9³ = 729. تحقّق: (4/3)π × 729 = 972π ✓. الخطأ الشائع: التوقّف عند r³ = 729 (الخيار أ) أو القسمة على 3 بدل الجذر التكعيبي: 729/3 = 243 (الخيار ب).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba409a8e-709a-569b-8161-5bab65afffce', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'أسطوانة نصف قطرها 4 cm وارتفاعها 7 cm. ما مساحتها الجانبية؟ (π ≈ 3,14)', '[{"id":"a","text":"87,92 cm²"},{"id":"b","text":"100,48 cm²"},{"id":"c","text":"175,84 cm²"},{"id":"d","text":"351,68 cm²"}]'::jsonb, 'c', 'المساحة الجانبية للأسطوانة = محيط القاعدة × الارتفاع = 2πrh = 2 × 3,14 × 4 × 7 = 6,28 × 28 = 175,84 cm². الخطأ الشائع: نسيان المعامل 2 (محيط الدائرة 2πr وليس πr) فيُحصل على 87,92 cm² (الخيار أ).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af07c682-e2b7-5bf7-9de1-e4933dafb486', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'إذا ضُرب نصف قطر كرة في 3 (ليصبح 3r بدل r)، فبكم يتضاعف حجمها؟', '[{"id":"a","text":"3 مرّات (×3)"},{"id":"b","text":"9 مرّات (×9)"},{"id":"c","text":"12 مرّة (×12)"},{"id":"d","text":"27 مرّة (×27)"}]'::jsonb, 'd', 'حجم الكرة V = (4/3)πr³ متناسب مع مكعّب نصف القطر. عند ضرب r في 3: (3r)³ = 27r³، إذن الحجم يتضاعف 27 مرّة. الخطأ الشائع: الضرب في 3 فقط (تفكير خطّي، الخيار أ) أو في 3² = 9 (قاعدة المساحات لا الحجوم، الخيار ب).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('524341c8-b06e-56ea-8f79-09a4cf281ab8', '0d636faa-337f-57db-a256-88d4ec85ca49', 'math', 'اختبار المراجعة الشاملة ⭐', 1, 20, 5, 'quiz', 'admin', 0)
