INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('043b6c57-2efe-5f16-a63d-35c6a2219be7', '524341c8-b06e-56ea-8f79-09a4cf281ab8', 'احسب العدد A = −2 + 3 × (−4).', '[{"id":"a","text":"−14"},{"id":"b","text":"−20"},{"id":"c","text":"−10"},{"id":"d","text":"4"}]'::jsonb, 'a', 'نطبّق أولويّة العمليّات: الضرب قبل الجمع. 3 × (−4) = −12، ثمّ A = −2 + (−12) = −14. الخطأ الشائع: حساب (−2 + 3) × (−4) بإهمال الأولويّة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d480a2b-5fe3-5f4e-9fb7-2b7b02ff7b6c', '524341c8-b06e-56ea-8f79-09a4cf281ab8', 'حلّ المعادلة 3(x − 2) = 2x + 1.', '[{"id":"a","text":"x = 5"},{"id":"b","text":"x = 7"},{"id":"c","text":"x = −7"},{"id":"d","text":"x = 1"}]'::jsonb, 'b', 'ننشر الطرف الأيسر: 3x − 6 = 2x + 1. ننقل: 3x − 2x = 1 + 6، أي x = 7. التحقّق: 3(7 − 2) = 15 و2(7) + 1 = 15 ✓.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b849ffc-3cac-5d7c-8784-162dc3b498e6', '524341c8-b06e-56ea-8f79-09a4cf281ab8', 'مثلّث قائم في B، ضلعاه القائمان AB = 6 cm وBC = 8 cm. ما طول الوتر AC؟', '[{"id":"a","text":"10 cm"},{"id":"b","text":"14 cm"},{"id":"c","text":"√28 cm"},{"id":"d","text":"48 cm"}]'::jsonb, 'a', 'بنظرية فيثاغورس: AC² = AB² + BC² = 6² + 8² = 36 + 64 = 100. إذن AC = √100 = 10 cm. الخطأ الشائع (b): جمع الضلعين مباشرةً 6 + 8.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72e21fb5-04f1-5caa-94a2-af01cf9b94ea', '524341c8-b06e-56ea-8f79-09a4cf281ab8', 'لتكن الدالّة التآلفية f(x) = 3x − 2. ما صورة العدد 4 بهذه الدالّة، أي f(4)؟', '[{"id":"a","text":"10"},{"id":"b","text":"12"},{"id":"c","text":"5"},{"id":"d","text":"14"}]'::jsonb, 'a', 'نعوّض x بـ 4: f(4) = 3 × 4 − 2 = 12 − 2 = 10. الخطأ الشائع (b): نسيان طرح 2.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db3b30fd-ee59-5c74-8500-eab1faf97ee4', '524341c8-b06e-56ea-8f79-09a4cf281ab8', 'انشر وبسّط العبارة (2x − 3)².', '[{"id":"a","text":"4x² − 9"},{"id":"b","text":"4x² + 9"},{"id":"c","text":"4x² − 12x + 9"},{"id":"d","text":"2x² − 12x + 9"}]'::jsonb, 'c', 'متطابقة شهيرة: (a − b)² = a² − 2ab + b² مع a = 2x وb = 3. إذن (2x)² − 2(2x)(3) + 3² = 4x² − 12x + 9. الخطأ الشائع (a): نسيان الحدّ الأوسط −12x.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ff263b7-981a-5cfa-9768-a8a23b0804cd', '524341c8-b06e-56ea-8f79-09a4cf281ab8', 'في مثلّث ABC، M على [AB] وN على [AC] مع (MN) ∥ (BC). إذا كان AM = 4 cm، AB = 10 cm، BC = 15 cm، فما طول MN؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"9 cm"},{"id":"c","text":"5 cm"},{"id":"d","text":"7,5 cm"}]'::jsonb, 'a', 'بنظرية طاليس: MN/BC = AM/AB = 4/10 = 2/5. إذن MN = 15 × 2/5 = 6 cm. الخطأ الشائع (b): استعمال MB = AB − AM = 6 بدل AM وحساب 15 × 6/10 = 9.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d813920b-13bd-5a85-a676-7afb99359221', '524341c8-b06e-56ea-8f79-09a4cf281ab8', 'حصل تلميذ على الأعداد التالية في خمسة فروض: 4، 6، 8، 10، 12. ما المعدّل الحسابي لهذه الأعداد؟', '[{"id":"a","text":"8"},{"id":"b","text":"10"},{"id":"c","text":"40"},{"id":"d","text":"7"}]'::jsonb, 'a', 'المعدّل = مجموع القيم ÷ عددها. المجموع = 4 + 6 + 8 + 10 + 12 = 40، والعدد 5. إذن المعدّل = 40 ÷ 5 = 8. الخطأ الشائع (c): إعطاء المجموع دون القسمة على العدد.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d5c17bc9-c4cb-5704-993c-7d599dc2a1ec', '524341c8-b06e-56ea-8f79-09a4cf281ab8', 'مثلّث قائم في B، الزاوية في A قياسها x. الضلع المجاور لـ x هو AB = 5 cm والوتر AC = 10 cm. ما قياس الزاوية x؟', '[{"id":"a","text":"30°"},{"id":"b","text":"45°"},{"id":"c","text":"60°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'نستعمل جيب التمام (المجاور على الوتر): cos x = AB/AC = 5/10 = 1/2. ومن القيم المشهورة cos 60° = 1/2، إذن x = 60°. الخطأ الشائع (a): استعمال cos 30° = √3/2.', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('192ab383-a349-5ce8-bef9-fc37ad988a0d', '0d636faa-337f-57db-a256-88d4ec85ca49', 'math', '⭐⭐ 📝 سبر تطبيقي: مسألة هندسية ومسألة واقعية', 2, 75, 15, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd0ba843-88b7-5cc8-addd-5100a5eaa060', '192ab383-a349-5ce8-bef9-fc37ad988a0d', 'المسألة الأولى (هندسة): ABC مثلّث قائم في A حيث AB = 8 cm والوتر BC = 10 cm.

السؤال (1): احسب طول الضلع AC.', '[{"id":"a","text":"2 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"√164 cm"},{"id":"d","text":"18 cm"}]'::jsonb, 'b', 'بنظرية فيثاغورس في المثلّث القائم في A: BC² = AB² + AC². نعزل الضلع المجهول: AC² = BC² − AB² = 100 − 64 = 36، إذن AC = √36 = 6 cm. الخطأ الشائع: جمع المربّعين √(100 + 64) = √164 مع أنّ BC وتر، أو طرح الطولين مباشرةً 10 − 8 = 2.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6a171843-375c-54bc-adea-4a43f742dd8f', '192ab383-a349-5ce8-bef9-fc37ad988a0d', 'المسألة الثانية (وضعية واقعية): اشترى تلميذ 3 كرّاسات وقلمَين بـ 13 دينارًا، واشترى زميله كرّاستَين وقلمَين بـ 10 دنانير. لِيكن x ثمن الكرّاسة وy ثمن القلم.

السؤال (1): ما الجملة التي تترجم الوضعية؟', '[{"id":"a","text":"المعادلتان: 3x + 2y = 13 و 2x + 2y = 10"},{"id":"b","text":"المعادلتان: 3x + 2y = 10 و 2x + 2y = 13"},{"id":"c","text":"المعادلتان: 3x + y = 13 و 2x + y = 10"},{"id":"d","text":"المعادلتان: 2x + 3y = 13 و 2x + 2y = 10"}]'::jsonb, 'a', '«3 كرّاسات وقلمَين بـ 13» تُترجَم 3x + 2y = 13، و«كرّاستَين وقلمَين بـ 10» تُترجَم 2x + 2y = 10. ننتبه لربط كلّ ثمن بالكمّيّة الصحيحة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bc0a3b8a-0181-52b8-b02b-c8cc4ddf2178', '192ab383-a349-5ce8-bef9-fc37ad988a0d', 'تابع المسألة الأولى (بما أنّ BC = 10 cm وAB = 8 cm): M نقطة من [AB] وN نقطة من [AC] بحيث (MN) ∥ (BC) وAM = 4 cm.

السؤال (2): احسب طول MN.', '[{"id":"a","text":"2,5 cm"},{"id":"b","text":"4 cm"},{"id":"c","text":"5 cm"},{"id":"d","text":"6 cm"}]'::jsonb, 'c', 'بما أنّ (MN) ∥ (BC) نطبّق نظرية طاليس: MN/BC = AM/AB = 4/8 = 1/2. إذن MN = BC × 1/2 = 10 × 1/2 = 5 cm. الخطأ الشائع: الإجابة بـ 6 cm وهو طول AC وليس MN.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95ac532b-ec09-5fc4-bbe7-c011f4cbc90e', '192ab383-a349-5ce8-bef9-fc37ad988a0d', 'تابع المسألة الأولى (بما أنّ BC = 10 cm وAB = 8 cm): D نقطة من [AB] وE نقطة من [AC] بحيث (DE) ∥ (BC) وDE = 7,5 cm.

السؤال (3): احسب طول AD.', '[{"id":"a","text":"4,5 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"7,5 cm"},{"id":"d","text":"10,7 cm"}]'::jsonb, 'b', 'بطاليس: AD/AB = DE/BC = 7,5/10 = 3/4. هذه المرّة المجهول على الضلع [AB]: AD = AB × 3/4 = 8 × 3/4 = 6 cm. الخطأ الشائع: استعمال AC بدل AB فيُحصل على AE = 6 × 3/4 = 4,5 cm، أو قلب النسبة 8 × 10/7,5 ≈ 10,7 cm.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d9aa8d24-ae11-549c-a3d3-9ec44d001f8b', '192ab383-a349-5ce8-bef9-fc37ad988a0d', 'تابع المسألة الثانية: المعادلتان: 3x + 2y = 13 و 2x + 2y = 10.

السؤال (2): ما ثمن الكرّاسة الواحدة x؟', '[{"id":"a","text":"2 دينار"},{"id":"b","text":"3 دنانير"},{"id":"c","text":"4 دنانير"},{"id":"d","text":"5 دنانير"}]'::jsonb, 'b', 'نطرح المعادلة الثانية من الأولى: (3x + 2y) − (2x + 2y) = 13 − 10، إذن x = 3. ثمن الكرّاسة 3 دنانير. التحقّق يأتي في السؤال التالي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('623424cd-8728-5bc3-a117-2876959bfe29', '192ab383-a349-5ce8-bef9-fc37ad988a0d', 'تابع المسألة الثانية (وجدنا x = 3).

السؤال (3): ما ثمن القلم الواحد y؟ (وتحقّق من النتيجتَين)', '[{"id":"a","text":"1 دينار"},{"id":"b","text":"2 دينار"},{"id":"c","text":"3 دنانير"},{"id":"d","text":"4 دنانير"}]'::jsonb, 'b', 'نعوّض x = 3 في 2x + 2y = 10: 6 + 2y = 10، إذن 2y = 4 وy = 2 دينار. التحقّق في المعادلة الأولى: 3(3) + 2(2) = 9 + 4 = 13 ✓. إذن الكرّاسة بـ 3 دنانير والقلم بدينارَين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('29558798-6563-5fdb-9042-5374b54145be', '0d636faa-337f-57db-a256-88d4ec85ca49', 'math', '⚔️ زعيم السبر ⭐⭐⭐: مسألة هندسية مركّبة ومسألة جملة', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8138d5ed-04dd-53a0-9ed2-d74e856bec4c', '29558798-6563-5fdb-9042-5374b54145be', 'المسألة الأولى (هندسة مركّبة): ABC مثلّث حيث AB = 9 cm وBC = 12 cm وAC = 15 cm.

السؤال (1): بيّن أنّ المثلّث ABC قائم. ما الاستنتاج الصحيح بتعليله؟', '[{"id":"a","text":"قائم في B لأنّ AC² = AB² + BC² (أي 225 = 81 + 144)"},{"id":"b","text":"قائم في C لأنّ AC هو أطول الأضلاع"},{"id":"c","text":"قائم في A لأنّ BC² = AB² + AC²"},{"id":"d","text":"ليس قائمًا لأنّ AB + BC ≠ AC"}]'::jsonb, 'a', 'نطبّق النظرية العكسية لفيثاغورس على أطول ضلع AC: AC² = 15² = 225 وAB² + BC² = 81 + 144 = 225. التساوي محقّق، إذن المثلّث قائم، والزاوية القائمة في الرأس B المقابل للوتر AC. الخطأ الشائع: وضع الزاوية القائمة عند أحد طرفَي الوتر (b)، أو مقارنة الأطوال بالجمع بدل المربّعات (d).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b45cbd0-daf0-5a83-8c40-d1acd2064bd0', '29558798-6563-5fdb-9042-5374b54145be', 'تابع المسألة الأولى: M نقطة من [BA] حيث BM = 3 cm وN نقطة من [BC] حيث BN = 5 cm.

السؤال (2): هل (MN) ∥ (AC)؟ اختر الاستنتاج الصحيح بتعليله.', '[{"id":"a","text":"نعم، لأنّ M وN تقعان على الضلعين [BA] و[BC]"},{"id":"b","text":"لا، لأنّ BM/BA = 3/9 = 4/12 بينما BN/BC = 5/12، والنسبتان مختلفتان"},{"id":"c","text":"لا، لأنّ المثلّث ABC قائم في B"},{"id":"d","text":"نعم، لأنّ BM/BA = BN/BC = 1/3"}]'::jsonb, 'b', 'بالنظرية العكسية لطاليس نقارن النسبتين برأس B: BM/BA = 3/9 = 1/3 = 4/12، وBN/BC = 5/12. بما أنّ 4/12 ≠ 5/12 فالنسبتان غير متساويتين، إذن (MN) غير موازية لـ (AC). الخطأ الشائع (d): التسرّع في الاختصار واعتبار 5/12 = 1/3، أو الظنّ أنّ موقع النقطتين يكفي للتوازي (a).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d72cd3cc-bd7c-5d95-b6fd-d31c928a5193', '29558798-6563-5fdb-9042-5374b54145be', 'المسألة الثانية (وضعية واقعية): في حظيرة دجاجٌ وأرانب، عدد الرؤوس 35 وعدد الأرجل 94. للدجاجة رجلان وللأرنب أربع أرجل. لِيكن c عدد الدجاج وr عدد الأرانب.

السؤال (1): ما الجملة التي تترجم الوضعية؟', '[{"id":"a","text":"المعادلتان: c + r = 94 و 2c + 4r = 35"},{"id":"b","text":"المعادلتان: c + r = 35 و 4c + 2r = 94"},{"id":"c","text":"المعادلتان: 2c + 2r = 35 و 4c + 4r = 94"},{"id":"d","text":"المعادلتان: c + r = 35 و 2c + 4r = 94"}]'::jsonb, 'd', 'عدد الرؤوس = عدد الحيوانات: c + r = 35. عدد الأرجل: الدجاجة برجلين والأرنب بأربع، فـ 2c + 4r = 94. الخطأ الشائع (b): عكس عدد أرجل الدجاج والأرانب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5957aff2-a935-52ae-8898-fa1ca57ce106', '29558798-6563-5fdb-9042-5374b54145be', 'المسألة الثالثة (حساب حرفي): بسّط العبارة E = (x + 5)(x − 5) + 25.', '[{"id":"a","text":"x²"},{"id":"b","text":"x² + 50"},{"id":"c","text":"x² − 50"},{"id":"d","text":"x² + 25"}]'::jsonb, 'a', 'بالمتطابقة الشهيرة (a − b)(a + b) = a² − b² مع a = x وb = 5: (x + 5)(x − 5) = x² − 25. إذن E = x² − 25 + 25 = x². الخطأ الشائع (b): اعتبار (x + 5)(x − 5) = x² + 25 بإهمال إشارة الناقص.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c3bf5fa3-9bf5-56ad-817e-28fa667ad4aa', '29558798-6563-5fdb-9042-5374b54145be', 'تابع المسألة الأولى (المثلّث ABC قائم في B، AB = 9، BC = 12، AC = 15). نهتمّ بالزاوية A.

السؤال (3): احسب cos A.', '[{"id":"a","text":"4/3"},{"id":"b","text":"5/3"},{"id":"c","text":"3/5"},{"id":"d","text":"4/5"}]'::jsonb, 'c', 'بالنسبة للزاوية A: الضلع المجاور هو AB والوتر هو AC. إذن cos A = AB/AC = 9/15 = 3/5 (المجاور على الوتر). الخطأ الشائع (d): استعمال الضلع المقابل BC = 12 بدل المجاور، وهذا يعطي sin A = 12/15 = 4/5.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dee23524-04be-574e-91db-9cea702744cd', '29558798-6563-5fdb-9042-5374b54145be', 'تابع المسألة الثانية: المعادلتان: c + r = 35 و 2c + 4r = 94.

السؤال (2): كم عدد الأرانب r؟ (مع التحقّق)', '[{"id":"a","text":"10 أرانب"},{"id":"b","text":"12 أرنبًا"},{"id":"c","text":"15 أرنبًا"},{"id":"d","text":"23 أرنبًا"}]'::jsonb, 'b', 'من المعادلة الأولى c = 35 − r. نعوّض في الثانية: 2(35 − r) + 4r = 94، أي 70 − 2r + 4r = 94، فـ 2r = 24 ومنه r = 12 أرنبًا (وعدد الدجاج c = 35 − 12 = 23). التحقّق بالأرجل: 2(23) + 4(12) = 46 + 48 = 94 ✓.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('377d74ea-0e11-5a70-9f62-2b390afb7c31', '0d636faa-337f-57db-a256-88d4ec85ca49', 'math', '👑 تحدّي النخبة ⭐⭐⭐⭐: سبر شامل بمستوى الامتياز', 4, 300, 60, 'challenge', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('646a87b5-809b-5756-84bc-739528107bb8', '377d74ea-0e11-5a70-9f62-2b390afb7c31', 'المسألة الأولى (هندسة نخبويّة): ABC مثلّث قائم في A حيث AB = 6 cm وAC = 6√3 cm.

السؤال (1): احسب طول الوتر BC.', '[{"id":"a","text":"12 cm"},{"id":"b","text":"6√2 cm"},{"id":"c","text":"12√3 cm"},{"id":"d","text":"18 cm"}]'::jsonb, 'a', 'بنظرية فيثاغورس: BC² = AB² + AC² = 6² + (6√3)² = 36 + 36 × 3 = 36 + 108 = 144. إذن BC = √144 = 12 cm. الانتباه: (6√3)² = 36 × 3 = 108 وليس 108√3.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('29c1af86-32e0-5a01-ac46-29295c0b7232', '377d74ea-0e11-5a70-9f62-2b390afb7c31', 'المسألة الثانية (وضعية واقعية): عمر الأب اليوم يساوي ثلاثة أمثال عمر ابنه. بعد 10 سنوات سيصبح عمر الأب ضعفَ عمر ابنه. لِيكن f عمر الأب وs عمر الابن اليوم.

السؤال (1): ما الجملة التي تترجم الوضعية؟', '[{"id":"a","text":"المعادلتان: f = 3s و f + 10 = 2(s + 10)"},{"id":"b","text":"المعادلتان: f = 3s و f + 10 = 2s + 10"},{"id":"c","text":"المعادلتان: s = 3f و s + 10 = 2(f + 10)"},{"id":"d","text":"المعادلتان: f = 3s و 2f + 10 = s + 10"}]'::jsonb, 'a', '«عمر الأب ثلاثة أمثال عمر الابن» ← f = 3s. «بعد 10 سنوات»: عمر الأب f + 10 وعمر الابن s + 10، و«الأب ضعف الابن» ← f + 10 = 2(s + 10). الخطأ الشائع (b): نسيان توزيع 2 على (s + 10).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44bd5381-d4a8-5be1-b2a6-ff072c863d6a', '377d74ea-0e11-5a70-9f62-2b390afb7c31', 'تابع المسألة الأولى (AB = 6 ; AC = 6√3 ; BC = 12). نهتمّ بالزاوية B.

السؤال (2): استنتج قياس الزاوية B.', '[{"id":"a","text":"30°"},{"id":"b","text":"45°"},{"id":"c","text":"60°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'بالنسبة للزاوية B: المقابل هو AC والمجاور هو AB. إذن tan B = AC/AB = 6√3/6 = √3 (المقابل على المجاور). ومن القيم المشهورة tan 60° = √3، إذن B = 60°. (يمكن أيضًا: cos B = AB/BC = 6/12 = 1/2 ⇒ B = 60°.)', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ccc803c5-cc4f-5ac1-9595-d8898996194b', '377d74ea-0e11-5a70-9f62-2b390afb7c31', 'تابع المسألة الأولى: M نقطة من [AB] حيث AM = 2 cm، وN نقطة من [AC] حيث AN = 2√3 cm.

السؤال (3): هل (MN) ∥ (BC)؟ اختر الاستنتاج الصحيح بتعليله.', '[{"id":"a","text":"لا، لأنّ AM ≠ AN"},{"id":"b","text":"نعم، لأنّ المثلّث قائم في A"},{"id":"c","text":"لا، لأنّ AM/AB ≠ AN/AC"},{"id":"d","text":"نعم، لأنّ AM/AB = AN/AC = 1/3"}]'::jsonb, 'd', 'نحسب النسبتَين: AM/AB = 2/6 = 1/3، وAN/AC = 2√3/(6√3) = 2/6 = 1/3 (نختصر √3). النسبتان متساويتان وM وN في نفس الجانب من A، إذن بالنظرية العكسية لطاليس (MN) ∥ (BC). الخطأ الشائع (a): مقارنة الطولين بدل النسبتَين، و(b): الزاوية القائمة لا علاقة لها بالتوازي.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('921c7574-54f6-5507-94df-8842f8c3f864', '377d74ea-0e11-5a70-9f62-2b390afb7c31', 'تابع المسألة الثانية: المعادلتان: f = 3s و f + 10 = 2(s + 10).

السؤال (2): ما عمر الابن اليوم s؟ (مع التحقّق)', '[{"id":"a","text":"8 سنوات"},{"id":"b","text":"10 سنوات"},{"id":"c","text":"12 سنة"},{"id":"d","text":"15 سنة"}]'::jsonb, 'b', 'نعوّض f = 3s في المعادلة الثانية: 3s + 10 = 2(s + 10) = 2s + 20. ننقل: 3s − 2s = 20 − 10، إذن s = 10 سنوات (وعمر الأب f = 3 × 10 = 30 سنة). التحقّق: بعد 10 سنوات الأب 40 والابن 20، و40 = 2 × 20 ✓.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a997509e-0437-51bc-b63e-c9e905aef586', '377d74ea-0e11-5a70-9f62-2b390afb7c31', 'المسألة الثالثة (دالّة ومعادلة): سيّارة أجرة تأخذ 2 دينار عند الانطلاق ثمّ 0,5 دينار لكلّ كيلومتر. الثمن بالدينار حسب المسافة x بالكيلومترات هو f(x) = 0,5x + 2.

السؤال: إذا دفع راكب 16 دينارًا، فما المسافة التي قطعها؟', '[{"id":"a","text":"14 كم"},{"id":"b","text":"28 كم"},{"id":"c","text":"32 كم"},{"id":"d","text":"36 كم"}]'::jsonb, 'b', 'نحلّ المعادلة f(x) = 16، أي 0,5x + 2 = 16. ننقل: 0,5x = 14، ثمّ نقسم على 0,5 (أو نضرب في 2): x = 14 ÷ 0,5 = 28 كم. التحقّق: 0,5 × 28 + 2 = 14 + 2 = 16 ✓. الخطأ الشائع (a): نسيان القسمة على 0,5 والاكتفاء بـ x = 14.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

